var isa_ch_21_Verses = [
  {num:1,words:[["O le avega a le vao o le sami. E ui ane e pei o asiosio i le itu i toga,", "The burden of the desert of the sea. As whirlwinds in the south pass through;"], ["e sau lava mai le vao,", "so it cometh from the desert,"], ["mai le nuu matautia.", "from a terrible land."]]},
  {num:2,words:[["O le faaaliga faigata ua faaalia mai ia te au,", "A grievous vision is declared unto me;"], ["o le ua saua o loo faasaua,", "the treacherous dealer dealeth treacherously,"], ["o le ua faatafuna o loo faatafuna;", "and the spoiler spoileth. Go up,"], ["Elama e, ina alu ae ia;", "O Elam:"], ["Metai e,", "besiege,"], ["ina vagaia ia le 'olo;", "O Media;"], ["ua ou faaiuina mapuitiga uma.", "all the sighing thereof have I made to cease."]]},
  {num:3,words:[["O le mea lea ua matuā tiga ai lo'u tua,", "Therefore are my loins filled with pain:"], ["ua maua a'u i le tiga e pei o le faatiga o le fafine a fanau;", "pangs have taken hold upon me,"], ["ua tigaina a'u, e le mafai ona faalogo atu;", "as the pangs of a woman that travaileth:"], ["ua ou soona atuatuvale,", "I was bowed down at the hearing of it;"], ["e le mafai ona vaai.", "I was dismayed at the seeing of it."]]},
  {num:4,words:[["Ua polepole vale lo'u loto;", "My heart panted,"], ["ua osofia a'u i le mata'u;", "fearfulness affrighted me:"], ["o le po na ou olioli ai ua faia lea e ia ma mea e matautuia ai a'u.", "the night of my pleasure hath he turned into fear unto me."]]},
  {num:5,words:[["Ua laulau atu mea i le laoai;", "Prepare the table,"], ["ua tofia le matāmoe;", "watch in the watchtower,"], ["o loo aai,", "eat,"], ["o loo inu;", "drink:"], ["alii e,", "arise,"], ["tutū ia i luga,", "ye princes,"], ["ina faauu ia le talita.", "and anoint the shield."]]},
  {num:6,words:[["Auā ua faapea ona fetalai mai o le Alii ia te au,", "For thus hath the Lord said unto me,"], ["Alu ia,", "Go,"], ["ina e tofia se tagata e vaai, o le mea na te iloa,", "set a watchman,"], ["ia te faaali ane.", "let him declare what he seeth."]]},
  {num:7,words:[["Ona iloa lea e ia o 'au e ō taitoalua,", "And he saw a chariot with a couple of horsemen,"], ["e tietie i solofanua,", "a chariot of asses,"], ["o 'au e tietie i asini, ma 'au e tietie i kamela;", "and a chariot of camels;"], ["ona matuā faalogologo ai lava lea o ia.", "and he hearkened diligently with much heed:"]]},
  {num:8,words:[["Ona alaga lea o ia e pei o le leona,", "And he cried,"], ["Le alii e,", "A lion:"], ["ou te tu a'u nei i le olo e leoleo ai e le aunoa i le ao;", "My lord, I stand continually upon the watchtower in the daytime,"], ["ou te tu foi a'u i le mea ou te matāmoe ai i po uma lava.", "and I am set in my ward whole nights:"]]},
  {num:9,words:[["Faauta foi,", "And, behold,"], ["o loo o mai 'au e ō taitoalua e tietie i solofanua.", "here cometh a chariot of men, with a couple of horsemen."], ["Ona toe fai mai ai lea o ia,", "And he answered and said,"], ["Ua paū,", "Babylon is fallen,"], ["ua paū Papelonia;", "is fallen;"], ["o tupua uma foi a ona atua ua ia tu'ipalaina i le eleele.", "and all the graven images of her gods he hath broken unto the ground."]]},
  {num:10,words:[["La'u sasaga e,", "O my threshing,"], ["ma le saito o i la'u mea e sasa ai saito;", "and the corn of my floor:"], ["o mea ua ou faalogologo ai ia Ieova o 'au o le Atua o Isaraelu,", "that which I have heard of the LORD of hosts, the God of Israel,"], ["ua ou faaali atu ai ia te outou.", "have I declared unto you."]]},
  {num:11,words:[["O le avega a Tuma. Na valaau mai le tasi ia te au mai Seira,", "The burden of Dumah. He calleth to me out of Seir,"], ["Le leoleo e,", "Watchman,"], ["po ua a ea le po? Le leoleo e,", "what of the night? Watchman,"], ["po ua a ea le po?", "what of the night?"]]},
  {num:12,words:[["Ua fai atu le leoleo,", "The watchman said,"], ["O loo sau le taeao,", "The morning cometh,"], ["atoa foi ma le po;", "and also the night:"], ["afai tou te fesili,", "if ye will enquire,"], ["ina fesili ia;", "enquire ye:"], ["ia outou liliu ia,", "return,"], ["ina o mai ia.", "come."]]},
  {num:13,words:[["O le avega a Arapi.", "The burden upon Arabia."], ["O le vao o Arapi tou te momoe ai outou malaga a Titana.", "In the forest in Arabia shall ye lodge, O ye travelling companies of Dedanim."]]},
  {num:14,words:[["O e nonofo i le nuu o Tema ua latou avatu le vai e faafetaiai i e ua fia inu,", "The inhabitants of the land of Tema brought water to him that was thirsty,"], ["ua latou fonofono ma mea e 'ai i e ua sosola mai.", "they prevented with their bread him that fled."]]},
  {num:15,words:[["Auā ua latou sosola ese i pelu,", "For they fled from the swords,"], ["o le pelu foi ua toina,", "from the drawn sword,"], ["ma le aufana ua lolou,", "and from the bent bow,"], ["atoa ma le taua ua faigata.", "and from the grievousness of war."]]},
  {num:16,words:[["Auā o loo faapea ona fetalai mai o le Alii ia te au,", "For thus hath the Lord said unto me,"], ["Toe tasi le tausaga,", "Within a year,"], ["e tusa ma tausaga o le ua galue i le totogi,", "according to the years of an hireling,"], ["ona faaumatia ai lea o le mamalu uma o Kitara.", "and all the glory of Kedar shall fail:"]]},
  {num:17,words:[["O e ua totoe o e fai aufana,", "And the residue of the number of archers,"], ["o tagata totoa o Kitara e faatoaitiitia i latou;", "the mighty men of the children of Kedar, shall be diminished:"], ["auā ua fetalai mai ai Ieova le Atua o Isaraelu.", "for the LORD God of Israel hath spoken it."]]},
];
renderVerseSet(isa_ch_21_Verses, 'isa-ch21-verses');

var isa_ch_22_Verses = [
  {num:1,words:[["O le avega a le vanu o le faaaliga.", "The burden of the valley of vision."], ["Pe faapefea lava oe ina ua o ae ou tagata uma i luga o fale?", "What aileth thee now, that thou art wholly gone up to the housetops?"]]},
  {num:2,words:[["Sa tumu oe i vāvāō,", "Thou that art full of stirs,"], ["o le aai e pisapisao,", "a tumultuous city,"], ["o le aai e olioli lava;", "a joyous city:"], ["o ou tagata fasia e lei fasia i latou i le pelu,", "thy slain men are not slain with the sword,"], ["e lei oti foi i le taua.", "nor dead in battle."]]},
  {num:3,words:[["Ua sosola faatasi ou alii uma,", "All thy rulers are fled together,"], ["ona o aufana ua fusifusia lava i latou;", "they are bound by the archers:"], ["ua fusifusia faatasi i latou uma o e na maua ua ia te oe,", "all that are found in thee are bound together,"], ["o e na sosola mai i le mea mamao.", "which have fled from far."]]},
  {num:4,words:[["O le mea lea na ou fai atu ai,", "Therefore said I,"], ["Ia outou liliu ese ia te au;", "Look away from me;"], ["ou te tagi lotulotu lava,", "I will weep bitterly,"], ["aua tou te finau e faamafanafana mai ia te au,", "labour not to comfort me,"], ["ona o le faatafunaina o le tama fafine a lo'u nuu.", "because of the spoiling of the daughter of my people."]]},
  {num:5,words:[["Auā o le aso o le pisapisao,", "For it is a day of trouble,"], ["ma le soliga,", "and of treading down,"], ["ma le fememeai mai le Alii o Ieova o 'au i le vanu o le faaaliga,", "and of perplexity by the Lord GOD of hosts in the valley of vision,"], ["o le aso e lepetia ai pa,", "breaking down the walls,"], ["ma alalaga atu ai i mauga.", "and of crying to the mountains."]]},
  {num:6,words:[["Ua tauave e Elama le utu, faatasi ma kariota ua i ai tagata ma e tietie i solofanua;", "And Elam bare the quiver with chariots of men and horsemen,"], ["ua to ese foi e Kira le ufiufi o le talita.", "and Kir uncovered the shield."]]},
  {num:7,words:[["Ua tutumu ou vanu e sili ona lelei i kariota,", "And it shall come to pass, that thy choicest valleys shall be full of chariots,"], ["ua pae tau mai foi 'au e tietie i solofanua i le faitotoa.", "and the horsemen shall set themselves in array at the gate."]]},
  {num:8,words:[["Ua to ese le ufiufi o Iuta,", "And he discovered the covering of Judah,"], ["o lea aso foi e te faasaga ai i auupega o i le fale i le vao.", "and thou didst look in that day to the armour of the house of the forest."]]},
  {num:9,words:[["Ua outou vaavaai i mea ua lepetia i le aai o Tavita ina ua tele,", "Ye have seen also the breaches of the city of David, that they are many:"], ["ma outou faapotopotoina le vai o le lepa aupito i lalo.", "and ye gathered together the waters of the lower pool."]]},
  {num:10,words:[["Ua outou faitauina foi fale o Ierusalema,", "And ye have numbered the houses of Jerusalem,"], ["ma outou lepetia fale e teu a'i le 'olo.", "and the houses have ye broken down to fortify the wall."]]},
  {num:11,words:[["Ua outou elia se mea i le va o pa e lua e tali ai le vai o le lepa tuai;", "Ye made also a ditch between the two walls for the water of the old pool:"], ["a ua outou le faasaga atu i le ua tupu ai ia mea,", "but ye have not looked unto the maker thereof,"], ["ua outou le vaai atu foi i le na saunia ai anamua.", "neither had respect unto him that fashioned it long ago."]]},
  {num:12,words:[["O lea aso foi ua valaau mai ai le Alii o Ieova o 'au ia fetagisi,", "And in that day did the Lord GOD of hosts call to weeping,"], ["ma ia taufaitagitu'i,", "and to mourning,"], ["ma ia sele mamā lauulu,", "and to baldness,"], ["ma ia lavalava i ie talatala.", "and to girding with sackcloth:"]]},
  {num:13,words:[["Faauta foi,", "And behold joy and gladness,"], ["o le fiafia ma le olioli,", "slaying oxen,"], ["o le fasiga o povi ma le fasiga o mamoe,", "and killing sheep,"], ["o loo aai tufaaga ma inu uaina,", "eating flesh,"], ["Ina tatou aai ia,", "and drinking wine:"], ["ma inu;", "let us eat and drink;"], ["auā a taeao tatou te oti ai.", "for to morrow we shall die."]]},
  {num:14,words:[["A ua faaalia mai i o'u taliga e Ieova o 'au e matuā le faamagaloina lena agasala ia te outou e oo i lo outou oti,", "And it was revealed in mine ears by the LORD of hosts, Surely this iniquity shall not be purged from you till ye die,"], ["o loo faapea mai ai le Alii o Ieova o 'au.", "saith the Lord GOD of hosts."]]},
  {num:15,words:[["Ua faapea ona fetalai mai o le Alii o Ieova o 'au,", "Thus saith the Lord GOD of hosts,"], ["Sau ia,", "Go,"], ["ina alu i lena auauna ua pule,", "get thee unto this treasurer,"], ["o Sevena foi,", "even unto Shebna,"], ["o le ua pule i le aiga,", "which is over the house,"], ["ia faapea atu i ai ,", "and say,"]]},
  {num:16,words:[["Se a ea se mea ua ia te oe iina? o ai ea foi o ia te oe i le mea nei? ina ua e elia mo oe se tuugamau i le mea nei,", "What hast thou here? and whom hast thou here,"], ["ua eli e ia lona tuugamau i le mea maualuga,", "that thou hast hewed thee out a sepulchre here, as he that heweth him out a sepulchre on high,"], ["ua foa i le papa se fale mo ia.", "and that graveth an habitation for himself in a rock?"]]},
  {num:17,words:[["Faauta,", "Behold,"], ["o Ieova na te matuā lafotuina oe ma le malosi tele,", "the LORD will carry thee away with a mighty captivity,"], ["na te ufitia lava oe.", "and will surely cover thee."]]},
  {num:18,words:[["Na te matuā lialiai oe, e lialiai e pei o se mea lapotopoto e sasau atu i le nuu lautele;", "He will surely violently turn and toss thee like a ball into a large country:"], ["e te oti ai,", "there shalt thou die,"], ["e i ai foi ou nofoa faataavalevale matagofie, o le gao o le aiga o lou alii.", "and there the chariots of thy glory shall be the shame of thy lord's house."]]},
  {num:19,words:[["Ou te tulia oe i lou tofi,", "And I will drive thee from thy station,"], ["ou te lafotuina foi oe i le mea ua ē tu ai.", "and from thy state shall he pull thee down."]]},
  {num:20,words:[["O lea aso foi ou te valaauina ai la'u auauna o Eliakimo le atalii o Hilikia;", "And it shall come to pass in that day, that I will call my servant Eliakim the son of Hilkiah:"]]},
  {num:21,words:[["ou te faaofuina foi o ia i lou ofu;", "And I will clothe him with thy robe,"], ["ma ou faamalosi ia te ia i lou fusi;", "and strengthen him with thy girdle,"], ["ou te tuuina atu ia te ia lau pule,", "and I will commit thy government into his hand: and he shall be a father to the inhabitants of Jerusalem,"], ["e avea foi o ia ma tamā o e nonofo i Ierusalema atoa ma le aiga o Iuta.", "and to the house of Judah."]]},
  {num:22,words:[["Ou te faaee foi le ki a le aiga o Tavita i lona ua;", "And the key of the house of David will I lay upon his shoulder;"], ["na te tatalaina,", "so he shall open,"], ["a e leai se na te puipuia;", "and none shall shut;"], ["na te puipuia foi,", "and he shall shut,"], ["a e leai se na te tatalaina.", "and none shall open."]]},
  {num:23,words:[["Ou te faamauina o ia e pei o le fao i le mea e mausali ai,", "And I will fasten him as a nail in a sure place;"], ["e fai foi o ia ma nofoālii mamalu i le fale o lona tamā;", "and he shall be for a glorious throne to his father's house."]]},
  {num:24,words:[["latou te tāutau ia te ia o le tele o mea uma o i le fale o lona tamā;", "And they shall hang upon him all the glory of his father's house,"], ["o e tutupu ai,", "the offspring and the issue,"], ["ma e ua fanau mai ai, o ipu iti uma lava,", "all vessels of small quantity,"], ["o ipu faaofuofu,", "from the vessels of cups,"], ["atoa ma fagu uma.", "even to all the vessels of flagons."]]},
  {num:25,words:[["O loo fetalai mai Ieova o 'au,", "In that day,"], ["O lea aso e aveeseina ai le fao sa faamauina i le mea sa mausali ai,", "saith the LORD of hosts,"], ["e vaevaea foi,", "shall the nail that is fastened in the sure place be removed, and be cut down,"], ["ma paū;", "and fall;"], ["e salaeseina foi le mea o tautau ai;", "and the burden that was upon it shall be cut off:"], ["auā ua fetalai mai ai Ieova.", "for the LORD hath spoken it."]]},
];
renderVerseSet(isa_ch_22_Verses, 'isa-ch22-verses');

var isa_ch_23_Verses = [
  {num:1,words:[["O le avega a Turo.", "The burden of Tyre."], ["Ina uio ia outou vaa o Tasesa,", "Howl,"], ["auā ua faatafunaina o ia;", "ye ships of Tarshish;"], ["e leai se fale,", "for it is laid waste, so that there is no house,"], ["e leai foi se mea e ui atu ai;", "no entering in:"], ["ua faaali atu ai ia te i latou ai le nuu o Kitimo.", "from the land of Chittim it is revealed to them."]]},
  {num:2,words:[["Ina faalologo ia outou o e nonofo i le nuu tuloto,", "Be still,"], ["o tagata faatauoa o Saitonu,", "ye inhabitants of the isle;"], ["e ua ui atu i le sami,", "thou whom the merchants of Zidon, that pass over the sea,"], ["na latou faatumuina oe.", "have replenished."]]},
  {num:3,words:[["Sa i ai saito o Seora i vai tetele,", "And by great waters the seed of Sihor,"], ["o le seleselegāsaito mai le vaitafe na mau oloa ai o ia;", "the harvest of the river, is her revenue;"], ["na fai o ia ma mea e faatau ai oa i nuu ese.", "and she is a mart of nations."]]},
  {num:4,words:[["Saitonu e,", "Be thou ashamed,"], ["ia masiasi oe,", "O Zidon:"], ["auā ua tautala mai le sami,", "for the sea hath spoken,"], ["o le 'olo lava o le sami,", "even the strength of the sea,"], ["o loo faapea mai,", "saying,"], ["Ua le faatiga a'u,", "I travail not,"], ["ua ou le fanau mai,", "nor bring forth children,"], ["ua ou le tausia ni taulelea,", "neither do I nourish up young men,"], ["ua ou le tausia foi ni taupou.", "nor bring up virgins."]]},
  {num:5,words:[["E pei ona tiga o i latou i le tala ia Aikupito,", "As at the report concerning Egypt,"], ["e faapea ona tiga tele o i latou i le tala ia Turo.", "so shall they be sorely pained at the report of Tyre."]]},
  {num:6,words:[["Ina o atu ia i Tasesa,", "Pass ye over to Tarshish; howl,"], ["ina uio ia outou o e nonofo i le nuu tuloto.", "ye inhabitants of the isle."]]},
  {num:7,words:[["O la outou aai olioli ea lenei,", "Is this your joyous city,"], ["o lona amataga mai ona po anamua lava ia? O ona lava vae e avea mamao ai o ia ina ia aunuua ai.", "whose antiquity is of ancient days? her own feet shall carry her afar off to sojourn."]]},
  {num:8,words:[["O ai ea ua na pule lenei mea ia Turo le ua tufatufa palealii? o ona tagata faatauoa o alii sili i latou,", "Who hath taken this counsel against Tyre, the crowning city,"], ["o ona tagata faatau o alii mamalu o le lalolagi i latou.", "whose merchants are princes, whose traffickers are the honourable of the earth?"]]},
  {num:9,words:[["O Ieova o 'au ua ia pule ai,", "The LORD of hosts hath purposed it,"], ["ina ia faaiu vale le faalialia o mea matagofie uma,", "to stain the pride of all glory,"], ["ma ia faaleaogaina alii mamalu uma o le lalolagi.", "and to bring into contempt all the honourable of the earth."]]},
  {num:10,words:[["Ia e ui atu i lou nuu e pei o le vaitafe,", "Pass through thy land as a river,"], ["le tama fafine a Tasesa e,", "O daughter of Tarshish:"], ["ua le toe ai se pupuni.", "there is no more strength."]]},
  {num:11,words:[["Ua faaloaloa lona aao i luga o le sami,", "He stretched out his hand over the sea,"], ["ua na faagateteina malo;", "he shook the kingdoms: the LORD hath given a commandment against the merchant city,"], ["ua fetalai Ieova i Kanana ia faaumatia ona 'olo.", "to destroy the strong holds thereof."]]},
  {num:12,words:[["Ua fetalai mai o ia,", "And he said,"], ["E te le toe mitamita oe le taupou,", "Thou shalt no more rejoice,"], ["le tama fafine a Saitonu le ua faaleagaina;", "O thou oppressed virgin, daughter of Zidon:"], ["ina tu ia i luga,", "arise,"], ["ina o atu ia i Kitimo;", "pass over to Chittim;"], ["a e leai se filemu ia te oe i lea mea.", "there also shalt thou have no rest."]]},
  {num:13,words:[["Faauta i le nuu o Kaletaia,", "Behold the land of the Chaldeans;"], ["o le nuu lea sa leai,", "this people was not,"], ["na faatuina e Asuria mo e sa nonofo i le vao;", "till the Assyrian founded it for them that dwell in the wilderness:"], ["ua latou faatuina o latou 'olo,", "they set up the towers thereof,"], ["ua latou faaumatia ona maota;", "they raised up the palaces thereof;"], ["ua latou faia o ia ma faupuegafale ua pauu.", "and he brought it to ruin."]]},
  {num:14,words:[["Ina uio ia outou vaa o Tasesa,", "Howl, ye ships of Tarshish:"], ["auā ua faatafunaina lo outou 'olo.", "for your strength is laid waste."]]},
  {num:15,words:[["O lea aso foi e galo ai Turo i tausaga e fitugafulu,", "And it shall come to pass in that day,"], ["e tusa ma aso o le tupu e tasi;", "that Tyre shall be forgotten seventy years,"], ["a mavae tausaga e fitugafulu,", "according to the days of one king:"], ["ona faia ai lea ia Turo e peiseai o le pese i le fafine talitane.", "after the end of seventy years shall Tyre sing as an harlot."]]},
  {num:16,words:[["Tago ia i le kitara,", "Take an harp,"], ["ina fealuai solo ia i le aai,", "go about the city,"], ["o oe le fafine talitane ua faagaloina;", "thou harlot that hast been forgotten;"], ["ia e ta malie;", "make sweet melody,"], ["ia tele ni pese e lagi,", "sing many songs,"], ["ina ia manatua oe.", "that thou mayest be remembered."]]},
  {num:17,words:[["A mavae foi tausaga e fitugafulu e asiasi Ieova ia Turo;", "And it shall come to pass after the end of seventy years,"], ["ona toe foi atu ai lea o ia i lona taui,", "that the LORD will visit Tyre,"], ["ona faitaaga ai lea o ia ma malo uma o le lalolagi,", "and she shall turn to her hire,"], ["o e o i le fogāeleele.", "and shall commit fornication with all the kingdoms of the world upon the face of the earth."]]},
  {num:18,words:[["A o ana mea e maua atoa ma lona taui e faasaina ia mo Ieova;", "And her merchandise and her hire shall be holiness to the LORD:"], ["e le faaputuina i mea e teu ai oloa,", "it shall not be treasured nor laid up;"], ["e le teua foi; auā o ana mea e maua e fai ia mā latou o e nonofo i luma o Ieova,", "for her merchandise shall be for them that dwell before the LORD,"], ["ina ia aai ai ia maoona,", "to eat sufficiently,"], ["ia fai ai foi ofu matagofie.", "and for durable clothing."]]},
];
renderVerseSet(isa_ch_23_Verses, 'isa-ch23-verses');

var isa_ch_24_Verses = [
  {num:1,words:[["Faauta,", "Behold,"], ["o loo sasaaina e Ieova le nuu ia uma,", "the LORD maketh the earth empty,"], ["na te faafaōina,", "and maketh it waste, and turneth it upside down,"], ["na te faataapeapeina foi e o nonofo ai.", "and scattereth abroad the inhabitants thereof."]]},
  {num:2,words:[["E iu ina tutusa o le nuu ma le ositaulaga;", "And it shall be, as with the people,"], ["e tutusa le auauna ma lona alii;", "so with the priest; as with the servant,"], ["e tutusa le auauna fafine ma lona matai fafine;", "so with his master; as with the maid,"], ["e tutusa le ua faatau atu ma le ua faatau mai;", "so with her mistress; as with the buyer, so with the seller;"], ["e tutusa le ua avatu mea ma le ua aitalafu;", "as with the lender, so with the borrower;"], ["e tutusa le ua talia le totogi faasili ma le ua avatu le totogi faasili.", "as with the taker of usury, so with the giver of usury to him."]]},
  {num:3,words:[["E matuā sasaaina le nuu,", "The land shall be utterly emptied,"], ["e matuā vetea lava;", "and utterly spoiled:"], ["auā ua fetalai mai Ieova lenei fetalaiga.", "for the LORD hath spoken this word."]]},
  {num:4,words:[["Ua faanoanoa le lalolagi, ua mamae;", "The earth mourneth and fadeth away,"], ["ua faavaivai le atu laulau,", "the world languisheth and fadeth away,"], ["ua mamae; ua faavaivai alii sili o le nuu.", "the haughty people of the earth do languish."]]},
  {num:5,words:[["Ua leaga le nuu i e o nonofo ai;", "The earth also is defiled under the inhabitants thereof;"], ["auā ua latou solia tulafono;", "because they have transgressed the laws,"], ["ua latou liliu ese le sauniga;", "changed the ordinance,"], ["ua latou solia le feagaiga e faavavau.", "broken the everlasting covenant."]]},
  {num:6,words:[["O le mea lea e faaumatia ai le nuu i le faafano,", "Therefore hath the curse devoured the earth,"], ["ua faasalaina foi e o nonofo ai;", "and they that dwell therein are desolate:"], ["o le mea lea ua susunuina ai e o nonofo i le nuu;", "therefore the inhabitants of the earth are burned,"], ["e toaitiiti foi tagata ua totoe.", "and few men left."]]},
  {num:7,words:[["Ua faanoanoa le sua vine,", "The new wine mourneth,"], ["ua faavaivai le vine;", "the vine languisheth,"], ["ua mapuitiga i latou uma e sa olioli o latou loto.", "all the merryhearted do sigh."]]},
  {num:8,words:[["Ua mavae le fiafia o topa;", "The mirth of tabrets ceaseth,"], ["ua uma le pisa o e na olioli;", "the noise of them that rejoice endeth,"], ["ua mavae le fiafia o le kitara.", "the joy of the harp ceaseth."]]},
  {num:9,words:[["Ua latou le toe inu uaina ma pepese;", "They shall not drink wine with a song;"], ["e oona le 'ava ia te i latou o e feinu ai.", "strong drink shall be bitter to them that drink it."]]},
  {num:10,words:[["Ua lepetia le aai gaogao;", "The city of confusion is broken down:"], ["ua punitia fale uma,", "every house is shut up,"], ["e le uia.", "that no man may come in."]]},
  {num:11,words:[["O i ala le alaga i le uaina;", "There is a crying for wine in the streets;"], ["ua mavae atu le olioli uma;", "all joy is darkened,"], ["ua alu ese le fiafia o le nuu.", "the mirth of the land is gone."]]},
  {num:12,words:[["Ua toe i le aai na o le faatafunaina,", "In the city is left desolation,"], ["ua tu'ipalaina le puipui.", "and the gate is smitten with destruction."]]},
  {num:13,words:[["Auā e faapea ona fai i le laueleele i totonu o le nuu,", "When thus it shall be in the midst of the land among the people,"], ["e pei ona sasaina ifo o le olive,", "there shall be as the shaking of an olive tree,"], ["e pei o nai toe fuifui vine pe a uma le tauga vine.", "and as the gleaning grapes when the vintage is done."]]},
  {num:14,words:[["Latou te leo tetele,", "They shall lift up their voice,"], ["latou te alalaga fiafia, ona o le mamalu o Ieova,", "they shall sing for the majesty of the LORD,"], ["latou te alalaga mai le sami.", "they shall cry aloud from the sea."]]},
  {num:15,words:[["O le mea lea ia outou vivii atu ai ia Ieova i le afi, i nuu tuloto i le sami,", "Wherefore glorify ye the LORD in the fires,"], ["o le suafa lava o Ieova o le Atua o Isaraelu.", "even the name of the LORD God of Israel in the isles of the sea."]]},
  {num:16,words:[["Ua tatou faalogo i pese mai le tuluiga o le lalolagi;", "From the uttermost part of the earth have we heard songs,"], ["o le viiga i le ua amiotonu;", "even glory to the righteous. But I said, My leanness,"], ["a ua ou fai atu,", "my leanness,"], ["Ua malaia a'u nei! ua malaia a'u nei! Aue a'u nei! O e faasaua ua latou faasaua,", "woe unto me! the treacherous dealers have dealt treacherously; yea,"], ["o le saua lava ua faasaua mai ai e ua faasaua.", "the treacherous dealers have dealt very treacherously."]]},
  {num:17,words:[["Ua ia te oe le nofo i le nuu le mata'u,", "Fear, and the pit,"], ["ma le lua,", "and the snare,"], ["ma le mailei faasaua.", "are upon thee, O inhabitant of the earth."]]},
  {num:18,words:[["O le ua sola i le leo o le mea e faamata'u a'i,", "And it shall come to pass,"], ["e paū o ia i le lua;", "that he who fleeth from the noise of the fear shall fall into the pit;"], ["o le ua alu ae foi i le lua e lavea o ia i le mailei;", "and he that cometh up out of the midst of the pit shall be taken in the snare:"], ["auā ua faaavanoa pupuni i lugā,", "for the windows from on high are open,"], ["e luluina foi faavae o le lalolagi.", "and the foundations of the earth do shake."]]},
  {num:19,words:[["Ua matuā gaugauina le nuu,", "The earth is utterly broken down,"], ["ua matuā nutililii le nuu,", "the earth is clean dissolved,"], ["ua matuā luluina le nuu.", "the earth is moved exceedingly."]]},
  {num:20,words:[["Ua tautevateva le nuu e pei o le tagata onā,", "The earth shall reel to and fro like a drunkard,"], ["ua feluea'iina e pei o le moega tautau;", "and shall be removed like a cottage;"], ["ua mamafa lona fouvale i luga ia te ia;", "and the transgression thereof shall be heavy upon it;"], ["e paū ai o ia,", "and it shall fall,"], ["e le toe tu lava.", "and not rise again."]]},
  {num:21,words:[["O lea aso foi e faasala ai Ieova i 'au i lugā i le mea maualuga,", "And it shall come to pass in that day, that the LORD shall punish the host of the high ones that are on high,"], ["atoa ma tupu o le lalolagi i le lalolagi.", "and the kings of the earth upon the earth."]]},
  {num:22,words:[["E faapotopotoina i latou pei ona faapotopotoina e ua fusifusia i le lua;", "And they shall be gathered together,"], ["e puipuia foi i latou i le fale puipui;", "as prisoners are gathered in the pit,"], ["a mavae foi aso e tele,", "and shall be shut up in the prison,"], ["ona asiasia ai lea o i latou.", "and after many days shall they be visited."]]},
  {num:23,words:[["E faamaina le masina,", "Then the moon shall be confounded,"], ["e masiasi foi le la,", "and the sun ashamed,"], ["auā e fai ma tupu Ieova o 'au i le mauga o Siona ma Ierusalema,", "when the LORD of hosts shall reign in mount Zion, and in Jerusalem,"], ["i luma foi o ona toeaina ma le mamalu.", "and before his ancients gloriously."]]},
];
renderVerseSet(isa_ch_24_Verses, 'isa-ch24-verses');

var isa_ch_25_Verses = [
  {num:1,words:[["Ieova e,", "O LORD,"], ["o lo'u Atua lava oe;", "thou art my God;"], ["ou te faaneenee ia te oe; ou te vivii atu i lou suafa;", "I will exalt thee,"], ["auā ua e faia mea e ofo ai;", "I will praise thy name;"], ["o mea na e pule ai talu anamua e faamaoni ia,", "for thou hast done wonderful things;"], ["e moni lava;", "thy counsels of old are faithfulness and truth."]]},
  {num:2,words:[["auā ua e faia le aai ma faupuega maa;", "For thou hast made of a city an heap;"], ["o le aai nofo 'olo ua e lepetia;", "of a defenced city a ruin:"], ["ua e faia le maota o tagata ese ia leai se aai;", "a palace of strangers to be no city;"], ["e le toe faia lava e faavavau;", "it shall never be built."]]},
  {num:3,words:[["o le mea lea e vivii atu ai ia te oe le nuu malosi;", "Therefore shall the strong people glorify thee,"], ["e matatau ia te oe le aai o nuu ese e matautia;", "the city of the terrible nations shall fear thee."]]},
  {num:4,words:[["auā o oe e malosi ai le ua vaivai,", "For thou hast been a strength to the poor,"], ["e malosi ai le ua mativa i lona puapuaga,", "a strength to the needy in his distress,"], ["o le malu i le afā,", "a refuge from the storm,"], ["o le paolo i le vevela,", "a shadow from the heat,"], ["pe a oo mai le ita o e o matautia e pei o se afā i le pa.", "when the blast of the terrible ones is as a storm against the wall."]]},
  {num:5,words:[["E pei o le vevela i le nuu naumati,", "Thou shalt bring down the noise of strangers,"], ["e te faamaulaloina le taalili o tagata ese;", "as the heat in a dry place;"], ["e pei o le vevela i le paolo o le ao,", "even the heat with the shadow of a cloud:"], ["e faamaulaloina lava le pese a tagata matautia.", "the branch of the terrible ones shall be brought low."]]},
  {num:6,words:[["E faia e Ieova o 'au i lenei mauga mo nuu uma le faigaai o mea lelei,", "And in this mountain shall the LORD of hosts make unto all people a feast of fat things,"], ["o le tausamiga o uaina ua tuu ai 'alu;", "a feast of wines on the lees,"], ["o mea e silisili ona lelei,", "of fat things full of marrow,"], ["o uaina ua faamaninoina sa tuu ai 'alu.", "of wines on the lees well refined."]]},
  {num:7,words:[["E faaumatia foi e ia i lenei mauga le ie ufiufi, o loo ufitia a'i nuu uma,", "And he will destroy in this mountain the face of the covering cast over all people,"], ["ma le ufiufi ua ufitia a'i nuu ese uma lava.", "and the vail that is spread over all nations."]]},
  {num:8,words:[["E faaumatia e ia le oti e faavavau;", "He will swallow up death in victory;"], ["e soloiesea foi e le Alii o Ieova o loimata i mata uma lava;", "and the Lord GOD will wipe away tears from off all faces;"], ["e faateaeseina foi e ia le gao o lona nuu i le lalolagi uma lava;", "and the rebuke of his people shall he take away from off all the earth:"], ["auā ua fetalai mai ai Ieova.", "for the LORD hath spoken it."]]},
  {num:9,words:[["O lea aso e faapea ai,", "And it shall be said in that day,"], ["Faauta,", "Lo,"], ["o lo tatou Atua lenei;", "this is our God;"], ["sa tatou faatalitali ia te ia,", "we have waited for him,"], ["ua ia faaolaina foi i tatou;", "and he will save us:"], ["o Ieova lava lenei,", "this is the LORD;"], ["sa tatou faatalitali ia te ia;", "we have waited for him,"], ["tatou te fiafia ma olioli i lana faaolataga.", "we will be glad and rejoice in his salvation."]]},
  {num:10,words:[["Auā e tumau le aao o Ieova i lenei mauga;", "For in this mountain shall the hand of the LORD rest,"], ["e solia foi Moapi i lona lava nuu,", "and Moab shall be trodden down under him,"], ["e pei ona solia o 'au o saito i le faaputuga nasu.", "even as straw is trodden down for the dunghill."]]},
  {num:11,words:[["E faaloloa foi e ia ona aao i totonu ia te i latou,", "And he shall spread forth his hands in the midst of them,"], ["e pei ona faaloloa lima o le tagata e aau ina ua aau; na te faamaulaloina lo latou faamaualuluga,", "as he that swimmeth spreadeth forth his hands to swim:"], ["atoa ma togafiti o latou lima.", "and he shall bring down their pride together with the spoils of their hands."]]},
  {num:12,words:[["Na te lafotuina le 'olo maualuga o ou pa,", "And the fortress of the high fort of thy walls shall he bring down,"], ["na te faamaulaloina,", "lay low,"], ["na te faagatasia ma le eleele,", "and bring to the ground,"], ["e oo lava i le efuefu.", "even to the dust."]]},
  {num:13,words:[["Le ALII", "the Lord"], ["e,", "by"], ["lo matou Atua,", "our God"], ["sa pule ia te i matou nisi alii", "rule unto in we some Lord"], ["e le", "by the"], ["na o oe;", "you"], ["ua na o oe lava matou te vivii atu ai", "you indeed we to praise"], ["i lou suafa.", "in your name"]]},
  {num:14,words:[["Ua oti", "die"], ["i latou,", "them"], ["latou te le toe ola;", "them the again life"], ["o agaga", "spirit"], ["i latou,", "them"], ["latou te le toe 1013", "them the again 1013"]]},
];
renderVerseSet(isa_ch_25_Verses, 'isa-ch25-verses');

var isa_ch_26_Verses = [
  {num:1,words:[["O lea aso e pese ai lenei pese i le laueleele o Iuta,", "In that day shall this song be sung in the land of Judah;"], ["Ua ia te i tatou le aai malosi;", "We have a strong city;"], ["o le faaolataga na te faia lea ma pa ma 'olo.", "salvation will God appoint for walls and bulwarks."]]},
  {num:2,words:[["Ina to mai ia e outou o puipui,", "Open ye the gates,"], ["ina ia ulufale mai ai le nuu amiotonu o e tausi le mea moni.", "that the righteous nation which keepeth the truth may enter in."]]},
  {num:3,words:[["E te leoleoina ia fifilemu lava le ua mausali lona loto;", "Thou wilt keep him in perfect peace, whose mind is stayed on thee:"], ["auā ua ia faatuatua ia te oe.", "because he trusteth in thee."]]},
  {num:4,words:[["Ina faatuatua ia outou ia Ieova e faavavau lava; auā o Ioa Ieova,", "Trust ye in the LORD for ever:"], ["o le papa e faavavau ia.", "for in the LORD JEHOVAH is everlasting strength:"]]},
  {num:5,words:[["Auā ua ia lafotuina i lalo e sa nonofo i le mea maualuga;", "For he bringeth down them that dwell on high; the lofty city,"], ["o le aai sa maualuga ua faamaulaloina e ia,", "he layeth it low;"], ["ua faamaulaloina ua oo i le eleele,", "he layeth it low,"], ["ua faagatasia ma le efuefu.", "even to the ground; he bringeth it even to the dust."]]},
  {num:6,words:[["E solia ia e vae,", "The foot shall tread it down,"], ["o vae lava o e tigaina,", "even the feet of the poor,"], ["o vae foi o e matitiva.", "and the steps of the needy."]]},
  {num:7,words:[["Ua laugatasi le ala o le ua amiotonu;", "The way of the just is uprightness:"], ["o e na lē amiotonu,", "thou, most upright,"], ["ua e faalauleleiina le ala o le ua amiotonu.", "dost weigh the path of the just."]]},
  {num:8,words:[["E moni,", "Yea,"], ["Ieova e,", "in the way of thy judgments,"], ["ua matou faatalitali ia te oe i le ala o au faamasinoga;", "O LORD, have we waited for thee;"], ["o le manao o matou loto o loo i ai lea i lou suafa,", "the desire of our soul is to thy name,"], ["ma le faamanatuga ia te oe.", "and to the remembrance of thee."]]},
  {num:9,words:[["Ua manao lo'u loto ia te oe i le po;", "With my soul have I desired thee in the night;"], ["e moni,", "yea,"], ["e ala saili ia te oe lo'u agaga i totonu ia te au;", "with my spirit within me will I seek thee early:"], ["auā e a'oa'oina e o nonofo i le atu laulau,", "for when thy judgments are in the earth,"], ["pe a faia au faamasinoga i le lalolagi.", "the inhabitants of the world will learn righteousness."]]},
  {num:10,words:[["E alofagia le ua amio leaga,", "Let favour be shewed to the wicked,"], ["a e le a'oa'o lava o ia i le amiotonu;", "yet will he not learn righteousness:"], ["o le nuu o i ai le amiotonu e agafaapiopio ai o ia,", "in the land of uprightness will he deal unjustly,"], ["na te le manatua foi le mamalu o Ieova.", "and will not behold the majesty of the LORD."]]},
  {num:11,words:[["Ieova e,", "LORD,"], ["e siitia lou aao,", "when thy hand is lifted up,"], ["a e latou te le vaavaai;", "they will not see:"], ["latou te vaavaai lava, e faamāina foi i latou;", "but they shall see,"], ["o le maelega ona o lou nuu,", "and be ashamed for their envy at the people;"], ["e moni,", "yea,"], ["o le afi ona o e ua ita ia te oe e faaumatia ai i latou.", "the fire of thine enemies shall devour them."]]},
  {num:12,words:[["Ieova e,", "LORD,"], ["e te tuuina mai le manuia ia te i matou;", "thou wilt ordain peace for us:"], ["auā foi ua e faia mo i matou a matou galuega uma.", "for thou also hast wrought all our works in us."]]},
  {num:13,words:[["Ieova e,", "O LORD our God,"], ["lo matou Atua,", "other lords beside thee have had dominion over us:"], ["sa pule ia te i matou nisi alii e le na o oe ua na o oe lava matou te vivii atu ai i lou suafa.", "but by thee only will we make mention of thy name."]]},
  {num:14,words:[["Ua oti i latou,", "They are dead,"], ["latou te le toe ola;", "they shall not live;"], ["o agaga i latou, latou te le toe tutū;", "they are deceased,"], ["auā ua e faasalaina,", "they shall not rise:"], ["ma faaumatia i latou,", "therefore hast thou visited and destroyed them,"], ["ua e faagaloina lava le manatu uma ia i latou.", "and made all their memory to perish."]]},
  {num:15,words:[["Ua e faatoateleina le nuu,", "Thou hast increased the nation,"], ["Ieova e,", "O LORD,"], ["ua e faatoateleina le nuu;", "thou hast increased the nation:"], ["ua viia lava oe;", "thou art glorified:"], ["ua e faamamaoina tuaoi uma o le nuu.", "thou hadst removed it far unto all the ends of the earth."]]},
  {num:16,words:[["Ieova e,", "LORD,"], ["na latou sailiili ia te oe i lo latou puapuaga,", "in trouble have they visited thee,"], ["na latou faapaūina atu le tatalo ona o lau aoaiga sa ia te i latou.", "they poured out a prayer when thy chastening was upon them."]]},
  {num:17,words:[["E pei o le fafine to ua latalata ona fanau,", "Like as a woman with child, that draweth near the time of her delivery,"], ["ua tiga ia ma uio i lona faatiga;", "is in pain,"], ["Ieova e,", "and crieth out in her pangs;"], ["sa faapea lava i matou i ou luma.", "so have we been in thy sight, O LORD."]]},
  {num:18,words:[["Sa totō i matou,", "We have been with child,"], ["sa faatiga,", "we have been in pain,"], ["e peiseai na matou fanau ma le savili;", "we have as it were brought forth wind;"], ["e lei faia e i matou se faaolataga i le lalolagi,", "we have not wrought any deliverance in the earth;"], ["e lei pauu foi e o nonofo i le atu laulau.", "neither have the inhabitants of the world fallen."]]},
  {num:19,words:[["E toe ola mai ou tagata oti,", "Thy dead men shall live,"], ["o latou tino oti e toe tutū mai. Ina ala mai ia,", "together with my dead body shall they arise. Awake and sing,"], ["ma alalaga fiafia outou e o nonofo i le efuefu;", "ye that dwell in dust:"], ["auā o lou sau e pei o le sau o le vao iti ia;", "for thy dew is as the dew of herbs,"], ["e lafo atu foi e le eleele e ua oti.", "and the earth shall cast out the dead."]]},
  {num:20,words:[["Ina o mai ia,", "Come,"], ["lo'u nuu e;", "my people,"], ["ina ulu atu ia i o outou afeafe,", "enter thou into thy chambers,"], ["ma pupuni o outou faitotoa;", "and shut thy doors about thee:"], ["ia outou lalafi e pei se emo ona puupuu,", "hide thyself as it were for a little moment,"], ["seia mavae atu le toasa.", "until the indignation be overpast."]]},
  {num:21,words:[["Auā faauta,", "For,"], ["o loo afio mai Ieova ai le mea o afio ai o ia,", "behold,"], ["ina ia faasalaina e o nonofo i le lalolagi ona o a latou amio leaga;", "the LORD cometh out of his place to punish the inhabitants of the earth for their iniquity:"], ["e faaalia foi e le eleele lana toto,", "the earth also shall disclose her blood,"], ["na te le toe ufitia foi lana fasi.", "and shall no more cover her slain."]]},
];
renderVerseSet(isa_ch_26_Verses, 'isa-ch26-verses');

var isa_ch_27_Verses = [
  {num:1,words:[["O lea aso e faasalaina ai e Ieova o leviatana, o le gata tele vave,", "In that day the LORD with his sore and great and strong sword shall punish leviathan the piercing serpent,"], ["o leviatana lava, o le gata taataai, e faasalaina lava i lana pelu maaa,", "even leviathan that crooked serpent;"], ["ma le tele ma le malosi; e fasimatea lava e ia le tanimo o loo i le vai.", "and he shall slay the dragon that is in the sea."]]},
  {num:2,words:[["O lea aso ia outou pepese ai i le tovine.", "In that day sing ye unto her, A vineyard of red wine."]]},
  {num:3,words:[["O a'u o Ieova,", "I the LORD do keep it;"], ["ou te leoleo i ai;", "I will water it every moment:"], ["ou te faasūsū pea lava i ai; ou te leoleo lava i ai i le po ma le ao,", "lest any hurt it,"], ["ne'i oo i ai se leaga.", "I will keep it night and day."]]},
  {num:4,words:[["Ou te le ita lava a'u;", "Fury is not in me:"], ["ta fia maua laau tuitui ma laau talatala i le taua; ou te alu atu ia te i latou,", "who would set the briers and thorns against me in battle? I would go through them,"], ["ou te susunu faatasi lava i latou.", "I would burn them together."]]},
  {num:5,words:[["Pe se'i tago o ia i lo'u malosi,", "Or let him take hold of my strength,"], ["ia mā lelei ma ia,", "that he may make peace with me;"], ["e lelei foi o ia ma a'u.", "and he shall make peace with me."]]},
  {num:6,words:[["O ona po amuli e sosolo ai aa o Iakopo;", "He shall cause them that come of Jacob to take root:"], ["e fuga mai ma mātala o Isaraelu,", "Israel shall blossom and bud,"], ["ona tumu ai lea o le fogāeleele uma i ona fua.", "and fill the face of the world with fruit."]]},
  {num:7,words:[["Ua na taia ea o ia, e pei ona taia e ia o i latou na taia o ia? po ua fasia o ia,", "Hath he smitten him,"], ["e pei o le fasi na fasia ai e ia?", "as he smote those that smote him? or is he slain according to the slaughter of them that are slain by him?"]]},
  {num:8,words:[["Na e finau faatatau ma ia ina ua tulia o ia;", "In measure, when it shooteth forth,"], ["na ia avea o ia i lona matagi tetele i le aso na agi mai ai le matagi mai sasae.", "thou wilt debate with it: he stayeth his rough wind in the day of the east wind."]]},
  {num:9,words:[["O le mea lea e faamagaloina ai le agasala a Iakopo i lea mea;", "By this therefore shall the iniquity of Jacob be purged;"], ["o ona iuga uma foi ia,", "and this is all the fruit to take away his sin;"], ["ina ia faateaeseina ai lana agasala; pe a faia e ia o maa uma o le fata faitaulaga ia pei o maa panisina ua nutililiia;", "when he maketh all the stones of the altar as chalkstones that are beaten in sunder,"], ["e le toe tutū i luga o tupua o Asaira ma tupua o le la.", "the groves and images shall not stand up."]]},
  {num:10,words:[["Auā e tuufua le aai nofo 'olo,", "Yet the defenced city shall be desolate,"], ["e le āina fale,", "and the habitation forsaken,"], ["a e tuulafoaiina e pei o se nuu tuufua;", "and left like a wilderness:"], ["e tataa ai tamai povi,", "there shall the calf feed,"], ["ma latou taooto ai,", "and there shall he lie down,"], ["latou te aai ona la laau.", "and consume the branches thereof."]]},
  {num:11,words:[["Pe a mamago ona la laau,", "When the boughs thereof are withered,"], ["ona gauieseina ai lea:", "they shall be broken off:"], ["e o mai fafine latou te susunuina;", "the women come, and set them on fire:"], ["auā e le se nuu mafaufau lea;", "for it is a people of no understanding:"], ["o le mea lea e le alofagia ai i latou e le na faia i latou,", "therefore he that made them will not have mercy on them,"], ["o ia foi na faia i latou na te le alofa lava ia te i latou.", "and he that formed them will shew them no favour."]]},
  {num:12,words:[["O lea lava aso e sasa ifo ai e Ieova ona fua ,", "And it shall come to pass in that day,"], ["e afua i le mea e tafe ai le vaitafe,", "that the LORD shall beat off from the channel of the river unto the stream of Egypt,"], ["e oo atu i le alia o Aikupito; e faapotopotoina foi outou e taitoatasi,", "and ye shall be gathered one by one,"], ["o outou le fanauga a Isaraelu.", "O ye children of Israel."]]},
  {num:13,words:[["O le aso foi lea e ili ai le pu latele,", "And it shall come to pass in that day,"], ["ona o mai ai lea o i latou na fai a fano i le nuu o Asuria,", "that the great trumpet shall be blown,"], ["atoa foi ma e na aunuua i le nuu o Aikupito,", "and they shall come which were ready to perish in the land of Assyria, and the outcasts in the land of Egypt,"], ["latou te ifo ia Ieova i le mauga paia i Ierusalema.", "and shall worship the LORD in the holy mount at Jerusalem."]]},
  {num:14,words:[["O le mea lea ia outou faalogologo mai ai", "therefore to ye all listen from"], ["i le afioga", "in the a word"], ["a le ALII,", "but the Lord"], ["outou tagata faatauemu,", "ye all man mock"], ["o e pule i lenei nuu o loo", "who rule in this nation"], ["i Ierusalema;", "in Jerusalem"], ["1015", "1015"]]},
];
renderVerseSet(isa_ch_27_Verses, 'isa-ch27-verses');

var isa_ch_28_Verses = [
  {num:1,words:[["Oi talofa i le palealii e faamaualuga,", "Woe to the crown of pride,"], ["o e onā o Efaraima,", "to the drunkards of Ephraim,"], ["atoa ma le fuga ua mamae o lo latou matagofie e faamananaia a'i i latou, o le ua i le ulu o le vanu lafulemu,", "whose glorious beauty is a fading flower,"], ["o i latou o e ua faiaina i le uaina.", "which are on the head of the fat valleys of them that are overcome with wine!"]]},
  {num:2,words:[["Faauta,", "Behold,"], ["o loo i le Alii le ua malosi ma le loto tele,", "the Lord hath a mighty and strong one,"], ["e pei o le afā o le ua to'a, o le afā fulifaō,", "which as a tempest of hail and a destroying storm,"], ["e pei o le tafe o vai tetele ua oso,", "as a flood of mighty waters overflowing,"], ["na te lafotuina ma le malosi i le eleele.", "shall cast down to the earth with the hand."]]},
  {num:3,words:[["E solia i vae le palealii e faamaualuga o e onā o Efaraima;", "The crown of pride, the drunkards of Ephraim, shall be trodden under feet:"]]},
  {num:4,words:[["o le fuga foi e mamae o lo latou mataofie e faamauanaia a'i i latou,", "And the glorious beauty,"], ["o le ua i le ulu o le vanu lafulemu,", "which is on the head of the fat valley,"], ["e avea ia e pei o mati ua muai otatā a o lei oo i le tausaga vevela;", "shall be a fading flower,"], ["ua iloa ai e le ua vaai atu i ai,", "and as the hasty fruit before the summer;"], ["a maua i lona lima,", "which when he that looketh upon it seeth,"], ["ona folo loa lea.", "while it is yet in his hand he eateth it up."]]},
  {num:5,words:[["O lea aso e avea ai Ieova o 'au ma palealii e matagofie,", "In that day shall the LORD of hosts be for a crown of glory, and for a diadem of beauty,"], ["ma pale lalelei i e ua totoe o lona nuu;", "unto the residue of his people,"]]},
  {num:6,words:[["e avea foi ma atamai e faamasino ai i lē nofo e fai le faamasinoga, e avea foi ma malosi,", "And for a spirit of judgment to him that sitteth in judgment,"], ["i e o faafoisia le taua i le faitotoa.", "and for strength to them that turn the battle to the gate."]]},
  {num:7,words:[["A e peitai o i latou,", "But they also have erred through wine,"], ["ua sese i latou i le uaina;", "and through strong drink are out of the way;"], ["ua feseseai i le 'ava;", "the priest and the prophet have erred through strong drink,"], ["ua sese le faitaulaga ma le perofeta i le 'ava; ua faiaina i latou i le uaina,", "they are swallowed up of wine,"], ["ua feseseai i latou i le 'ava;", "they are out of the way through strong drink;"], ["ua sese lo latou vaai,", "they err in vision,"], ["ua latou tautevateva i le faamasinoga.", "they stumble in judgment."]]},
  {num:8,words:[["Auā ua tutumu laoai uma i puaiga ma otaota,", "For all tables are full of vomit and filthiness,"], ["e leai lava se mea ua sao .", "so that there is no place clean."]]},
  {num:9,words:[["Na te a'oa'o atu ea ia te ai i le poto? na te faailoa ea ia te ai le tala? O e ua te'a ma le suāsusu,", "Whom shall he teach knowledge? and whom shall he make to understand doctrine? them that are weaned from the milk,"], ["ua faateaina lava ma le susu.", "and drawn from the breasts."]]},
  {num:10,words:[["Auā o loo i ai le upu ma le upu,", "For precept must be upon precept,"], ["o le upu ma le upu;", "precept upon precept;"], ["o le vavao ma le vavao,", "line upon line, line upon line;"], ["o le vavao ma le vavao;", "here a little,"], ["o sina mea itiiti iinei ma sina mea itiiti iina.", "and there a little:"]]},
  {num:11,words:[["Auā e tautala atu o ia i lenei nuu i upu e le matala, ma le gagana ese.", "For with stammering lips and another tongue will he speak to this people."]]},
  {num:12,words:[["Na ia fai atu foi ia te i latou,", "To whom he said,"], ["O le malologa lenei;", "This is the rest wherewith ye may cause the weary to rest;"], ["ia outou avatua le malologa i e ua lailoa; o le malologa foi lenei;", "and this is the refreshing:"], ["a ua latou le mafafai ona faalogo mai.", "yet they would not hear."]]},
  {num:13,words:[["E i ai foi le afioga a Ieova ia te i latou,", "But the word of the LORD was unto them precept upon precept,"], ["o le upu ma le upu,", "precept upon precept;"], ["o le upu ma le upu;", "line upon line,"], ["o le vavao ma le vavao,", "line upon line;"], ["o le vavao ma le vavao;", "here a little, and there a little;"], ["o sina mea itiiti iinei ma sina mea itiiti iina;", "that they might go,"], ["ina ia latou savavali ma pauu taliaga,", "and fall backward,"], ["ma ia momomo,", "and be broken,"], ["ia maileia foi,", "and snared,"], ["ma ia maua i latou.", "and taken."]]},
  {num:14,words:[["O le mea lea ia outou faalogologo mai ai i le afioga a Ieova,", "Wherefore hear the word of the LORD,"], ["outou tagata faatauemu,", "ye scornful men,"], ["o e pule i lenei nuu o loo i Ierusalema;", "that rule this people which is in Jerusalem."]]},
  {num:15,words:[["auā ua outou faapea mai,", "Because ye have said,"], ["Ua osia la matou feagaiga ma le oti;", "We have made a covenant with death,"], ["ua fai foi la matou feagaiga ma seoli;", "and with hell are we at agreement;"], ["a ui ane le sasa e lofia ai,", "when the overflowing scourge shall pass through,"], ["e le oo mai lea ia te i matou;", "it shall not come unto us:"], ["auā ua matou faia le pepelo mo matou malu;", "for we have made lies our refuge,"], ["ua matou lalafi foi i tala oole.", "and under falsehood have we hid ourselves:"]]},
  {num:16,words:[["O lenei,", "Therefore thus saith the Lord GOD,"], ["o loo faapea ona fetalai mai o le Alii o Ieova,", "Behold,"], ["Faauta,", "I lay in Zion for a foundation a stone,"], ["ou te tuuina i Siona le maa e fai ma faavae; o le maa ua uma ona faata'ita'iina,", "a tried stone,"], ["o le maa tulimanu tāua,", "a precious corner stone,"], ["o le faavae ua mau;", "a sure foundation:"], ["o lē faatuatua ia te ia e le popole lava ia.", "he that believeth shall not make haste."]]},
  {num:17,words:[["Ou te faia le faamasinoga ia faatatauina i le fua faataoto,", "Judgment also will I lay to the line,"], ["ou te faia foi le amiotonu ia faatatauina i le fua faatautau;", "and righteousness to the plummet:"], ["e tafea le malu o le tala pepelo i le uato'a,", "and the hail shall sweep away the refuge of lies,"], ["e lofia foi le lafitaga i le vai.", "and the waters shall overflow the hiding place."]]},
  {num:18,words:[["E faafuvaleina la outou feagaiga ma le oti,", "And your covenant with death shall be disannulled,"], ["e le tumau foi la outou feagaiga ma seoli;", "and your agreement with hell shall not stand;"], ["a ui ane le sasa e lofia ai,", "when the overflowing scourge shall pass through,"], ["ona solia ai lea outou e ia.", "then ye shall be trodden down by it."]]},
  {num:19,words:[["A ui ane ia,", "From the time that it goeth forth it shall take you:"], ["ona avea ai lea outou;", "for morning by morning shall it pass over,"], ["auā e ui ane ia i lea taeao ma lea taeao, i le ao atoa ma le po;", "by day and by night:"], ["a lagona na o le tala e matuā atuatuvale ai.", "and it shall be a vexation only to understand the report."]]},
  {num:20,words:[["Auā e puupuu le moega a le mafai e se tasi ona faaloloa ai o ia;", "For the bed is shorter than that a man can stretch himself on it:"], ["e lauitiiti le ie afu e le mafai ona pulupulu ai o ia.", "and the covering narrower than that he can wrap himself in it."]]},
  {num:21,words:[["Auā e tulai atu Ieova e pei ona faia i le mauga o Faresa,", "For the LORD shall rise up as in mount Perazim,"], ["e toasa foi o ia e pei ona fai i le vanu o Kipeona,", "he shall be wroth as in the valley of Gibeon,"], ["ina ia faia lana mea e fai,", "that he may do his work,"], ["ua ese lava;", "his strange work;"], ["ina ia faia foi lana galuega,", "and bring to pass his act,"], ["o lana galuega ese lava.", "his strange act."]]},
  {num:22,words:[["O lenei, aua tou te faatauemu,", "Now therefore be ye not mockers,"], ["ina ne'i atili ai ona faamauina o outou noanoaga;", "lest your bands be made strong:"], ["auā o le faaumatia ua pulea,", "for I have heard from the Lord GOD of hosts a consumption,"], ["ua ou faalogo ai mai le Alii o Ieova o 'au, e oo i le lalolagi uma lava.", "even determined upon the whole earth."]]},
  {num:23,words:[["Ina uai mai ia o outou taliga,", "Give ye ear,"], ["ma faalogo mai i lo'u leo;", "and hear my voice;"], ["ina faasaga mai ia outou,", "hearken,"], ["ma faalogo mai i la'u upu.", "and hear my speech."]]},
  {num:24,words:[["Ua galue ea i le suotosina i aso uma lava le ua galue i le suotosina ina ia lulu ai saito? Ua suatia ea e ia ma faamaluluina lona fanua?", "Doth the plowman plow all day to sow? doth he open and break the clods of his ground?"]]},
  {num:25,words:[["A uma ona faalauleleia e ia le eleele , e le saaluuina ea e ia le kiseka,", "When he hath made plain the face thereof,"], ["ma lulusoloina le kumina,", "doth he not cast abroad the fitches,"], ["ma totōina le saito faaatusolo,", "and scatter the cummin,"], ["ma le karite i le mea e totō ai, ma le kaseme i lona tuaoi?", "and cast in the principal wheat and the appointed barley and the rie in their place?"]]},
  {num:26,words:[["Auā ua a'oa'o lona Atua ia te ia i le tonu,", "For his God doth instruct him to discretion,"], ["ua ia a'oa'o lava ia te ia.", "and doth teach him."]]},
  {num:27,words:[["Auā e le solia le kiseka i le mea e soli ai saito,", "For the fitches are not threshed with a threshing instrument,"], ["e le faataamilo foi i luga o le kumina le mea e taavalevale a'i le fata faataavalevale;", "neither is a cart wheel turned about upon the cummin;"], ["a ua sasaina le kiseka i le sasa,", "but the fitches are beaten out with a staff,"], ["ua sasaina foi le kumina i le tootoo.", "and the cummin with a rod."]]},
  {num:28,words:[["E nutililii le saito;", "Bread corn is bruised;"], ["a e le solia pea lava e ia,", "because he will not ever be threshing it,"], ["pe toso ane i ai le mea e taavalevale a'i le fata faataavalevale;", "nor break it with the wheel of his cart,"], ["e le nutililiia foi e ana solofanua.", "nor bruise it with his horsemen."]]},
  {num:29,words:[["E ala mai lava lea mea mai ia Ieova o 'au;", "This also cometh forth from the LORD of hosts,"], ["e maeu lona faautauta,", "which is wonderful in counsel,"], ["e sili lava lona poto.", "and excellent in working."]]},
];
renderVerseSet(isa_ch_28_Verses, 'isa-ch28-verses');

var isa_ch_29_Verses = [
  {num:1,words:[["Oi talofa i Arielu,", "Woe to Ariel,"], ["o Arielu,", "to Ariel,"], ["o le aai sa nofo ai Tavita. Ina faaopoopo ia o lea tausaga ma lea tausaga;", "the city where David dwelt! add ye year to year;"], ["ia latou fai pea foi o tausamiga.", "let them kill sacrifices."]]},
  {num:2,words:[["A e peitai ou te faatigaina Arielu;", "Yet I will distress Ariel,"], ["e i ai le faanoanoa ma le faavauvau;", "and there shall be heaviness and sorrow:"], ["e ia te au foi o ia e pei o Arielu.", "and it shall be unto me as Ariel."]]},
  {num:3,words:[["Ou te to lauapi e vagavagai ia te oe;", "And I will camp against thee round about,"], ["ou te siosio ia te oe i 'au;", "and will lay siege against thee with a mount,"], ["ou te faatuina atu foi 'olo e tau ai ma oe.", "and I will raise forts against thee."]]},
  {num:4,words:[["E tuuina oe i lalo,", "And thou shalt be brought down,"], ["e tautala mai oe mai le eleele,", "and shalt speak out of the ground, and thy speech shall be low out of the dust,"], ["e leo itiiti mai au upu mai le efuefu;", "and thy voice shall be,"], ["o lou leo foi e oo mai mai le eleele e pei o le ua i ai le aitu vavalo;", "as of one that hath a familiar spirit, out of the ground,"], ["e te leo iī foi mai le efuefu.", "and thy speech shall whisper out of the dust."]]},
  {num:5,words:[["E pei o le efuefu ninii le toatele foi o e ua ita ia te oe;", "Moreover the multitude of thy strangers shall be like small dust,"], ["o le toatele foi o e ua matautia e pei o aputi e lelea i latou;", "and the multitude of the terrible ones shall be as chaff that passeth away: yea,"], ["e faafuasei ua se emo lava ona oo mai.", "it shall be at an instant suddenly."]]},
  {num:6,words:[["E asiasia oe e Ieova o 'au i le faititili,", "Thou shalt be visited of the LORD of hosts with thunder,"], ["ma le mafuie,", "and with earthquake,"], ["ma le taalili tele; o le asiosio,", "and great noise,"], ["ma le afā,", "with storm and tempest,"], ["ma le mumū o le afi e faaumatia ai.", "and the flame of devouring fire."]]},
  {num:7,words:[["E pei o le miti,", "And the multitude of all the nations that fight against Ariel,"], ["o le mea e vaaia i le po,", "even all that fight against her and her munition,"], ["e faapea foi le vao tagata o nuu uma o e tau ma Arielu, o i latou uma o e tau ma ia ma ona 'olo,", "and that distress her,"], ["atoa ma i latou o e faatiga ia te ia.", "shall be as a dream of a night vision."]]},
  {num:8,words:[["E pei o le ua fia 'ai o loo fai lana miti,", "It shall even be as when an hungry man dreameth,"], ["faauta,", "and, behold,"], ["ua 'ai lava ia;", "he eateth;"], ["a ua ala mai,", "but he awaketh,"], ["ua laina lava ia;", "and his soul is empty: or as when a thirsty man dreameth,"], ["e pei o le ua fia inu foi o loo fai lana miti,", "and,"], ["faauta,", "behold,"], ["ua inu ia;", "he drinketh;"], ["a ua ala mai,", "but he awaketh, and,"], ["faauta,", "behold,"], ["ua mole,", "he is faint,"], ["ua fia inu lava ia;", "and his soul hath appetite: so shall the multitude of all the nations be,"], ["e faapea lava le vao tagata o nuu uma o e tau i le mauga o Siona.", "that fight against mount Zion."]]},
  {num:9,words:[["Ia outou faatuatuai,", "Stay yourselves,"], ["ma ia outou ofo;", "and wonder;"], ["ia outou olioli,", "cry ye out,"], ["a e tauaso outou;", "and cry:"], ["ua latou onā,", "they are drunken,"], ["a e le o le uaina;", "but not with wine;"], ["ua latou tautevateva,", "they stagger,"], ["a e le o le 'ava.", "but not with strong drink."]]},
  {num:10,words:[["Auā ua liligi atu e Ieova le agaga e moe gase ai i luga ia te outou,", "For the LORD hath poured out upon you the spirit of deep sleep,"], ["ua fusifusia foi e ia o outou mata;", "and hath closed your eyes:"], ["ua ia ufitia foi mata o perofeta atoa ma outou alii,", "the prophets and your rulers,"], ["o tagata vaai ia.", "the seers hath he covered."]]},
  {num:11,words:[["Ua avea foi le faaaliga o mea uma ia te outou e pei o upu a le tasi ua faamaufaailogaina;", "And the vision of all is become unto you as the words of a book that is sealed,"], ["ua avatua i le ua iloa faitau,", "which men deliver to one that is learned,"], ["ua faapea atu,", "saying,"], ["Se'i faitau mai ia lenei tusi;", "Read this, I pray thee:"], ["a ua fai mai o ia,", "and he saith,"], ["Ou te le mafai,", "I cannot;"], ["auā ua faamaufaailogaina.", "for it is sealed:"]]},
  {num:12,words:[["Ona avatua lea o le tusi i le ua le iloa faitau,", "And the book is delivered to him that is not learned,"], ["ua faapea atu,", "saying,"], ["Se'i faitau mai ia lenei tusi;", "Read this, I pray thee:"], ["a ua fai mai o ia,", "and he saith,"], ["Ou te le iloa faitau.", "I am not learned."]]},
  {num:13,words:[["O le mea lea ua fetalai mai ai le Alii,", "Wherefore the Lord said,"], ["Ua faalatalata mai lenei nuu ia te au i o latou gutu,", "Forasmuch as this people draw near me with their mouth,"], ["ma latou vivii mai ia te au i o latou laugutu,", "and with their lips do honour me,"], ["a ua mamao lava o latou loto ia te au,", "but have removed their heart far from me,"], ["o lo latou mata'u foi ia te au ua a'oa'oina lea i upu a tagata;", "and their fear toward me is taught by the precept of men:"]]},
  {num:14,words:[["o le mea lava lea,", "Therefore,"], ["faauta mai,", "behold,"], ["o le a a'u faia ai le vavega i lenei nuu, o le vavega lava,", "I will proceed to do a marvellous work among this people,"], ["o le mea foi e ofo ai;", "even a marvellous work and a wonder:"], ["e fano lava le poto o latou tagata popoto,", "for the wisdom of their wise men shall perish,"], ["e mavae foi le mafaufau o latou tagata mafaufau.", "and the understanding of their prudent men shall be hid."]]},
  {num:15,words:[["Oi talofa i e o fai togafiti faaloloto ina ia lilo ai la latou filifiliga ia Ieova;", "Woe unto them that seek deep to hide their counsel from the LORD,"], ["ua fai i le pouliuli a latou mea,", "and their works are in the dark,"], ["ma ua faapea ane i latou,", "and they say,"], ["O ai ea se vaai mai ia te i tatou? o ai foi se iloa mai i tatou?", "Who seeth us? and who knoweth us?"]]},
  {num:16,words:[["E! lo outou faatuiese e. Pe faatusaina ea le omea i le tufuga? pe fai atu ea le mea na faia i le na na faia,", "Surely your turning of things upside down shall be esteemed as the potter's clay:"], ["E lei faia lava a'u e ia? pe fai atu ea le mea na gaosia i le na na gaosia o ia,", "for shall the work say of him that made it, He made me not? or shall the thing framed say of him that framed it,"], ["E leai sona mafaufau?", "He had no understanding?"]]},
  {num:17,words:[["E le toe itiiti lava ea,", "Is it not yet a very little while,"], ["ona liua lea o Lepanona ma fanua lafulemu, e ta'ua foi le fanua lafulemu,", "and Lebanon shall be turned into a fruitful field,"], ["o le vao matua?", "and the fruitful field shall be esteemed as a forest?"]]},
  {num:18,words:[["O le aso lava lea e lagona ai e o tutuli i upu a le tusi,", "And in that day shall the deaf hear the words of the book, and the eyes of the blind shall see out of obscurity,"], ["e faapupulaina foi mata o e ua tauaso ina ua te'a le pouliuli ma le pogisa.", "and out of darkness."]]},
  {num:19,words:[["O e tigaina e faatuputeleina lo latou fiafia ia Ieova;", "The meek also shall increase their joy in the LORD,"], ["o tagata matitiva foi e olioli i latou i le Paia o Isaraelu.", "and the poor among men shall rejoice in the Holy One of Israel."]]},
  {num:20,words:[["Auā ua mavae atu le na faasaua,", "For the terrible one is brought to nought,"], ["ua faaumatia le na tauemu,", "and the scorner is consumed,"], ["e fasiotia foi i latou uma o e na mataala e fai mea leaga;", "and all that watch for iniquity are cut off:"]]},
  {num:21,words:[["o e na faasalaina le tagata i lana upu,", "That make a man an offender for a word,"], ["ma latou taumailei i le ua fai finauga i le faitotoa,", "and lay a snare for him that reproveth in the gate,"], ["ma faaliliueseina fua lava le ua amiotonu.", "and turn aside the just for a thing of nought."]]},
  {num:22,words:[["O lenei,", "Therefore thus saith the LORD,"], ["o loo faapea ona fetalai mai o Ieova,", "who redeemed Abraham,"], ["o le na laveaiina Aperaamo, ua faapea mai i le aiga o Iakopo,", "concerning the house of Jacob,"], ["E le toe faamāina lava Iakopo,", "Jacob shall not now be ashamed,"], ["e le toe sesega foi ona mata.", "neither shall his face now wax pale."]]},
  {num:23,words:[["Auā a vaai atu o ia i lana fanau,", "But when he seeth his children,"], ["o le galuega a o'u lima,", "the work of mine hands,"], ["i totonu ia te ia,", "in the midst of him,"], ["latou te ta'upaiaina lo'u igoa,", "they shall sanctify my name,"], ["ma ta'upaiaina le Paia o Iakopo,", "and sanctify the Holy One of Jacob,"], ["latou te matatau foi i le Atua o Isaraelu.", "and shall fear the God of Israel."]]},
  {num:24,words:[["O e na sese i o latou loto, latou te iloa mafaufau;", "They also that erred in spirit shall come to understanding,"], ["o e na muimui foi latou te a'oa'o ia popoto.", "and they that murmured shall learn doctrine."]]},
];
