var isa_ch_38_Verses = [
  {num:1,words:[["O ona po ia na ma'i ai Esekia, ua tāli oti.", "In those days was Hezekiah sick unto death."], ["Ona sau ai lea ia te ia o le perofeta o Isaia le atalii o Amota,", "And Isaiah the prophet the son of Amoz came unto him,"], ["ua fai mai ia te ia,", "and said unto him,"], ["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["Sauni ia sau mavaega i lou aiga,", "Set thine house in order:"], ["auā o le a e maliu,", "for thou shalt die,"], ["e te le soifua.", "and not live."]]},
  {num:2,words:[["Ona liliu atu ai lea e Esekia ona fofoga i le pa o le fale,", "Then Hezekiah turned his face toward the wall,"], ["ua tatalo atu o ia ia Ieova,", "and prayed unto the LORD,"]]},
  {num:3,words:[["ua faapea atu,", "And said,"], ["Ieova e,", "Remember now,"], ["ou te aioi atu,", "O LORD,"], ["ia e manatu mai i lo'u savali i ou luma ma le faamaoni,", "I beseech thee,"], ["ma le loto atoa,", "how I have walked before thee in truth and with a perfect heart,"], ["ua ou faia foi mea ua e finagalo i ai. Ona tagi lotulotu ai lea o Esekia.", "and have done that which is good in thy sight. And Hezekiah wept sore."]]},
  {num:4,words:[["Ona oo mai ai lea o le afioga a Ieova ia Isaia,", "Then came the word of the LORD to Isaiah,"], ["ua faapea mai,", "saying,"]]},
  {num:5,words:[["Alu ia,", "Go,"], ["ina e fai atu ia Esekia,", "and say to Hezekiah,"], ["O loo faapea ona fai mai o Ieova le Atua o Tavita lou tamā,", "Thus saith the LORD,"], ["Ua ou faalogo i lau tatalo,", "the God of David thy father, I have heard thy prayer,"], ["ua ou iloa ou loimata;", "I have seen thy tears:"], ["faauta foi,", "behold,"], ["ou te faaopoopo i aso o lou ola o tausaga e sefulu ma le lima;", "I will add unto thy days fifteen years."]]},
  {num:6,words:[["Ou te laveai foi ia te oe ma le aai nei ai le lima o le tupu o Asuria;", "And I will deliver thee and this city out of the hand of the king of Assyria:"], ["ou te faamamaluina foi lenei aai.", "and I will defend this city."]]},
  {num:7,words:[["O lenei foi le faailoga mai ia Ieova ia te oe e te iloa ai ,", "And this shall be a sign unto thee from the LORD,"], ["e faia e Ieova lenei lava mea ua na fetalaia mai.", "that the LORD will do this thing that he hath spoken;"]]},
  {num:8,words:[["Faauta,", "Behold,"], ["ou te faafoi atu le ata i vaega na uma ona alu ifo i le mea a Aasa e vaevae ai itu la,", "I will bring again the shadow of the degrees, which is gone down in the sun dial of Ahaz,"], ["ia foi atu i vaega e sefulu.", "ten degrees backward."], ["Ona foi atu ai lea o le la i vaega e sefulu,", "So the sun returned ten degrees,"], ["o vaega lava ia ua uma ona alu ifo ai.", "by which degrees it was gone down."]]},
  {num:9,words:[["O le tusi a Esekia le tupu o Iuta,", "The writing of Hezekiah king of Judah, when he had been sick,"], ["ina ua malolo o ia sa ma'i.", "and was recovered of his sickness:"]]},
  {num:10,words:[["Na a'u faapea ane,", "I said in the cutting off of my days,"], ["O le tautuluaga o lo'u ola ou te ulu atu ai i faitotoa o le tuugamau,", "I shall go to the gates of the grave:"], ["e aveesea o'u tausaga ua totoe.", "I am deprived of the residue of my years."]]},
  {num:11,words:[["Na a'u faapea ane,", "I said,"], ["Ou te le toe iloa Ioa,", "I shall not see the LORD,"], ["o Ioa lava, i le nuu o tagata ola;", "even the LORD,"], ["ou te le toe vaavaai i tagata,", "in the land of the living:"], ["faatasi ma e o nonofo i le lalolagi.", "I shall behold man no more with the inhabitants of the world."]]},
  {num:12,words:[["Ua liaiina lo'u fale,", "Mine age is departed,"], ["ua aveeseina ia te au e pei o le fale ie o le leoleo mamoe;", "and is removed from me as a shepherd's tent:"], ["ua ou taataaia lo'u ola e pei o lē laga ie;", "I have cut off like a weaver my life:"], ["ua na vavaeeseina a'u i pito manoa;", "he will cut me off with pining sickness:"], ["o le aso e tasi e te faaumatia ai a'u.", "from day even to night wilt thou make an end of me."]]},
  {num:13,words:[["Na a'u fifilemu seia ao,", "I reckoned till morning, that,"], ["ona ia momomo ai lea o o'u ivi uma e pei o se leona;", "as a lion,"], ["o le aso e tasi e te faaumatia ai a'u.", "so will he break all my bones: from day even to night wilt thou make an end of me."]]},
  {num:14,words:[["E pei o le pe'ape'a,", "Like a crane or a swallow,"], ["po o le akuru,", "so did I chatter:"], ["e faapea lava ona ou iī;", "I did mourn as a dove:"], ["ou te tagi e pei o le lupe; ua tiga o'u mata i lo'u vaavaai ae;", "mine eyes fail with looking upward:"], ["Ieova e,", "O LORD,"], ["ua puapuagatia a'u,", "I am oppressed;"], ["ia fai oe mo'u fesoasoani.", "undertake for me."]]},
  {num:15,words:[["Pe se a se mea ou te fai atu ai? na fetalai mai lava o ia ia te au,", "What shall I say? he hath both spoken unto me,"], ["o ia foi na ia faia; ou te savali ma le faamaulalo i o'u tausaga uma,", "and himself hath done it:"], ["ona o le tiga o lo'u loto.", "I shall go softly all my years in the bitterness of my soul."]]},
  {num:16,words:[["Le Alii e,", "O Lord,"], ["o mea i e ola ai tagata;", "by these things men live,"], ["o mea uma ia e ola ai lou agaga;", "and in all these things is the life of my spirit:"], ["e te faamalolo ia te au,", "so wilt thou recover me,"], ["e te faaola foi ia te au.", "and make me to live."]]},
  {num:17,words:[["Faauta,", "Behold,"], ["ua suia lo'u tiga tele i le filemu;", "for peace I had great bitterness:"], ["na e finagalo e laveaiina a'u i le lua e faaumatia ai;", "but thou hast in love to my soul delivered it from the pit of corruption:"], ["auā ua e lafoaiina a'u agasala uma i ou tua.", "for thou hast cast all my sins behind thy back."]]},
  {num:18,words:[["Auā e le vivii atu le tuugamau ia te oe;", "For the grave cannot praise thee,"], ["e le faaneenee le oti ia te oe;", "death can not celebrate thee:"], ["o e o ifo i le lua latou te le faamoemoe i lou faamaoni.", "they that go down into the pit cannot hope for thy truth."]]},
  {num:19,words:[["O le ua ola,", "The living,"], ["o le ua ola,", "the living,"], ["o ia lava e vivii atu ia te oe,", "he shall praise thee,"], ["e pei o a'u lava i le aso nei;", "as I do this day:"], ["e faailoa lou faamaoni e le tamā i lana fanau.", "the father to the children shall make known thy truth."]]},
  {num:20,words:[["Ua faaolaina a'u e Ieova;", "The LORD was ready to save me:"], ["matou te taia a'u nekina i le fale o Ieova i aso uma o lo matou ola.", "therefore we will sing my songs to the stringed instruments all the days of our life in the house of the LORD."]]},
  {num:21,words:[["Auā sa fai atu Isaia,", "For Isaiah had said,"], ["Ia latou ave se potopotogāmati,", "Let them take a lump of figs,"], ["ma tuu ai o tu'ivaivai i le mea na fulaga'i,", "and lay it for a plaister upon the boil,"], ["ona malolo ai lea o ia.", "and he shall recover."]]},
  {num:22,words:[["Sa fai atu foi Esekia, Se a se mea ou te iloa ai,", "Hezekiah also had said,"], ["ou te alu ae i le fale o Ieova?", "What is the sign that I shall go up to the house of the LORD?"]]},
];
