var isa_ch_40_Verses = [
  {num:1,words:[["Ia outou faamafanafana,", "Comfort ye,"], ["ina faamafanafana atu ia outou i lo'u nuu,", "comfort ye my people,"], ["ua fetalai mai ai lo outou Atua.", "saith your God."]]},
  {num:2,words:[["Ia outou faamatalaloto ia Ierusalema,", "Speak ye comfortably to Jerusalem,"], ["ma outou alalaga ia te ia,", "and cry unto her,"], ["ua iu ona po o lona tiga,", "that her warfare is accomplished,"], ["ua tauia lana amioletonu;", "that her iniquity is pardoned:"], ["auā ua na maua faalua mai le lima o Ieova le taui ona o ana agasala uma.", "for she hath received of the LORD'S hand double for all her sins."]]},
  {num:3,words:[["O le leo o le ua alaga i le vao,", "The voice of him that crieth in the wilderness,"], ["Ina teuteu ia outou le ala o Ieova;", "Prepare ye the way of the LORD,"], ["ia outou faalauleleia le ala tele i le vao lafulafua mo lo tatou Atua.", "make straight in the desert a highway for our God."]]},
  {num:4,words:[["O vanu uma e faaeaina ia;", "Every valley shall be exalted,"], ["o mauga uma ma mea maupuepue e faamaulaloina ia;", "and every mountain and hill shall be made low:"], ["o mea faafatiatamai e fai ma mea faalaugatasi ia,", "and the crooked shall be made straight,"], ["ma mea gaoa e fai ma mea laulelei.", "and the rough places plain:"]]},
  {num:5,words:[["Ona faaalia mai ai lea o le pupula o Ieova e vāaia lava e tagata uma faatasi;", "And the glory of the LORD shall be revealed, and all flesh shall see it together:"], ["auā ua fetalai mai ai le fofoga o Ieova.", "for the mouth of the LORD hath spoken it."]]},
  {num:6,words:[["Ua fai mai le leo,", "The voice said,"], ["Ina alaga ia.", "Cry."], ["Ona fai atu lea o ia,", "And he said,"], ["Se a ea se upu ou te alagaina? O tagata uma o le mutia i latou, ma lo latou lelei uma,", "What shall I cry? All flesh is grass,"], ["e tusa lea ma le fuga o le vao;", "and all the goodliness thereof is as the flower of the field:"]]},
  {num:7,words:[["e magumagu le mutia,", "The grass withereth,"], ["e toulu le fuga;", "the flower fadeth:"], ["auā o le mānava o Ieova ua agi mai i ai; e moni,", "because the spirit of the LORD bloweth upon it:"], ["o le mutia lava le nuu.", "surely the people is grass."]]},
  {num:8,words:[["E magumagu le mutia,", "The grass withereth,"], ["e toulu le fuga; a o le afioga a lo tatou Atua,", "the flower fadeth:"], ["e tumau lea e faavavau.", "but the word of our God shall stand for ever."]]},
  {num:9,words:[["Alu ae i le mauga maualuga,", "O Zion,"], ["o oe lē au mai le tala lelei ia Siona;", "that bringest good tidings,"], ["ia matuā leo tele,", "get thee up into the high mountain; O Jerusalem,"], ["o oe lē au mai le tala lelei ia Ierusalema;", "that bringest good tidings,"], ["ia leo tele,", "lift up thy voice with strength;"], ["aua le fefe;", "lift it up, be not afraid;"], ["fai atu i aai o Iuta,", "say unto the cities of Judah,"], ["Faauta i lo outou Atua.", "Behold your God!"]]},
  {num:10,words:[["Faauta,", "Behold,"], ["e afio mai le Alii o Ieova ma le malosi,", "the Lord GOD will come with strong hand,"], ["e pule lona aao mo ia;", "and his arm shall rule for him:"], ["faauta,", "behold,"], ["ua ia te ia lana taui,", "his reward is with him,"], ["ua i ona luma le totogi o lana galuega.", "and his work before him."]]},
  {num:11,words:[["Na te leoleoina lona lafu e pei o le leoleo mamoe;", "He shall feed his flock like a shepherd:"], ["na te sapaia tamai mamoe i ona lima,", "he shall gather the lambs with his arm,"], ["ma tauave i latou i lona fatafata;", "and carry them in his bosom,"], ["na te ta'ita'i filemu i mamoe ua fananau.", "and shall gently lead those that are with young."]]},
  {num:12,words:[["O ai ea ua na fuatia le sami i lona alofilima,", "Who hath measured the waters in the hollow of his hand,"], ["ma na fuatia le lagi i le āga,", "and meted out heaven with the span,"], ["ma na fuatia le eleele o le lalolagi i le fua faaofuofu;", "and comprehended the dust of the earth in a measure,"], ["ua na fuatia mauga foi i le fua,", "and weighed the mountains in scales,"], ["ma mauga iti i le fua faatautau?", "and the hills in a balance?"]]},
  {num:13,words:[["O ai ea ua fuatia le atamai o Ieova? o ai foi se tagata e pulega faatasi ma ia,", "Who hath directed the Spirit of the LORD,"], ["ua na a'oa'oina o ia?", "or being his counsellor hath taught him?"]]},
  {num:14,words:[["O ai ea se na la filifili faatasi ma ia,", "With whom took he counsel,"], ["ma na a'oa'o ia te ia,", "and who instructed him,"], ["ma na a'oa'o ia te ia i le ala o le faamasinoga;", "and taught him in the path of judgment,"], ["ma na a'oa'o ia te ia ia poto ai,", "and taught him knowledge,"], ["ma na faailoa ia te ia le ala o le faautauta?", "and shewed to him the way of understanding?"]]},
  {num:15,words:[["Faauta o atu nuu e tusa i latou ma si mea e sisina ifo nai le pakete;", "Behold,"], ["e faatatauina i latou e pei o le efuefu i le fua faatautau;", "the nations are as a drop of a bucket,"], ["faauta,", "and are counted as the small dust of the balance: behold,"], ["na te siitia nuu tu tai e peiseai sina mea ninii lava.", "he taketh up the isles as a very little thing."]]},
  {num:16,words:[["E le lava foi Lepanona ina mu a'i le afi; ma manu o i ai,", "And Lebanon is not sufficient to burn,"], ["e le lava ai se taulaga mu.", "nor the beasts thereof sufficient for a burnt offering."]]},
  {num:17,words:[["O atu nuu uma peiseai ua leai i ona luma;", "All nations before him are as nothing;"], ["ua matuā leai lava i latou i lona manatu,", "and they are counted to him less than nothing,"], ["ma ua matuā faatauvaa lava.", "and vanity."]]},
  {num:18,words:[["O lenei, tou te faatusa le Atua ia te ai? se a foi se faatusa tou te faatusaina ai o ia?", "To whom then will ye liken God? or what likeness will ye compare unto him?"]]},
  {num:19,words:[["O le tufuga na te gaosia le tupua uamea,", "The workman melteth a graven image,"], ["ma lē fai mea uamea na te ufiufi ai i le auro;", "and the goldsmith spreadeth it over with gold,"], ["na te gaosia filifili ario.", "and casteth silver chains."]]},
  {num:20,words:[["O le ua mativa i taulaga na te filifilia se laau e le pala;", "He that is so impoverished that he hath no oblation chooseth a tree that will not rot;"], ["na te sailia sana tufuga poto,", "he seeketh unto him a cunning workman to prepare a graven image,"], ["ia na faia se tupua e le maluluina.", "that shall not be moved."]]},
  {num:21,words:[["Tou te le iloa ea? Tou te lei faalogo ea? E lei ta'uina atu ea ia te outou mai le amataga? Tou te lei lagona ea mai le faavaeina o le lalolagi?", "Have ye not known? have ye not heard? hath it not been told you from the beginning? have ye not understood from the foundations of the earth?"]]},
  {num:22,words:[["O ia lē tietie i luga o le faataaliolio o le lalolagi,", "It is he that sitteth upon the circle of the earth,"], ["a o e nonofo ai e tutusa i latou ma sē;", "and the inhabitants thereof are as grasshoppers;"], ["o ia lē fofola le lagi e pei o se ie manifinifi;", "that stretcheth out the heavens as a curtain,"], ["na te faamafolafolaina ai foi e pei o se fale ie e nofo ai.", "and spreadeth them out as a tent to dwell in:"]]},
  {num:23,words:[["Na te liua alii ia leai;", "That bringeth the princes to nothing;"], ["o faamasino o le lalolagi ua faia i latou e ia e tusa ma se mea faatauvaa.", "he maketh the judges of the earth as vanity."]]},
  {num:24,words:[["Ua le totōina lava i latou,", "Yea, they shall not be planted;"], ["ua le luluina lava ni o latou fua,", "yea,"], ["ua le mau aa lava i le eleele lo latou pogai;", "they shall not be sown:"], ["ua na ona ulafia i latou e ia,", "yea, their stock shall not take root in the earth:"], ["ona mamago ai lea o i latou,", "and he shall also blow upon them, and they shall wither,"], ["e avea foi i le afā e pei o le tagutugutu o saito.", "and the whirlwind shall take them away as stubble."]]},
  {num:25,words:[["O lenei,", "To whom then will ye liken me,"], ["po o ai ea tou te faatusa i ai a'u? po o ai foi ma te tutusa? ua fetalai mai ai le Paia.", "or shall I be equal? saith the Holy One."]]},
  {num:26,words:[["Se'i tetepa ae i luga,", "Lift up your eyes on high,"], ["ma outou vaai,", "and behold who hath created these things,"], ["po o ai ea ua na faia nei mea? Na te ta'ita'iina mai a latou 'au ua faitauina;", "that bringeth out their host by number:"], ["na te valaau ia te i latou uma i o latou igoa;", "he calleth them all by names by the greatness of his might,"], ["ona o le tele o lona malosi ma lona mana tele;", "for that he is strong in power;"], ["e leai so latou e le iloa.", "not one faileth."]]},
  {num:27,words:[["Iakopo e,", "Why sayest thou,"], ["se a le mea e te fai ane ai? Isaraelu e,", "O Jacob,"], ["se a le mea e te faapea ai,", "and speakest, O Israel,"], ["Ua lilo lo'u ala ia Ieova,", "My way is hid from the LORD,"], ["ua tuua foi lo'u faamasinoga e lo'u Atua?", "and my judgment is passed over from my God?"]]},
  {num:28,words:[["E te le iloa ea? E te lei faalogo ai ea? O le Atua o le vavau,", "Hast thou not known? hast thou not heard,"], ["o Ieova o le na faia tuluiga o le lalolagi,", "that the everlasting God,"], ["e le vaivai o ia,", "the LORD, the Creator of the ends of the earth,"], ["e le tigaina foi,", "fainteth not,"], ["e le masuesueina lona mafaufau.", "neither is weary? there is no searching of his understanding."]]},
  {num:29,words:[["Na te avatua le malosi i e ua vaivai; a o e ua leai se malosi,", "He giveth power to the faint;"], ["na te faatuputele i ai le malosi.", "and to them that have no might he increaseth strength."]]},
  {num:30,words:[["E vaivai ma tigaina tama matutua; o taulelea foi,", "Even the youths shall faint and be weary,"], ["e pauu lava i latou;", "and the young men shall utterly fall:"]]},
  {num:31,words:[["a o e faatalitali ia Ieova,", "But they that wait upon the LORD shall renew their strength;"], ["e toe faafouina lo latou malosi;", "they shall mount up with wings as eagles;"], ["latou te sii ae apaau e pei o aeto; latou te femoei,", "they shall run,"], ["a e le vaivai;", "and not be weary;"], ["latou te savavali,", "and they shall walk,"], ["a e le tigaina.", "and not faint."]]},
];
renderVerseSet(isa_ch_40_Verses, 'isa-ch40-verses');

var isa_ch_41_Verses = [
  {num:1,words:[["Faalologo ia outou o nuu tu matafaga i o'u luma;", "Keep silence before me,"], ["o nuu foi,", "O islands;"], ["ia toe faafouina lo latou malosi;", "and let the people renew their strength:"], ["ia faalatalata mai i latou,", "let them come near;"], ["ona latou tautala ai lea;", "then let them speak:"], ["ia tatou faalatalata faatasi o le faamasinoga.", "let us come near together to judgment."]]},
  {num:2,words:[["O ai ea na na faaoso mai le ua amiotonu mai sasae? ua valaau atu ia te ia ia mulimuli ia te ia;", "Who raised up the righteous man from the east,"], ["ua tuuina atu ia te ia nuu ese,", "called him to his foot,"], ["ua ia faatoilaloina foi tupu;", "gave the nations before him,"], ["ua ia tuuina atu i latou e pei o le efu i lana pelu,", "and made him rule over kings? he gave them as the dust to his sword,"], ["ua tuuina atu i latou i lana aufana e pei o tagutugutu o saito ua taape.", "and as driven stubble to his bow."]]},
  {num:3,words:[["Ua ia tuliloaina i latou,", "He pursued them, and passed safely;"], ["ua ia ui atu ma le saogalemu i le ala e lei ui ai ona vae.", "even by the way that he had not gone with his feet."]]},
  {num:4,words:[["O ai ea ua ia saunia ma na faia,", "Who hath wrought and done it,"], ["o lē valaau i tupulaga talu mai le amataga? O a'u o Ieova,", "calling the generations from the beginning? I the LORD,"], ["o lē muamua e faatasi foi ma lē mulimuli,", "the first, and with the last;"], ["o a'u lava ia.", "I am he."]]},
  {num:5,words:[["Na vaaia e nuu tu matafaga,", "The isles saw it,"], ["ona latou fefefe ai lea;", "and feared;"], ["ua gatete tuluiga o le lalolagi;", "the ends of the earth were afraid, drew near,"], ["ua faalatalata mai ma o mai i latou.", "and came."]]},
  {num:6,words:[["Ua latou fesoasoani le tasi i le tasi;", "They helped every one his neighbour;"], ["ua fai atu le tasi i le tasi,", "and every one said to his brother,"], ["Faamalosi ia.", "Be of good courage."]]},
  {num:7,words:[["Ua faamalosi le tufuga i lē fai mea uamea;", "So the carpenter encouraged the goldsmith,"], ["o le ua faamolemole i le samala,", "and he that smootheth with the hammer him that smote the anvil,"], ["ua ia faamalosi i le ua tu'i le mea e tu'i ai uamea; ua faapea ane,", "saying,"], ["E lelei le pulu;", "It is ready for the sodering:"], ["ua ia faamauina foi i fao,", "and he fastened it with nails,"], ["e le maluluina.", "that it should not be moved."]]},
  {num:8,words:[["A o oe Isaraelu e la'u auauna,", "But thou,"], ["o oe Iakopo e,", "Israel,"], ["le na ou filifilia,", "art my servant, Jacob whom I have chosen,"], ["o le fanau a Aperaamo la'u uo;", "the seed of Abraham my friend."]]},
  {num:9,words:[["o oe le na ou aumaia i tuluiga o le lalolagi,", "Thou whom I have taken from the ends of the earth,"], ["na a'u valaauina foi oe i ona itu mamao;", "and called thee from the chief men thereof,"], ["na ou fai atu foi ia te oe,", "and said unto thee,"], ["O oe o la'u auauna,", "Thou art my servant;"], ["o le na ou filifilia,", "I have chosen thee,"], ["ou te lei lafoaiina oe.", "and not cast thee away."]]},
  {num:10,words:[["Aua e te fefe,", "Fear thou not;"], ["auā ou te ia te oe;", "for I am with thee:"], ["aua le fetepatepai,", "be not dismayed;"], ["auā o a'u o lou Atua;", "for I am thy God:"], ["ou te faamalosia oe;", "I will strengthen thee;"], ["e moni,", "yea,"], ["ou te fesoasoani ia te oe;", "I will help thee;"], ["e moni,", "yea,"], ["ou te taofia oe i lo'u lima taumatau e i ai le amiotonu.", "I will uphold thee with the right hand of my righteousness."]]},
  {num:11,words:[["Faauta,", "Behold,"], ["e mamā ma masiasi i latou uma o e ita ia te oe;", "all they that were incensed against thee shall be ashamed and confounded:"], ["e avea i latou e peiseai ua leai;", "they shall be as nothing;"], ["e fano foi i latou o e finau atu ia te oe.", "and they that strive with thee shall perish."]]},
  {num:12,words:[["E te sailia i latou,", "Thou shalt seek them,"], ["a e te le maua i latou o e fai oe mo latou fili;", "and shalt not find them,"], ["e avea i latou peiseai ua leai,", "even them that contended with thee: they that war against thee shall be as nothing,"], ["e peiseai ua matuā leai lava e na tau ma oe.", "and as a thing of nought."]]},
  {num:13,words:[["Auā o a'u o Ieova lou Atua, o le ua taofi lou lima taumatau;", "For I the LORD thy God will hold thy right hand,"], ["o le ua fai atu ia te oe,", "saying unto thee,"], ["Aua e te fefe,", "Fear not;"], ["o a'u, ou te fesoasoani ia te oe.", "I will help thee."]]},
  {num:14,words:[["Aua e te fefe,", "Fear not,"], ["le anufe Iakopo e,", "thou worm Jacob,"], ["ma tagata o Isaraelu;", "and ye men of Israel;"], ["o a'u, ou te fesoasoani ia te oe,", "I will help thee,"], ["ua fetalai mai ai Ieova,", "saith the LORD,"], ["o le na faatauina oe,", "and thy redeemer,"], ["le Paia o Isaraelu.", "the Holy One of Israel."]]},
  {num:15,words:[["Faauta, ou te avea oe ma mea e soli a'i saito,", "Behold,"], ["e maamaai,", "I will make thee a new sharp threshing instrument having teeth:"], ["e fou, e fai nifo;", "thou shalt thresh the mountains,"], ["e te solia ai mauga,", "and beat them small,"], ["ma e nutininii ai; e te faia foi mauga iti e pei o aputi o saito.", "and shalt make the hills as chaff."]]},
  {num:16,words:[["E te faasavili ia te i latou,", "Thou shalt fan them,"], ["e lelea foi i latou i le matagi;", "and the wind shall carry them away,"], ["e faataapeapeina i latou i le afā; a o oe,", "and the whirlwind shall scatter them:"], ["e te olioli ia Ieova,", "and thou shalt rejoice in the LORD,"], ["e te mitamita foi i le Paia o Isaraelu.", "and shalt glory in the Holy One of Israel."]]},
  {num:17,words:[["O e ua tigaina ma ē matitiva o loo latou saili i se vai,", "When the poor and needy seek water,"], ["a ua leai; ua matutu o latou laulaufaiva i le fia inu;", "and there is none,"], ["o a'u o Ieova,", "and their tongue faileth for thirst,"], ["ou te tali atu ia te i latou, o a'u o le Atua o Isaraelu,", "I the LORD will hear them,"], ["ou te le tuulafoaiina i latou.", "I the God of Israel will not forsake them."]]},
  {num:18,words:[["Ou te suena vaitafe i luga o mauga tula,", "I will open rivers in high places,"], ["ma vaipuna i vanu;", "and fountains in the midst of the valleys:"], ["ou te faia le vao lafulafua ma vailepa,", "I will make the wilderness a pool of water,"], ["ou te faia foi le laueleele naumati ma vaipuna.", "and the dry land springs of water."]]},
  {num:19,words:[["Ou te avatu i le laueleele lafulafua le arasi,", "I will plant in the wilderness the cedar,"], ["ma le setima,", "the shittah tree,"], ["ma le atasi,", "and the myrtle,"], ["ma le laau e maua ai le suāuu;", "and the oil tree;"], ["ou te tuuina atu foi i le toafa o le perosi,", "I will set in the desert the fir tree,"], ["o le titara,", "and the pine,"], ["faatasi ma le tasura;", "and the box tree together:"]]},
  {num:20,words:[["ina ia latou vaai,", "That they may see,"], ["ma latou iloa,", "and know,"], ["ma mafaufau,", "and consider,"], ["ma faautauta faatasi,", "and understand together,"], ["o le aao lava o Ieova na faia ai lea mea,", "that the hand of the LORD hath done this,"], ["o le Paia o Isaraelu ua na faia lava.", "and the Holy One of Israel hath created it."]]},
  {num:21,words:[["Au mai ia a outou finauga,", "Produce your cause,"], ["ua fetalai mai ai Ieova;", "saith the LORD;"], ["laulau mai ia a outou upu e finau malosi ai,", "bring forth your strong reasons,"], ["ua fetalai mai ai le Tupu o Iakopo.", "saith the King of Jacob."]]},
  {num:22,words:[["Se'i latou laulau mai,", "Let them bring them forth,"], ["ma latou faaali mai ia i tatou mea e tutupu;", "and shew us what shall happen:"], ["ia latou faaali mai mea muamua,", "let them shew the former things,"], ["po o a ia mea;", "what they be,"], ["ona tatou mafaufau ai lea,", "that we may consider them,"], ["ma tatou iloa le iuga o na mea;", "and know the latter end of them;"], ["pe faailoa mai e i latou mea e oo mai.", "or declare us things for to come."]]},
  {num:23,words:[["Faaali mai ia o mea e tutupu amuli,", "Shew the things that are to come hereafter,"], ["ina ia matou iloa o atua lava outou;", "that we may know that ye are gods:"], ["ia outou faia lava se mea lelei,", "yea, do good,"], ["pe fai se mea leaga,", "or do evil,"], ["ina ia matou fevaavaaiai,", "that we may be dismayed,"], ["ma tatou iloa faatasi.", "and behold it together."]]},
  {num:24,words:[["Faauta,", "Behold,"], ["e sili se mea ua leai ia te outou,", "ye are of nothing,"], ["e sili foi le mea ua leai i la outou galuega;", "and your work of nought:"], ["e inosia le na te filifili ia te outou.", "an abomination is he that chooseth you."]]},
  {num:25,words:[["Ua ou faaosoina le tasi mai le itu i matu,", "I have raised up one from the north,"], ["e sau foi o ia;", "and he shall come:"], ["o le mea e alu ae ai le la na te valaau ai i lo'u igoa;", "from the rising of the sun shall he call upon my name:"], ["na te sau i alii e pei o le omea,", "and he shall come upon princes as upon morter,"], ["e pei o le fai ipu omea foi ona soli i le omea.", "and as the potter treadeth clay."]]},
  {num:26,words:[["O ai ea ua na faaali mai talu le amataga,", "Who hath declared from the beginning,"], ["ina ia tatou iloa? mai anamua foi,", "that we may know? and beforetime, that we may say,"], ["ina ia tatou faapea ane,", "He is righteous? yea,"], ["Ua tonu. E moni,", "there is none that sheweth,"], ["sa leai se na faaali mai;", "yea,"], ["sa leai lava se na faailoa mai;", "there is none that declareth, yea,"], ["sa leai lava se na faalogo i a outou upu.", "there is none that heareth your words."]]},
  {num:27,words:[["Na a'u muai fai atu ia Siona,", "The first shall say to Zion,"], ["Faauta,", "Behold,"], ["faauta ia te i latou;", "behold them:"], ["na a'u avatua foi ia Ierusalema le na te aumaia le tala lelei.", "and I will give to Jerusalem one that bringeth good tidings."]]},
  {num:28,words:[["Na ou vaai,", "For I beheld,"], ["a e leai se tagata;", "and there was no man;"], ["o i latou nei lava,", "even among them, and there was no counsellor,"], ["a e leai se faaali mai;", "that,"], ["na a'u fesili atu ia te i latou,", "when I asked of them,"], ["a ua latou le mafai ona tali mai.", "could answer a word."]]},
  {num:29,words:[["Faauta,", "Behold,"], ["o mea le aoga i latou uma;", "they are all vanity;"], ["o a latou mea e fai ua matuā leai lava ia;", "their works are nothing:"], ["o le matagi ma le mea faatauvaa a latou tupua uamea.", "their molten images are wind and confusion."]]},
];
renderVerseSet(isa_ch_41_Verses, 'isa-ch41-verses');

var isa_ch_42_Verses = [
  {num:1,words:[["Faauta i la'u auauna,", "Behold my servant,"], ["ou te taofia o ia i luga;", "whom I uphold;"], ["o le na a'u filifilia ua fiafia i ai lo'u loto;", "mine elect, in whom my soul delighteth;"], ["ua ou tuuina atu lo'u Agaga i ona luga;", "I have put my spirit upon him:"], ["na te avatua le faamasinoga mo nuu ese.", "he shall bring forth judgment to the Gentiles."]]},
  {num:2,words:[["Na te le alaga,", "He shall not cry,"], ["na te le leo tele,", "nor lift up,"], ["e le lagona foi lona leo i le ala.", "nor cause his voice to be heard in the street."]]},
  {num:3,words:[["O le u gapēpē na te le gausia;", "A bruised reed shall he not break,"], ["o le vavae ua mu itiiti na te le tineia;", "and the smoking flax shall he not quench:"], ["o le faamaoni na te avatu ai le faamasinoga.", "he shall bring forth judgment unto truth."]]},
  {num:4,words:[["E le mu itiiti o ia,", "He shall not fail nor be discouraged,"], ["e le gapēpē foi o ia, seia na faatuina le faamasinoga i le lalolagi;", "till he have set judgment in the earth:"], ["e faatalitali foi nuu tu matafaga i lana tulafono.", "and the isles shall wait for his law."]]},
  {num:5,words:[["O loo faapea ona fetalai mai o le Atua o Ieova,", "Thus saith God the LORD,"], ["o le na faia le lagi,", "he that created the heavens,"], ["ma na faamafolafolaina ai;", "and stretched them out; he that spread forth the earth,"], ["o le na fofola le lalolagi ma mea e tutupu mai ai;", "and that which cometh out of it;"], ["o le ua foai le mānava i nuu o i ai,", "he that giveth breath unto the people upon it,"], ["ma le agaga i e o savavali i ai.", "and spirit to them that walk therein:"]]},
  {num:6,words:[["O a'u o Ieova,", "I the LORD have called thee in righteousness,"], ["na ou valaauina oe i le amiotonu;", "and will hold thine hand,"], ["ou te taofimauina lou lima, ma a'u leoleo ia te oe,", "and will keep thee,"], ["ou te avatua foi oe e fai ma feagaiga a le nuu,", "and give thee for a covenant of the people,"], ["o le malamalama o nuu ese;", "for a light of the Gentiles;"]]},
  {num:7,words:[["e faapupula i mata o e tauaso,", "To open the blind eyes,"], ["e aumaina i fafo nai le fale puipui le ua fusifusia,", "to bring out the prisoners from the prison,"], ["atoa ma e ua nonofo i le pogisa ia aumaia i latou nai le fale ua taofiina ai.", "and them that sit in darkness out of the prison house."]]},
  {num:8,words:[["O a'u o Ieova,", "I am the LORD:"], ["o lo'u igoa lea;", "that is my name:"], ["o lo'u mamalu foi ou te le avatua lea i se tasi,", "and my glory will I not give to another,"], ["ma lo'u viiga ou te le avatua i tupua ua ta.", "neither my praise to graven images."]]},
  {num:9,words:[["O mea muamua, faauta,", "Behold,"], ["ua oo mai ia;", "the former things are come to pass,"], ["o mea fou foi o loo ou te ta'uina atu;", "and new things do I declare:"], ["ua ou faailoa atu ia te outou, a o lei tutupu mai.", "before they spring forth I tell you of them."]]},
  {num:10,words:[["Pepese ia Ieova i le pese fou,", "Sing unto the LORD a new song,"], ["o lona viiga mai le tuluiga o le lalolagi,", "and his praise from the end of the earth,"], ["outou o e ō ifo i le sami,", "ye that go down to the sea,"], ["atoa ma e o tumu ai;", "and all that is therein;"], ["outou nuu tu matafaga,", "the isles,"], ["ma e o nonofo ai.", "and the inhabitants thereof."]]},
  {num:11,words:[["E leo tele mai le vao ma ona aai,", "Let the wilderness and the cities thereof lift up their voice,"], ["o faoa aai e nofo ai Kitara;", "the villages that Kedar doth inhabit:"], ["e alalaga e o nonofo i le papa;", "let the inhabitants of the rock sing,"], ["latou te faataio mai tumutumu o mauga.", "let them shout from the top of the mountains."]]},
  {num:12,words:[["Latou te avatu le faaneeneega ia Ieova,", "Let them give glory unto the LORD,"], ["ma latou ta'u atu lona viiga i nuu tu matafaga.", "and declare his praise in the islands."]]},
  {num:13,words:[["E afio atu Ieova pei se toa,", "The LORD shall go forth as a mighty man,"], ["e pei o le tagata tau na te faatupuina lona maelega;", "he shall stir up jealousy like a man of war:"], ["e alaga o ia,", "he shall cry, yea,"], ["e ū'ū'ū,", "roar;"], ["na te manumalo i e ua ita ia te ia.", "he shall prevail against his enemies."]]},
  {num:14,words:[["Ua leva lo'u faalologo;", "I have long time holden my peace;"], ["ua ou le gagana,", "I have been still,"], ["ua ou onosai;", "and refrained myself:"], ["ou te uio e pei o le fafine ua faatiga;", "now will I cry like a travailing woman;"], ["ou te gaegae ma ou mapusela faatasi.", "I will destroy and devour at once."]]},
  {num:15,words:[["E moana ia te au atu mauga ma mauga;", "I will make waste mountains and hills,"], ["e mamago ia te au o latou laau 'aina uma lava;", "and dry up all their herbs;"], ["ou te liua vaitafe ma nuu tuloto;", "and I will make the rivers islands,"], ["ou te faapa'umatuina vailepa.", "and I will dry up the pools."]]},
  {num:16,words:[["Ou te ta'ita'iina e ua tauaso i le ala sa latou le iloa;", "And I will bring the blind by a way that they knew not;"], ["ou te aumaia i latou i magaala sa latou le iloa;", "I will lead them in paths that they have not known:"], ["ou te liua le pouliuli i le malamalama i o latou luma, ma ala piopio e fai ma ala sa'o;", "I will make darkness light before them,"], ["o mea lava ia ou te faia ia te i latou,", "and crooked things straight. These things will I do unto them,"], ["ou te le lafoaiina foi i latou.", "and not forsake them."]]},
  {num:17,words:[["Ua liutuaina i latou,", "They shall be turned back,"], ["ua matuā mamā e ua faatuatua i tupua ua ta,", "they shall be greatly ashamed,"], ["o e ua fai ane i tupua uamea,", "that trust in graven images, that say to the molten images,"], ["O matou atua lava outou.", "Ye are our gods."]]},
  {num:18,words:[["Outou o e tutuli,", "Hear,"], ["ina faalogo mai ia;", "ye deaf;"], ["ma outou e ua tauaso,", "and look, ye blind,"], ["ina vaavaai ia ina ia iloa.", "that ye may see."]]},
  {num:19,words:[["O ai ea ua tauaso,", "Who is blind, but my servant? or deaf,"], ["ua na o la'u auauna? pe tutuli e pei o le sāvali na tuuina e a'u? o ai ea ua tauaso e pei o le ua atoatoa ona lelei? pe tauaso e pei o le auauna a Ieova?", "as my messenger that I sent? who is blind as he that is perfect, and blind as the LORD'S servant?"]]},
  {num:20,words:[["Ua e vaaia mea e tele,", "Seeing many things,"], ["a ua e le anaana i ai;", "but thou observest not;"], ["o loo pūpū taliga,", "opening the ears,"], ["a e le faalogo.", "but he heareth not."]]},
  {num:21,words:[["Ua finagalo mălie Ieova ona o lana amiotonu;", "The LORD is well pleased for his righteousness' sake;"], ["na te ta'uleleia le tulafono,", "he will magnify the law,"], ["ma faamamaluina ai.", "and make it honourable."]]},
  {num:22,words:[["A o i latou nei o le nuu ua vetea ma ua faoa a latou mea;", "But this is a people robbed and spoiled;"], ["ua maileia i latou uma i lua,", "they are all of them snared in holes,"], ["ua lilo foi i latou i fale puipui;", "and they are hid in prison houses:"], ["ua fai ma vete i latou,", "they are for a prey,"], ["a e leai se laveai;", "and none delivereth;"], ["ua fai foi ma e ua faoa a latou mea,", "for a spoil,"], ["a e leai se fai ane,", "and none saith,"], ["Ina toe tuu mai ai.", "Restore."]]},
  {num:23,words:[["O ai ea so outou e uai mai ona taliga i lenei mea? ma faasaga mai, ma faalogo mai i mea amuli?", "Who among you will give ear to this? who will hearken and hear for the time to come?"]]},
  {num:24,words:[["O ai ea na tuuina atu Iakopo ia faoa ana mea,", "Who gave Jacob for a spoil,"], ["o Isaraelu foi i e vete mea? E le o Ieova ea? o ia na tatou agasala i ai;", "and Israel to the robbers? did not the LORD,"], ["a e le mafafai i latou ona savavali i ona ala;", "he against whom we have sinned? for they would not walk in his ways,"], ["ua latou le faalogo foi i lana tulafono.", "neither were they obedient unto his law."]]},
  {num:25,words:[["Ona ia sasaa mai lea ia te ia o le tele o lona toasa,", "Therefore he hath poured upon him the fury of his anger,"], ["ma le mamafa o le taua;", "and the strength of battle:"], ["ua faamu faataaliolioina ai o ia,", "and it hath set him on fire round about,"], ["a e le iloa e ia;", "yet he knew not;"], ["ua mu ai o ia,", "and it burned him,"], ["a e le mafaufau i ai.", "yet he laid it not to heart."]]},
];
renderVerseSet(isa_ch_42_Verses, 'isa-ch42-verses');

var isa_ch_43_Verses = [
  {num:1,words:[["A o lenei,", "But now thus saith the LORD that created thee,"], ["o loo faapea ona fetalai mai o Ieova,", "O Jacob,"], ["o le na faia oe, Iakopo e,", "and he that formed thee,"], ["ma na faia oe,", "O Israel,"], ["Isaraelu e;", "Fear not:"], ["aua le fefe, auā ua ou faatauina oe,", "for I have redeemed thee,"], ["ua ou valaauina oe i lou lava igoa;", "I have called thee by thy name;"], ["e faia oe mo'u.", "thou art mine."]]},
  {num:2,words:[["A ē sopoia atu le vai,", "When thou passest through the waters,"], ["ou te ia te oe;", "I will be with thee;"], ["a ē sopoia atu vaitafe,", "and through the rivers,"], ["e le lofia ai oe;", "they shall not overflow thee:"], ["a ē savali i totonu o le afi,", "when thou walkest through the fire,"], ["e le mu ai oe;", "thou shalt not be burned;"], ["e le susunuina foi oe i le mumū o le afi.", "neither shall the flame kindle upon thee."]]},
  {num:3,words:[["Auā o a'u o Ieova lou Atua,", "For I am the LORD thy God,"], ["o le Paia o Isaraelu,", "the Holy One of Israel,"], ["lou Faaola;", "thy Saviour:"], ["na a'u avatua Aikupito e fai mou togiola,", "I gave Egypt for thy ransom,"], ["o Aitiope ma Sepa e sui a'i oe.", "Ethiopia and Seba for thee."]]},
  {num:4,words:[["Auā na faapelepeleina oe e a'u,", "Since thou wast precious in my sight,"], ["ua ou faamamaluina ai oe;", "thou hast been honourable,"], ["auā foi na ou alofa ia te oe,", "and I have loved thee:"], ["o le mea lea ou te avatu ai tagata e sui a'i oe,", "therefore will I give men for thee,"], ["ma nuu e sui a'i lou ola.", "and people for thy life."]]},
  {num:5,words:[["Aua le fefe,", "Fear not:"], ["auā ou te ia te oe;", "for I am with thee:"], ["ou te aumaia lau fanau mai sasae;", "I will bring thy seed from the east,"], ["ou te faapotopotoina foi outou mai sisifo.", "and gather thee from the west;"]]},
  {num:6,words:[["Ou te fai atu i le itu i matu,", "I will say to the north,"], ["tuu mai ia;", "Give up;"], ["ma le itu i toga,", "and to the south,"], ["Aua le toafia;", "Keep not back:"], ["au mai ia o'u atalii ai mea mamao,", "bring my sons from far,"], ["ma o'u afafine ai le tuluiga o le lalolagi;", "and my daughters from the ends of the earth;"]]},
  {num:7,words:[["o i latou uma ua igoa i lo'u igoa,", "Even every one that is called by my name: for I have created him for my glory,"], ["na ou faia ia viia ai a'u;", "I have formed him;"], ["na a'u gaosia ma ou faia lava i latou.", "yea, I have made him."]]},
  {num:8,words:[["Ta'ita'i mai ia le nuu tauaso, ua i ai o latou mata;", "Bring forth the blind people that have eyes,"], ["ma e tutuli, ua i ai o latou taliga.", "and the deaf that have ears."]]},
  {num:9,words:[["Ia faapotopotoina nuu ese uma faatasi,", "Let all the nations be gathered together,"], ["ma ia aofia nuu uma. O ai ea so latou na te faaalia mai lenei mea,", "and let the people be assembled:"], ["pe faailoa mai ia te i tatou mea muamua? Se'i latou tuu mai ia a latou molimau,", "who among them can declare this,"], ["ina ia ta'uamiotonuina i latou;", "and shew us former things? let them bring forth their witnesses, that they may be justified:"], ["pe faalogo mai i latou,", "or let them hear,"], ["ma latou fai mai,", "and say,"], ["E moni.", "It is truth."]]},
  {num:10,words:[["Ua fetalai mai Ieova,", "Ye are my witnesses,"], ["O outou o a'u molimau, ma la'u auauna o le na a'u filifilia;", "saith the LORD,"], ["ina ia outou iloa,", "and my servant whom I have chosen:"], ["ma ia outou faatuatua mai ia te au,", "that ye may know and believe me,"], ["ma ia outou lagona,", "and understand that I am he:"], ["o a'u lava o ia; e leai se atua na gaosia e muamua ia te au;", "before me there was no God formed,"], ["e leai foi se tasi e mulimuli ia te au.", "neither shall there be after me."]]},
  {num:11,words:[["O a'u o a'u lava o Ieova;", "I, even I,"], ["a e leai se faaola ua na.", "am the LORD; and beside me there is no saviour."]]},
  {num:12,words:[["O a'u lava,", "I have declared,"], ["na ou faaali atu,", "and have saved,"], ["ma ou faaolaina,", "and I have shewed,"], ["ma ou faailoa atu, sa leai foi ia te outou se atua ese;", "when there was no strange god among you:"], ["o outou foi o a'u molimau,", "therefore ye are my witnesses,"], ["o a'u lava o le Atua,", "saith the LORD,"], ["ua fetalai mai ai Ieova.", "that I am God."]]},
  {num:13,words:[["A o leai lava ni aso,", "Yea,"], ["o a'u lava o ia;", "before the day was I am he;"], ["e leai foi se na te laveaiina nai lo'u lima;", "and there is none that can deliver out of my hand:"], ["ou te faia,", "I will work,"], ["a o ai se na te faaleaogaina?", "and who shall let it?"]]},
  {num:14,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["o le na faatauina outou, o le Paia o Isaraelu;", "your redeemer,"], ["ona o outou ua ou aauina atu nisi i Papelonia,", "the Holy One of Israel;"], ["ma a'u aveina ifo le solaaga,", "For your sake I have sent to Babylon,"], ["o i latou uma,", "and have brought down all their nobles,"], ["lava, atoa ma Kaletaia,", "and the Chaldeans,"], ["o loo alalaga i latou i vaa.", "whose cry is in the ships."]]},
  {num:15,words:[["O a'u o Ieova,", "I am the LORD,"], ["o lo outou Alii Paia;", "your Holy One,"], ["o le na faia Isaraelu,", "the creator of Israel,"], ["o lo outou Tupu.", "your King."]]},
  {num:16,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["o le na faia le ala i le sami,", "which maketh a way in the sea,"], ["ma le magaala i le sami sousou tele.", "and a path in the mighty waters;"]]},
  {num:17,words:[["O lē aumaia le kariota ma le solofanua,", "Which bringeth forth the chariot and horse,"], ["o 'au,", "the army and the power;"], ["ma e fitafita; ua latou taooto faatasi;", "they shall lie down together,"], ["ua latou le toe tulai,", "they shall not rise:"], ["ua tineia i latou,", "they are extinct,"], ["ua pepē e pei o le vavae o le lamepa.", "they are quenched as tow."]]},
  {num:18,words:[["Aua tou te manatua mea na muamua,", "Remember ye not the former things,"], ["aua foi le mafaufau i mea anamua.", "neither consider the things of old."]]},
  {num:19,words:[["Faauta,", "Behold,"], ["ou te faia se mea e faatoa iloa,", "I will do a new thing;"], ["e tupu ae nei lava; tou te le iloa ea? E moni,", "now it shall spring forth;"], ["ou te faia se ala i le vao lafulafua,", "shall ye not know it? I will even make a way in the wilderness,"], ["ma vaitafe i le nuu naumati.", "and rivers in the desert."]]},
  {num:20,words:[["E viia a'u e manu o le vao,", "The beast of the field shall honour me,"], ["o luko ma iaena;", "the dragons and the owls:"], ["auā ou te avatu vai i le vao lafulafua,", "because I give waters in the wilderness, and rivers in the desert,"], ["o vaitafe i le nuu naumati;", "to give drink to my people,"], ["e feinu ai lo'u nuu ua ou filifilia.", "my chosen."]]},
  {num:21,words:[["O le nuu lenei na a'u faia mo a'u;", "This people have I formed for myself;"], ["latou te ta'uatua lo'u viiga.", "they shall shew forth my praise."]]},
  {num:22,words:[["A ua e le valaau mai ia te au,", "But thou hast not called upon me,"], ["o oe Iakopo e;", "O Jacob;"], ["auā ua e musu ia te au,", "but thou hast been weary of me,"], ["o oe Isaraelu e.", "O Israel."]]},
  {num:23,words:[["Ua e le aumaia ia te au o mamoe o au taulaga mu;", "Thou hast not brought me the small cattle of thy burnt offerings;"], ["ua e le viia foi a'u i au taulaga;", "neither hast thou honoured me with thy sacrifices. I have not caused thee to serve with an offering,"], ["ua le mafatia oe e a'u i taulaga i mea e 'ai ua ou le faatigaina foi oe i le pulu lipano.", "nor wearied thee with incense."]]},
  {num:24,words:[["Ua e le faatau mo a'u ni kani i tupe;", "Thou hast bought me no sweet cane with money,"], ["ua le au mai ia te au le ga'o o au taulaga ia a'u mălie ai;", "neither hast thou filled me with the fat of thy sacrifices:"], ["a e peitai ua mafatia a'u e oe i au agasala,", "but thou hast made me to serve with thy sins,"], ["ua faatigaina a'u i au amio leaga.", "thou hast wearied me with thine iniquities."]]},
  {num:25,words:[["O a'u,", "I,"], ["o a'u lava lē sōloiesea au solitulafoni,", "even I,"], ["ona o a'u lava;", "am he that blotteth out thy transgressions for mine own sake,"], ["o au agasala foi ou te le manatua ia.", "and will not remember thy sins."]]},
  {num:26,words:[["Ia faamanatu mai ia te au,", "Put me in remembrance:"], ["ia ta fefaamasinoai;", "let us plead together:"], ["ta'u mai ia oe,", "declare thou,"], ["ina ia ta'uamiotonuina ai oe.", "that thou mayest be justified."]]},
  {num:27,words:[["O lou tamā e sili, ua agasala ia;", "Thy first father hath sinned,"], ["ma ou a'oa'o ua latou foua a'u;", "and thy teachers have transgressed against me."]]},
  {num:28,words:[["o le mea lea ua gafua ai ia te au alii o le malumalu;", "Therefore I have profaned the princes of the sanctuary,"], ["ua ou tuuina foi Iakopo ia faafanoina,", "and have given Jacob to the curse,"], ["ma Isaraelu ia faalumaina.", "and Israel to reproaches."]]},
];
renderVerseSet(isa_ch_43_Verses, 'isa-ch43-verses');

var isa_ch_44_Verses = [
  {num:1,words:[["A o lenei,", "Yet now hear,"], ["faalogo mai ia Iakopo e la'u auauna,", "O Jacob my servant; and Israel,"], ["o Isaraelu foi na ou filifilia.", "whom I have chosen:"]]},
  {num:2,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD that made thee, and formed thee from the womb,"], ["o le na faia oe,", "which will help thee;"], ["ma na faatupuina oe i le manava;", "Fear not,"], ["o lē fesoasoani ia te oe;", "O Jacob, my servant;"], ["Aua e te fefe la'u auauna Iakopo e,", "and thou, Jesurun,"], ["o Iesuruna foi na ou filifilia.", "whom I have chosen."]]},
  {num:3,words:[["Auā ou te liligi atu le vai i le nuu naumati,", "For I will pour water upon him that is thirsty,"], ["ma vaitafe i le eleele matutu;", "and floods upon the dry ground:"], ["ou te liligi atu lo'u Agaga i luga o lau fanau,", "I will pour my spirit upon thy seed,"], ["ma la'u faamanuia i luga o e tutupu mai ia te oe.", "and my blessing upon thine offspring:"]]},
  {num:4,words:[["E tutupu ae i latou i totonu o le mutia,", "And they shall spring up as among the grass,"], ["e pei o garava i auvai o vaitafe.", "as willows by the water courses."]]},
  {num:5,words:[["E fai mai le tasi,", "One shall say,"], ["O a'u o le tagata o Ieova;", "I am the LORD'S;"], ["e ta'u atu le tasi i le igoa o Iakopo; a e tusi le tasi i lona lima,", "and another shall call himself by the name of Jacob;"], ["Mo Ieova;", "and another shall subscribe with his hand unto the LORD,"], ["e faaigoa foi o ia e ia i le igoa o Isaraelu,", "and surname himself by the name of Israel."]]},
  {num:6,words:[["O loo faapea ona fetalai mai o Ieova, o le Tupu o Isaraelu,", "Thus saith the LORD the King of Israel,"], ["o le na faatauina foi o ia,", "and his redeemer the LORD of hosts;"], ["o Ieova o 'au; o a'u lē muamua,", "I am the first,"], ["o a'u foi lē mulimuli;", "and I am the last;"], ["a e leai se atua, ua na o a'u lava.", "and beside me there is no God."]]},
  {num:7,words:[["O ai ea foi e pei o a'u ona valaau,", "And who, as I,"], ["ma faaali atu,", "shall call,"], ["ma sauni mai mo a'u,", "and shall declare it, and set it in order for me,"], ["talu ona ou tofia le nuu mai le vavau? ia latou faaali atu ia i latou mea o le a tutupu,", "since I appointed the ancient people? and the things that are coming,"], ["ma mea e oo mai.", "and shall come, let them shew unto them."]]},
  {num:8,words:[["Aua le fefefe outou;", "Fear ye not,"], ["aua foi le matatau;", "neither be afraid:"], ["pe na a'u le faailoa atu ea ia te oe anamua, ma a'u ta'uina atu ia te oe? o a'u molimau lava outou;", "have not I told thee from that time,"], ["pe ai ea se atua,", "and have declared it? ye are even my witnesses. Is there a God beside me? yea,"], ["ua na o a'u lava? Ua leai lava se papa,", "there is no God;"], ["ou te le iloa se tasi .", "I know not any."]]},
  {num:9,words:[["O e fai tupua ua ta,", "They that make a graven image are all of them vanity;"], ["e faatauvaa i latou uma, ma a latou mea faafiafia,", "and their delectable things shall not profit;"], ["ua le aoga lava ia;", "and they are their own witnesses;"], ["o i latou lava e molimau ia i latou;", "they see not,"], ["latou te le vaai, latou te le iloa foi,", "nor know;"], ["ina ia latou mamā.", "that they may be ashamed."]]},
  {num:10,words:[["O ai ea ua na faia se atua, ma na gaosia se tupua uamea,", "Who hath formed a god,"], ["e leai lava sona aoga?", "or molten a graven image that is profitable for nothing?"]]},
  {num:11,words:[["Faauta e mamā i latou uma o e faatasi ma ia;", "Behold,"], ["o tufuga foi,", "all his fellows shall be ashamed:"], ["o tagata lava i latou;", "and the workmen,"], ["ia faapotopoto i latou uma;", "they are of men: let them all be gathered together,"], ["ia latou tutū i luga;", "let them stand up;"], ["e matatau i latou,", "yet they shall fear,"], ["e mamā faatasi.", "and they shall be ashamed together."]]},
  {num:12,words:[["O le tufuga fai mea uamea na te faia se to'i;", "The smith with the tongs both worketh in the coals,"], ["na te gaosia i le malala;", "and fashioneth it with hammers,"], ["na te faia i samala;", "and worketh it with the strength of his arms:"], ["na te galue i ai i lona lima malosi;", "yea,"], ["ua fia 'ai foi o ia,", "he is hungry,"], ["ona leai lea o sona malosi,", "and his strength faileth:"], ["ua le inu ia i se vai,", "he drinketh no water,"], ["ona vaivai ai lea o ia.", "and is faint."]]},
  {num:13,words:[["O le tufuga na te faataotoina le fua,", "The carpenter stretcheth out his rule;"], ["na te tusia i le peni,", "he marketh it out with a line;"], ["na te faia i tofi,", "he fitteth it with planes,"], ["na te tusia i le fua faataaliolio,", "and he marketh it out with the compass,"], ["na te faia e pei o le tino o le tagata,", "and maketh it after the figure of a man,"], ["e tusa ma le matagofie o le tagata,", "according to the beauty of a man;"], ["ina ia nofo i le fale.", "that it may remain in the house."]]},
  {num:14,words:[["Ua ia tuu i lalo arasi mo ia,", "He heweth him down cedars,"], ["ua au mai e ia o le tiresa ma le aluna,", "and taketh the cypress and the oak,"], ["na te faamalosia foi mo ia i laau o le vao;", "which he strengtheneth for himself among the trees of the forest:"], ["ua ia totōina le orene,", "he planteth an ash,"], ["ona tupu tele ai lea i le uaga;", "and the rain doth nourish it."]]},
  {num:15,words:[["ona faia lea e le tagata ma fafie,", "Then shall it be for a man to burn: for he will take thereof,"], ["ua ia ave foi nisi mea e mumulu a'i o ia;", "and warm himself;"], ["na te faamuina lava ma tao a'i areto;", "yea, he kindleth it,"], ["na te faia lava se atua,", "and baketh bread;"], ["ma ifo atu i ai;", "yea, he maketh a god,"], ["na te fai a'i se tupua ua ta,", "and worshippeth it;"], ["ma ifo faō i ai.", "he maketh it a graven image, and falleth down thereto."]]},
  {num:16,words:[["O le tasi ona vaegā laau ua ia susunu ai i le afi;", "He burneth part thereof in the fire;"], ["o le tasi ona vaega ua ia 'ai ai le tufaaga;", "with part thereof he eateth flesh;"], ["na te tuuna le mea e tunu,", "he roasteth roast, and is satisfied:"], ["ua ma'ona foi o ia;", "yea,"], ["ua mumulu ai lava o ia,", "he warmeth himself,"], ["ona faapea ane lea o ia,", "and saith, Aha,"], ["Ena! ua ou mafanafana,", "I am warm,"], ["ua ou iloa le afi.", "I have seen the fire:"]]},
  {num:17,words:[["O le mea foi ua totoe na te fai a'i se atua,", "And the residue thereof he maketh a god,"], ["o lana tupua ua ta;", "even his graven image:"], ["ua ia ifo faō i ai,", "he falleth down unto it,"], ["ma tapuai atu i ai;", "and worshippeth it,"], ["ua ia tatalo foi i ai,", "and prayeth unto it,"], ["o loo faapea atu,", "and saith,"], ["Ia e laveai mai ia te au,", "Deliver me;"], ["auā o lo'u atua lava oe.", "for thou art my god."]]},
  {num:18,words:[["Ua latou le iloa,", "They have not known nor understood:"], ["ua latou le lagona;", "for he hath shut their eyes,"], ["auā ua ufitia o latou mata ia le vaai,", "that they cannot see; and their hearts,"], ["ma o latou loto ina ia le mafaufau.", "that they cannot understand."]]},
  {num:19,words:[["Ua le mafaufau o ia,", "And none considereth in his heart,"], ["ua leai se poto,", "neither is there knowledge nor understanding to say,"], ["ua leai se faautauta se'i faapea ane ai o ia,", "I have burned part of it in the fire;"], ["O le tasi ona vaegā laau ua ou susunuina lea i le afi,", "yea,"], ["ua ou taoa foi le areto i ona malala ola;", "also I have baked bread upon the coals thereof;"], ["ua ou tunua le tufaaga,", "I have roasted flesh,"], ["ma a'u 'aina;", "and eaten it:"], ["ou te faia ea le mea ua totoe ma mea e inosia? ou te ifo faō ea i le ogalaau?", "and shall I make the residue thereof an abomination? shall I fall down to the stock of a tree?"]]},
  {num:20,words:[["Ua fai mana mea e 'ai le lefulefu;", "He feedeth on ashes:"], ["o le loto pelogia ua faaliliueseina ai o ia;", "a deceived heart hath turned him aside,"], ["o lea na te le malaveaiina ai o ia ia te ia,", "that he cannot deliver his soul,"], ["na te le fai ane foi,", "nor say,"], ["E le o le pepelo ea ua i lo'u lima taumatau?", "Is there not a lie in my right hand?"]]},
  {num:21,words:[["Ia e manatu i nei mea Iakopo e;", "Remember these,"], ["o Isaraelu foi,", "O Jacob and Israel;"], ["auā o la'u auauna oe;", "for thou art my servant:"], ["ua ou faia oe,", "I have formed thee;"], ["o la'u auauna oe;", "thou art my servant:"], ["Isaraelu e,", "O Israel,"], ["e le galo oe ia te au.", "thou shalt not be forgotten of me."]]},
  {num:22,words:[["Ua ou sōloia ou solitulafono e pei o se ao uliuli,", "I have blotted out, as a thick cloud,"], ["ma au agasala e pei o se ao;", "thy transgressions, and,"], ["foi mai ia ia te au,", "as a cloud, thy sins:"], ["auā ua ou faatauina oe.", "return unto me; for I have redeemed thee."]]},
  {num:23,words:[["Ia pese oe le lagi e,", "Sing,"], ["auā ua faia lea mea e Ieova;", "O ye heavens; for the LORD hath done it:"], ["ia alalaga outou o mea maulalalo i le lalolagi;", "shout,"], ["ia leo tetele outou mauga e,", "ye lower parts of the earth: break forth into singing,"], ["ma alalaga fiafia;", "ye mountains,"], ["o oe le vao ma laau uma o i ai;", "O forest,"], ["auā ua faatauina Iakopo e Ieova,", "and every tree therein: for the LORD hath redeemed Jacob,"], ["na te faatupuina foi lona lava viiga ia Isaraelu.", "and glorified himself in Israel."]]},
  {num:24,words:[["O loo faapea ona fetalai mai o Ieova le na faatau ia te oe,", "Thus saith the LORD,"], ["o le na faatupuina foi oe i le manava;", "thy redeemer,"], ["o a'u o Ieova le na faia mea uma;", "and he that formed thee from the womb, I am the LORD that maketh all things;"], ["o lē faamafolafola le lagi na o a'u lava;", "that stretcheth forth the heavens alone;"], ["o a'u lava o lē fofolaina le lalolagi;", "that spreadeth abroad the earth by myself;"]]},
  {num:25,words:[["o le na te faaleaogaina faailoga o e pepelo;", "That frustrateth the tokens of the liars,"], ["na te faavaleleaina o e faataulāitu;", "and maketh diviners mad;"], ["o loo faaliliuina i tua o e popoto,", "that turneth wise men backward,"], ["na te faaleaogaina o latou poto;", "and maketh their knowledge foolish;"]]},
  {num:26,words:[["o loo faamauina le upu a lana auauna,", "That confirmeth the word of his servant,"], ["na te faataunuuina foi le pule a ana sāvali;", "and performeth the counsel of his messengers;"], ["o loo faapea ane i Ierusalema,", "that saith to Jerusalem,"], ["E āina o ia;", "Thou shalt be inhabited;"], ["o loo faapea foi i aai a Iuta,", "and to the cities of Judah,"], ["E faia lava ia;", "Ye shall be built,"], ["ou te faatuina foi ana mea ua faatafunaina;", "and I will raise up the decayed places thereof:"]]},
  {num:27,words:[["o le fai atu i mea loloto,", "That saith to the deep,"], ["Ia faapa'umatuina;", "Be dry,"], ["ou te faamamate foi i ou vaitafe.", "and I will dry up thy rivers:"]]},
  {num:28,words:[["O lē fai atu ia Kuresa,", "That saith of Cyrus,"], ["O lo'u leoleo mamoe o ia;", "He is my shepherd,"], ["na te faataunuuina foi o mea uma ou te loto i ai;", "and shall perform all my pleasure:"], ["o loo fai atu foi i Ierusalema,", "even saying to Jerusalem,"], ["E faia lava oe;", "Thou shalt be built;"], ["o loo fai atu foi i le malumalu,", "and to the temple,"], ["E faavaeina lava oe.", "Thy foundation shall be laid."]]},
];
renderVerseSet(isa_ch_44_Verses, 'isa-ch44-verses');

var isa_ch_45_Verses = [
  {num:1,words:[["O loo faapea ona fetalai mai o Ieova i le ua faauuina e ia,", "Thus saith the LORD to his anointed,"], ["o Kuresa,", "to Cyrus,"], ["o le ua ou taofia lona lima taumatau,", "whose right hand I have holden,"], ["ia faatoilaloina nuu i ona luma,", "to subdue nations before him;"], ["ou te tatalaina foi sulugatiti o tupu;", "and I will loose the loins of kings,"], ["e tatalaina i ona luma o puipui vae lua;", "to open before him the two leaved gates;"], ["e le punitia foi faitotoa.", "and the gates shall not be shut;"]]},
  {num:2,words:[["O a'u lava,", "I will go before thee,"], ["ou te savali atu i ou luma,", "and make the crooked places straight:"], ["ma ou faalauleleiina mea maupuepue; ou te nutininii i puipui 'apa memea;", "I will break in pieces the gates of brass,"], ["ou te gauia foi faamau uamea.", "and cut in sunder the bars of iron:"]]},
  {num:3,words:[["Ou te foai atu foi ia te oe oloa o loo i le pogisa,", "And I will give thee the treasures of darkness,"], ["ma oloa lilo o loo i mea nanā;", "and hidden riches of secret places,"], ["ina ia e iloa o a'u lava o Ieova,", "that thou mayest know that I, the LORD,"], ["o lē valaau i lou lava igoa,", "which call thee by thy name,"], ["o le Atua o Isaraelu.", "am the God of Israel."]]},
  {num:4,words:[["Ona o la'u auauna o Iakopo,", "For Jacob my servant's sake,"], ["ma Isaraelu le na a'u filifilia,", "and Israel mine elect,"], ["o le mea lea ua ou valaauina ai oe i lou lava igoa;", "I have even called thee by thy name:"], ["ua ou ta'ua lou igoa,", "I have surnamed thee,"], ["a o e lei iloa a'u.", "though thou hast not known me."]]},
  {num:5,words:[["O a'u o Ieova,", "I am the LORD,"], ["a e leai lava se tasi;", "and there is none else,"], ["e leai se Atua, na o a'u lava;", "there is no God beside me:"], ["ua ou fusia oe,", "I girded thee,"], ["a o e lei iloa a'u;", "though thou hast not known me:"]]},
  {num:6,words:[["ina ia latou iloa, e afua mai i le mea e alu ae ai le la,", "That they may know from the rising of the sun,"], ["e oo i le mea e alu ifo ai,", "and from the west,"], ["e leai se tasi na o a'u;", "that there is none beside me. I am the LORD,"], ["o a'u o Ieova, a e leai lava se tasi;", "and there is none else."]]},
  {num:7,words:[["o a'u lē faia le malamalama,", "I form the light,"], ["ma faatupuina le pouliuli;", "and create darkness:"], ["o lē faia le manuia, ma faatupuina le mala;", "I make peace,"], ["o a'u o Ieova,", "and create evil:"], ["o lē faia ia mea uma.", "I the LORD do all these things."]]},
  {num:8,words:[["Toulu mai ia,", "Drop down,"], ["o oe le lagi i luga;", "ye heavens,"], ["o ao foi,", "from above,"], ["ia faamaligi mai le amiotonu;", "and let the skies pour down righteousness:"], ["ia faamaga mai le laueleele, ma ia fua mai le olataga ma le amiotonu,", "let the earth open,"], ["ia faatupuina faatasi;", "and let them bring forth salvation,"], ["o a'u o Ieova,", "and let righteousness spring up together;"], ["ua ou faia lea mea.", "I the LORD have created it."]]},
  {num:9,words:[["Oi talofa i le ua finau ma le na faia o ia, o le ta'ega ipu i ta'ega ipu o le eleele.", "Woe unto him that striveth with his Maker! Let the potsherd strive with the potsherds of the earth."], ["Pe fai atu ea le omea i le na te gaosia,", "Shall the clay say to him that fashioneth it,"], ["O le a ea e te faia? pe fai atu lau galuega,", "What makest thou? or thy work,"], ["Ua leai ni ona lima?", "He hath no hands?"]]},
  {num:10,words:[["Oi talofa i le na te fai atu i lona tamā,", "Woe unto him that saith unto his father,"], ["O le a ea ua e fanaua? pe fai atu i le fafine,", "What begettest thou? or to the woman,"], ["O le a ea ua e fanau mai?", "What hast thou brought forth?"]]},
  {num:11,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["le Paia o Isaraelu,", "the Holy One of Israel,"], ["ma le na faia o ia, Fesili mai ia ia te au i mea o le a tutupu,", "and his Maker,"], ["fai mai ia te au i o'u atalii,", "Ask me of things to come concerning my sons,"], ["ma le galuega a o'u lima;", "and concerning the work of my hands command ye me."]]},
  {num:12,words:[["o a'u lava,", "I have made the earth,"], ["na ou faia le lalolagi,", "and created man upon it:"], ["ma a'u faia tagata o i ai;", "I,"], ["o a'u,", "even my hands,"], ["o o'u lava lima na fofola ai le lagi,", "have stretched out the heavens,"], ["ma a'u pule i 'au uma o i ai.", "and all their host have I commanded."]]},
  {num:13,words:[["O a'u lava,", "I have raised him up in righteousness,"], ["ua ou faaosoina mai o ia i le amiotonu; ou te faalauleleia foi ona ala uma;", "and I will direct all his ways:"], ["o ia na te faatuina la'u faiaai,", "he shall build my city,"], ["ma tuuina mai o'u tagata sa tāfea latou te o;", "and he shall let go my captives,"], ["e le ona o le taui, po o se mea alofa,", "not for price nor reward,"], ["ua fetalai mai ai Ieova o 'au.", "saith the LORD of hosts."]]},
  {num:14,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["O le oa o Aikupito,", "The labour of Egypt,"], ["ma mea faatau a Aitiope atoa ma Sepa,", "and merchandise of Ethiopia and of the Sabeans,"], ["o tagata tino eese,", "men of stature,"], ["latou te o ane ia te oe,", "shall come over unto thee,"], ["e fai foi i latou mou tagata;", "and they shall be thine:"], ["latou te mulimuli atu ia te oe,", "they shall come after thee;"], ["latou te o ane ma maea uamea,", "in chains they shall come over,"], ["latou te ifo atu ia te oe,", "and they shall fall down unto thee,"], ["ma latou ole atu ia te oe,", "they shall make supplication unto thee,"], ["e faapea ,", "saying,"], ["Ua na o oe ua i ai le Atua,", "Surely God is in thee;"], ["a e leai se tasi,", "and there is none else,"], ["ua leai se tasi Atua.", "there is no God."]]},
  {num:15,words:[["E moni,", "Verily thou art a God that hidest thyself,"], ["o oe lava le Atua e faaliloina oe e oe, le Atua o Isaraelu,", "O God of Israel,"], ["le Faaola.", "the Saviour."]]},
  {num:16,words:[["Ua mamā i latou,", "They shall be ashamed,"], ["ua masiasi lava o i latou uma;", "and also confounded,"], ["ua latou o faatasi ina ua masiasi,", "all of them:"], ["o tufuga ia o e fai tupua.", "they shall go to confusion together that are makers of idols."]]},
  {num:17,words:[["A e faaolaina Isaraelu e Ieova, o le olataga e faavavau lava;", "But Israel shall be saved in the LORD with an everlasting salvation:"], ["tou te le mamā, tou te le masiasi foi e faavavau faavavau lava.", "ye shall not be ashamed nor confounded world without end."]]},
  {num:18,words:[["Auā o loo faapea ona fetalai mai o Ieova,", "For thus saith the LORD that created the heavens;"], ["o le na faia le lagi; o ia lava o le Atua;", "God himself that formed the earth and made it;"], ["o le tufuga o le na faia le lalolagi;", "he hath established it,"], ["o ia na faatumauina;", "he created it not in vain,"], ["na ia le faia fua,", "he formed it to be inhabited:"], ["na ia faia ina ia āina, o a'u o Ieova,", "I am the LORD;"], ["a e leai se tasi.", "and there is none else."]]},
  {num:19,words:[["Ou te lei tautala faalilolilo i se mea pogisa o le lalolagi;", "I have not spoken in secret,"], ["ou te lei fai atu i le fanau a Iakopo,", "in a dark place of the earth:"], ["Ia outou saili fua mai ia te au;", "I said not unto the seed of Jacob,"], ["o a'u o Ieova,", "Seek ye me in vain:"], ["o lē tautala ma le faamaoni,", "I the LORD speak righteousness,"], ["o lē faaali atu mea tonu.", "I declare things that are right."]]},
  {num:20,words:[["Ia faapotopotoina,", "Assemble yourselves and come;"], ["ma ia o mai outou,", "draw near together,"], ["ia faalatalata faatasi mai lava, o outou e ua sao mai nuu ese;", "ye that are escaped of the nations:"], ["latou te le iloa o e tauave le laau o lo latou tupua ua ta,", "they have no knowledge that set up the wood of their graven image,"], ["ma latou tatalo i le atua na te le mafaia ona faaola.", "and pray unto a god that cannot save."]]},
  {num:21,words:[["Faaali mai ia,", "Tell ye,"], ["ma ia outou faalatalata mai;", "and bring them near;"], ["ia filifili faatasi foi i latou. O ai ea ua na faailoa mai lenei mea mai anamua,", "yea,"], ["ua faaalia mai talu anamua? E le o a'u ea o Ieova? e leai se tasi atua, ua na o a'u lava;", "let them take counsel together:"], ["o le Atua amiotonu,", "who hath declared this from ancient time? who hath told it from that time? have not I the LORD? and there is no God else beside me;"], ["i le ma le Faaola;", "a just God and a Saviour;"], ["e leai se tasi na o a'u.", "there is none beside me."]]},
  {num:22,words:[["Liliu mai ia ia te au,", "Look unto me,"], ["tou te ola ai,", "and be ye saved,"], ["o outou tuluiga uma o le lalolagi;", "all the ends of the earth:"], ["auā o a'u o le Atua,", "for I am God,"], ["a e leai lava se tasi.", "and there is none else."]]},
  {num:23,words:[["Ua ou tauto ia te au lava,", "I have sworn by myself,"], ["ua mavae atu le upu i lo'u gutu e faamaoni,", "the word is gone out of my mouth in righteousness,"], ["e le toe foi mai lava,", "and shall not return,"], ["E tootuli mai ia te au o tulivae uma lava,", "That unto me every knee shall bow,"], ["e tauto mai laulaufaiva uma lava;", "every tongue shall swear."]]},
  {num:24,words:[["e fai mai se tasi ,", "Surely,"], ["Ua na o Ieova ua ou maua ai le amiotonu ma le malosi;", "shall one say,"], ["e sau o ia ia te ia;", "in the LORD have I righteousness and strength: even to him shall men come;"], ["a e mamā i latou uma o e ua ita ia te ia.", "and all that are incensed against him shall be ashamed."]]},
  {num:25,words:[["O Ieova e ta'uamiotonuina ai ma mitamita ai le fanau uma a Isaraelu.", "In the LORD shall all the seed of Israel be justified, and shall glory."]]},
];
renderVerseSet(isa_ch_45_Verses, 'isa-ch45-verses');

var isa_ch_46_Verses = [
  {num:1,words:[["Ua punou Pele,", "Bel boweth down,"], ["ua ifo Nepo,", "Nebo stoopeth,"], ["ua i manu ma manu ave avega a latou tupua;", "their idols were upon the beasts, and upon the cattle:"], ["o a outou avega ua faaeetia ia,", "your carriages were heavy loaden;"], ["o le avega lea i manu ua tigaina.", "they are a burden to the weary beast."]]},
  {num:2,words:[["Ua latou ifo,", "They stoop,"], ["ua punonou faatasi,", "they bow down together;"], ["ua latou le mafai ona laveaiina o le avega; a o i latou lava,", "they could not deliver the burden,"], ["ua latou o i le tafeaga.", "but themselves are gone into captivity."]]},
  {num:3,words:[["Faalogo mai ia ia te au,", "Hearken unto me,"], ["outou le aiga o Iakopo,", "O house of Jacob,"], ["ma outou uma o e ua totoe o le aiga o Isaraelu,", "and all the remnant of the house of Israel,"], ["o e ua tauave e a'u talu ina fanau mai i le manava;", "which are borne by me from the belly,"], ["ua siitia e a'u talu ina fanau mai.", "which are carried from the womb:"]]},
  {num:4,words:[["E oo ina e toeaina,", "And even to your old age I am he;"], ["o a'u lava o ia, e oo foi ina ulusina,", "and even to hoar hairs will I carry you:"], ["o a'u lava ou te tauave ia te oe;", "I have made,"], ["o a'u na ou faia,", "and I will bear;"], ["ou te siitia foi, ou te tauave,", "even I will carry,"], ["ma ou laveaiina oe .", "and will deliver you."]]},
  {num:5,words:[["Po o ai ea tou te faatusa i ai a'u,", "To whom will ye liken me,"], ["pe faagatusa ma a'u,", "and make me equal, and compare me,"], ["pe faatatau ia te au ina ia ma tutusa?", "that we may be like?"]]},
  {num:6,words:[["Ua latou soona sasaa mai le auro mai le taga,", "They lavish gold out of the bag,"], ["ua latou fuatia le ario i le fua faatautau;", "and weigh silver in the balance,"], ["ua latou avatu le oloa i lē fai mea uamea,", "and hire a goldsmith; and he maketh it a god:"], ["na te faia se atua,", "they fall down,"], ["latou te ifo faō i ai,", "yea,"], ["latou te tapuai lava i ai.", "they worship."]]},
  {num:7,words:[["Latou te siitia o ia i o latou tau'au,", "They bear him upon the shoulder,"], ["ua latou amo ia te ia,", "they carry him,"], ["ua latou tuuina o ia i lana mea e tuu ai,", "and set him in his place,"], ["ona tu ai lea o ia,", "and he standeth;"], ["e le alu ese o ia ai lona tulaga;", "from his place shall he not remove: yea,"], ["e alaga lava se tasi ia te ia,", "one shall cry unto him,"], ["a e le tali mai o ia;", "yet can he not answer,"], ["na te le faaolaina o ia i lona puapuaga.", "nor save him out of his trouble."]]},
  {num:8,words:[["Ia outou manatunatu i lenei mea,", "Remember this,"], ["ma ia outou amio i amio a tagata;", "and shew yourselves men: bring it again to mind,"], ["ia mafaufau i ai outou o e solitulafono.", "O ye transgressors."]]},
  {num:9,words:[["Ia outou manatunatu i mea muamua talu mai le vavau;", "Remember the former things of old:"], ["auā o a'u o le Atua,", "for I am God,"], ["e leai lava se tasi;", "and there is none else;"], ["o le Atua,", "I am God,"], ["e leai se ma te tutusa;", "and there is none like me,"]]},
  {num:10,words:[["o loo faaali talu mai le amataga o mea e mulimuli;", "Declaring the end from the beginning,"], ["mai anamua foi o mea ua le faia;", "and from ancient times the things that are not yet done,"], ["o loo fai ane,", "saying,"], ["E tu la'u pule,", "My counsel shall stand,"], ["ou te faia foi mea uma ou te loto i ai.", "and I will do all my pleasure:"]]},
  {num:11,words:[["O loo valaau i le manu lele e feai mai sasae;", "Calling a ravenous bird from the east,"], ["o le tagata mai le nuu mamao ua ou tofia;", "the man that executeth my counsel from a far country:"], ["na ou fai atu ai ,", "yea, I have spoken it,"], ["ou te faaooina ai lava;", "I will also bring it to pass;"], ["na ou fuafuatia,", "I have purposed it,"], ["ou te faia lava.", "I will also do it."]]},
  {num:12,words:[["Faalogo mai ia,", "Hearken unto me,"], ["outou o e loto faafinauvale,", "ye stouthearted,"], ["o e ua mamao ma se amiotonu.", "that are far from righteousness:"]]},
  {num:13,words:[["Ua ou aumaia la'u amiotonu,", "I bring near my righteousness;"], ["e le mamao ia;", "it shall not be far off,"], ["e le faatuai foi la'u faaolataga;", "and my salvation shall not tarry:"], ["ou te avatu la'u faaolataga i Siona mo Isaraelu o le e viia ai a'u.", "and I will place salvation in Zion for Israel my glory."]]},
];
renderVerseSet(isa_ch_46_Verses, 'isa-ch46-verses');

var isa_ch_47_Verses = [
  {num:1,words:[["Alu ifo ia,", "Come down,"], ["ina e nofo i le efuefu,", "and sit in the dust,"], ["o oe le taupou le tama teine a Papelonia,", "O virgin daughter of Babylon,"], ["ina nofo i le eleele, e leai se nofoālii,", "sit on the ground:"], ["o oe le tama teine a Kaletaia;", "there is no throne,"], ["auā e le toe ta'ua oe,", "O daughter of the Chaldeans:"], ["O le ua tino văivai ma le faapelepeleina.", "for thou shalt no more be called tender and delicate."]]},
  {num:2,words:[["Tago ia i maaolo ma e olo falaoa;", "Take the millstones,"], ["suesue lou ie ufimata,", "and grind meal:"], ["agini ae ia le ofu laei,", "uncover thy locks, make bare the leg,"], ["faaaliali lou vae,", "uncover the thigh,"], ["asa atu i vaitafe.", "pass over the rivers."]]},
  {num:3,words:[["E faaalia lou tino,", "Thy nakedness shall be uncovered,"], ["e vaaia foi lou mā;", "yea,"], ["ou te taui ma sui,", "thy shame shall be seen: I will take vengeance,"], ["ou te le mafai ona ia tu mai se tagata.", "and I will not meet thee as a man."]]},
  {num:4,words:[["O le na faatauina i tatou,", "As for our redeemer,"], ["o Ieova o 'au lona suafa,", "the LORD of hosts is his name,"], ["o le Paia o Isaraelu.", "the Holy One of Israel."]]},
  {num:5,words:[["Nofo faalologo ia,", "Sit thou silent,"], ["ma e alu i le pouliuli,", "and get thee into darkness,"], ["o oe le tama teine a Kaletaia;", "O daughter of the Chaldeans:"], ["auā e le toe ta'ua oe,", "for thou shalt no more be called,"], ["O le tamaitai e pule i malo.", "The lady of kingdoms."]]},
  {num:6,words:[["Na a'u tiga i lo'u nuu,", "I was wroth with my people,"], ["na ou faatagaina lo'u tofi;", "I have polluted mine inheritance,"], ["na ou tuuina atu i latou i lou lima,", "and given them into thine hand:"], ["na e le alofa lava ia i latou,", "thou didst shew them no mercy;"], ["na e matuā faamamafaina lau amo i luga o toeaina.", "upon the ancient hast thou very heavily laid thy yoke."]]},
  {num:7,words:[["Na e fai ane foi,", "And thou saidst,"], ["E fai a'u ma tamaitai e faavavau;", "I shall be a lady for ever:"], ["o lea na e le mafaufau ai i nei mea,", "so that thou didst not lay these things to thy heart,"], ["ua e le manatua le iuga o ia mea.", "neither didst remember the latter end of it."]]},
  {num:8,words:[["O lenei,", "Therefore hear now this,"], ["faalogo mai ia i lenei mea,", "thou that art given to pleasures,"], ["o oe le sa'oloto i mea a le tino,", "that dwellest carelessly,"], ["o lē nofo faatalanoa,", "that sayest in thine heart,"], ["o lē fai ifo i lou lava loto, Ua na o a'u,", "I am,"], ["a e leai lava se tasi;", "and none else beside me;"], ["ou te le nofo o le fafine ua oti lana tane,", "I shall not sit as a widow,"], ["ou te le iloa ona āufanaua.", "neither shall I know the loss of children:"]]},
  {num:9,words:[["E oo mai lava ia te oe nei mea e lua,", "But these two things shall come to thee in a moment in one day,"], ["e faafuasei i le aso e tasi,", "the loss of children,"], ["o le āufanaua ma le oti o lau tane;", "and widowhood:"], ["e ui lava i le tele o au togafiti faataulāitu,", "they shall come upon thee in their perfection for the multitude of thy sorceries,"], ["ma le malosi o au 'apere e matuā oo mai lava ia te oe.", "and for the great abundance of thine enchantments."]]},
  {num:10,words:[["Ua e faatuatua foi i lou leaga;", "For thou hast trusted in thy wickedness:"], ["ua e fai ane,", "thou hast said,"], ["E leai se iloa mai a'u;", "None seeth me. Thy wisdom and thy knowledge,"], ["o lou poto ma lou malamalama, o mea lava ia ua faaliliueseina ai oe;", "it hath perverted thee;"], ["ua e faapea ifo foi i lou lava loto,", "and thou hast said in thine heart,"], ["Ua na o a'u lava,", "I am,"], ["a e leai se tasi.", "and none else beside me."]]},
  {num:11,words:[["O le mea lea e oo mai ai le leaga ia te oe,", "Therefore shall evil come upon thee;"], ["e te le iloa ona gafoa o lona ata;", "thou shalt not know from whence it riseth:"], ["e paū i ou luga le malaia e te le mafai ai sona togiola;", "and mischief shall fall upon thee; thou shalt not be able to put it off:"], ["e oo mai foi ia te oe le faatafunaina e faafuasei;", "and desolation shall come upon thee suddenly,"], ["e te le iloa.", "which thou shalt not know."]]},
  {num:12,words:[["Ia e finau i au 'apere ma le tele o au togafiti faataulāitu,", "Stand now with thine enchantments,"], ["ua e lailoa ai talu ina e itiiti;", "and with the multitude of thy sorceries,"], ["ai lava ua aoga ia te oe,", "wherein thou hast laboured from thy youth; if so be thou shalt be able to profit,"], ["ai lava e te faamatau mai ai .", "if so be thou mayest prevail."]]},
  {num:13,words:[["Ua tigaina oe i le tele o au filifiliga;", "Thou art wearied in the multitude of thy counsels. Let now the astrologers,"], ["se'i tutū mai o e vaevaea le lagi,", "the stargazers,"], ["o e vaavaai i fetu,", "the monthly prognosticators,"], ["o e iite i ona po o le masina faatoa vaaia,", "stand up,"], ["ma latou faaolaina oe i mea o le a oo ia te oe.", "and save thee from these things that shall come upon thee."]]},
  {num:14,words:[["Faauta,", "Behold,"], ["e avea i latou e pei o tagutugutu o saito;", "they shall be as stubble;"], ["e susunuina i latou i le afi;", "the fire shall burn them;"], ["e le laveaiina i latou e i latou ai le malosi o le mumū o le afi;", "they shall not deliver themselves from the power of the flame:"], ["e leai se malala ola e mumulu ai,", "there shall not be a coal to warm at,"], ["po o se afi e nofo atu ai i ona luma.", "nor fire to sit before it."]]},
  {num:15,words:[["E faapea lava ia te oe o i latou ua e lailoa ai;", "Thus shall they be unto thee with whom thou hast laboured,"], ["o e ua faatau ma oe talu ina e teine itiiti;", "even thy merchants,"], ["e taitasi ma alu i lona lava ala;", "from thy youth: they shall wander every one to his quarter;"], ["e leai se na te faaola ia te oe.", "none shall save thee."]]},
];
renderVerseSet(isa_ch_47_Verses, 'isa-ch47-verses');

var isa_ch_48_Verses = [
  {num:1,words:[["Faalogo mai ia i lenei mea outou le aiga o Iakopo,", "Hear ye this,"], ["o e ua igoa i le igoa o Isaraelu,", "O house of Jacob, which are called by the name of Israel,"], ["ma ua latou o atu nai le vai o Iuta;", "and are come forth out of the waters of Judah,"], ["o e tauto i le suafa o Ieova,", "which swear by the name of the LORD,"], ["ma ta'uta'u atu i le Atua o Isaraelu,", "and make mention of the God of Israel, but not in truth,"], ["a e le o le faamaoni ma le amiotonu.", "nor in righteousness."]]},
  {num:2,words:[["Auā e igoa ai i latou i le aai paia,", "For they call themselves of the holy city,"], ["ma latou faalagolago i le Atua o Isaraelu;", "and stay themselves upon the God of Israel;"], ["o Ieova o 'au lona suafa.", "The LORD of hosts is his name."]]},
  {num:3,words:[["Na a'u faaalia mea muamua talu anamua;", "I have declared the former things from the beginning;"], ["ua oo atu ia mea ai lo'u gutu,", "and they went forth out of my mouth,"], ["na ou faailoa atu ai;", "and I shewed them;"], ["ua faafuasei ona ou faia,", "I did them suddenly,"], ["ma ua taunuu lava.", "and they came to pass."]]},
  {num:4,words:[["Auā ua ou iloa ua finau vale lava oe,", "Because I knew that thou art obstinate,"], ["ma lou ua o le ua uamea lea,", "and thy neck is an iron sinew,"], ["ma lou muaulu o le 'apa memea lea;", "and thy brow brass;"]]},
  {num:5,words:[["o le mea lea na a'u faaali atu ai ia mea ia te oe talu anamua;", "I have even from the beginning declared it to thee;"], ["na ou faailoa ia te oe a o lei oo mai;", "before it came to pass I shewed it thee: lest thou shouldest say,"], ["ina ne'i ē fai ane,", "Mine idol hath done them,"], ["Ua faia ia mea e la'u tupua;", "and my graven image, and my molten image,"], ["ua pule ai foi la'u tupua ua ta ma la'u tupua uamea.", "hath commanded them."]]},
  {num:6,words:[["Ua e faalogo ai;", "Thou hast heard,"], ["ina vaai ia i na mea uma;", "see all this;"], ["a o outou,", "and will not ye declare it? I have shewed thee new things from this time,"], ["tou te le faaalia ea? E afua mai i nei ona po ou te faailoa ai ia te oe o mea fou,", "even hidden things,"], ["o mea lilo foi sa e le iloa.", "and thou didst not know them."]]},
  {num:7,words:[["Ua faia nei lava ia mea,", "They are created now,"], ["a e le o anamua;", "and not from the beginning;"], ["a o lei oo i le aso nei e te lei faalogo ai;", "even before the day when thou heardest them not;"], ["ina ne'i e fai ane,", "lest thou shouldest say,"], ["Faauta,", "Behold,"], ["na e iloa lava ia mea.", "I knew them."]]},
  {num:8,words:[["E moni,", "Yea,"], ["ua e le faalogo;", "thou heardest not;"], ["e moni, ua e le iloa;", "yea,"], ["e moni,", "thou knewest not;"], ["talu anamua ua le uai mai ou taliga;", "yea,"], ["auā na ou iloa e te matuā amio faa'ole'ole; na igoa oe,", "from that time that thine ear was not opened:"], ["o le fouvale,", "for I knew that thou wouldest deal very treacherously,"], ["talu ina fanau mai.", "and wast called a transgressor from the womb."]]},
  {num:9,words:[["Ou te faatoatoa ona o lo'u igoa;", "For my name's sake will I defer mine anger,"], ["ou te taofi foi lo'u ita ia te oe ona o lo'u viiga,", "and for my praise will I refrain for thee,"], ["ina ne'i ou faaumatia oe.", "that I cut thee not off."]]},
  {num:10,words:[["Faauta,", "Behold,"], ["ua ou faate'a le otaota ia te oe,", "I have refined thee,"], ["a e le pei o le ario;", "but not with silver;"], ["ua ou filifilia oe i le ogaumu o i ai le puapuaga.", "I have chosen thee in the furnace of affliction."]]},
  {num:11,words:[["Ona o a'u,", "For mine own sake,"], ["ona o a'u lava,", "even for mine own sake,"], ["ou te faia; auā pe faapefea ona faagafuaina lo'u igoa? o lo'u mamalu foi,", "will I do it:"], ["ou te le avatua lea i se tasi.", "for how should my name be polluted? and I will not give my glory unto another."]]},
  {num:12,words:[["Faalogo mai ia ia te au,", "Hearken unto me,"], ["Iakopo e,", "O Jacob and Israel,"], ["o oe foi Isaraelu le na ou valaauina;", "my called;"], ["o a'u lava ia,", "I am he;"], ["o a'u lava lē muamua,", "I am the first,"], ["o a'u foi lē mulimuli.", "I also am the last."]]},
  {num:13,words:[["O lo'u lima foi na faavaeina ai le lalolagi,", "Mine hand also hath laid the foundation of the earth,"], ["ma lo'u lima taumatau na folasia ai le lagi;", "and my right hand hath spanned the heavens:"], ["ou te valaau ia te i latou,", "when I call unto them,"], ["ona latou tutū faatasi mai lea.", "they stand up together."]]},
  {num:14,words:[["Ia faapotopoto mai outou uma lava,", "All ye, assemble yourselves,"], ["ma ia outou faalogo mai. O ai ea so latou na ia faaalia mai nei mea? Ua alofa Ieova ia te ia;", "and hear;"], ["na te faia lona finagalo i Papelonia,", "which among them hath declared these things? The LORD hath loved him:"], ["e oo foi lona lima i Kaletaia.", "he will do his pleasure on Babylon, and his arm shall be on the Chaldeans."]]},
  {num:15,words:[["O a'u,", "I,"], ["o a'u lava,", "even I,"], ["na a'u fai atu;", "have spoken; yea,"], ["na ou valaauina foi o ia;", "I have called him:"], ["na ou aumaia o ia,", "I have brought him,"], ["e manuia foi lona ala.", "and he shall make his way prosperous."]]},
  {num:16,words:[["Faalatalata mai ia ia te au;", "Come ye near unto me,"], ["ia outou faalogo mai i lenei mea;", "hear ye this;"], ["talu mai le amataga ou te lei tautala faalilolilo;", "I have not spoken in secret from the beginning;"], ["talu ona i ai o lea mea,", "from the time that it was,"], ["na ou i ai o a'u; o lenei foi,", "there am I:"], ["o le Alii o Ieova,", "and now the Lord GOD,"], ["na ia auina mai a'u,", "and his Spirit,"], ["ma lona Agaga.", "hath sent me."]]},
  {num:17,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["o le na faatauina oe, o le Paia o Isaraelu,", "thy Redeemer,"], ["O a'u o Ieova,", "the Holy One of Israel;"], ["o lou Atua, o loo a'oa'o ia te oe i mea e aoga,", "I am the LORD thy God which teacheth thee to profit,"], ["o loo ta'ita'iina oe i le ala e te ui ai.", "which leadeth thee by the way that thou shouldest go."]]},
  {num:18,words:[["E! ana uai mai ou taliga i a'u poloaiga, po ua tusa ma se vaitafe lou manuia;", "O that thou hadst hearkened to my commandments! then had thy peace been as a river,"], ["ma lau amiotonu, e tusa lea ma peau o le sami;", "and thy righteousness as the waves of the sea:"]]},
  {num:19,words:[["po ua pei o le oneone lau fanau; ma ē tutupu mai i lou manava,", "Thy seed also had been as the sand,"], ["e pei o lona manava;", "and the offspring of thy bowels like the gravel thereof;"], ["e le vavaeeseina, ma le fanoia lona igoa ai o'u luma.", "his name should not have been cut off nor destroyed from before me."]]},
  {num:20,words:[["Ia outou o ese i Papelonia;", "Go ye forth of Babylon,"], ["ia sosola ese ia Kaletaia ma le taalili o le alaga fiafia;", "flee ye from the Chaldeans,"], ["ia outou faaali atu,", "with a voice of singing declare ye,"], ["ia faailoa atu lenei mea,", "tell this,"], ["ia faaoo atu ai i le tuluiga o le lalolagi;", "utter it even to the end of the earth;"], ["ia outou fai atu ai,", "say ye,"], ["Ua faatauina e Ieova o lana auauna o Iakopo.", "The LORD hath redeemed his servant Jacob."]]},
  {num:21,words:[["Sa latou le fia inu i nuu naumati na ia avea ai i latou;", "And they thirsted not when he led them through the deserts:"], ["na ia faatafe mai le vai mai le papa mo i latou;", "he caused the waters to flow out of the rock for them:"], ["na ia vaea le papa,", "he clave the rock also,"], ["ona tafe mai ai lea o le vai.", "and the waters gushed out."]]},
  {num:22,words:[["Ua fetalai mai Ieova,", "There is no peace, saith the LORD,"], ["E leai se filemu i e amio leaga.", "unto the wicked."]]},
];
renderVerseSet(isa_ch_48_Verses, 'isa-ch48-verses');

var isa_ch_49_Verses = [
  {num:1,words:[["Faalogo mai ia ia te au,", "Listen, O isles,"], ["outou nuu tu matafaga e;", "unto me;"], ["uai mai ia o outou taliga outou nuu mamao e;", "and hearken, ye people,"], ["ua valaauina a'u e Ieova talu mai le manava;", "from far;"], ["ua na ta'ua lo'u igoa talu mai le manava o lo'u tinā.", "The LORD hath called me from the womb; from the bowels of my mother hath he made mention of my name."]]},
  {num:2,words:[["Ua na faia lo'u gutu e pei o le pelu maai;", "And he hath made my mouth like a sharp sword;"], ["ua ia natia a'u i le paolo o lona aao;", "in the shadow of his hand hath he hid me,"], ["ua na faia a'u ma u fanafana ua faapupulaina,", "and made me a polished shaft;"], ["ma na faalilo ia te au i lana utu.", "in his quiver hath he hid me;"]]},
  {num:3,words:[["Na ia fetalai mai ia te au,", "And said unto me,"], ["O la'u auauna lava oe Isaraelu e,", "Thou art my servant, O Israel,"], ["e viia lava a'u ona o oe.", "in whom I will be glorified."]]},
  {num:4,words:[["Ona ou fai atu ai lea,", "Then I said,"], ["Ua ou tigaina fua; ua ou faaumaina lo'u malosi,", "I have laboured in vain,"], ["ua iu vale,", "I have spent my strength for nought,"], ["ua le aoga;", "and in vain:"], ["a e ui lava i lea, o loo ia Ieova lo'u faamasinoga,", "yet surely my judgment is with the LORD,"], ["ma lo'u taui o loo i lo'u Atua lea.", "and my work with my God."]]},
  {num:5,words:[["A o lenei,", "And now,"], ["o loo fetalai mai Ieova,", "saith the LORD that formed me from the womb to be his servant,"], ["o le na faia a'u talu mai le manava e fai ma auauna ia te ia, e toe faafoisia Iakopo ia te ia;", "to bring Jacob again to him,"], ["e ui lava ina le faapotopotoina o Isaraelu,", "Though Israel be not gathered,"], ["a e viia a'u i luma o Ieova;", "yet shall I be glorious in the eyes of the LORD,"], ["e fai foi lo'u Atua mo'u malosi.", "and my God shall be my strength."]]},
  {num:6,words:[["Ua fetalai mai foi o ia,", "And he said,"], ["O le mea māmā ina ia fai oe ma auauna ia te au,", "It is a light thing that thou shouldest be my servant to raise up the tribes of Jacob,"], ["ina ia faaea mai itu aiga o Iakopo, ma faafoisia mai e ua faasaoina i Isaraelu;", "and to restore the preserved of Israel:"], ["ua ou avatua foi oe e fai ma malamalama o nuu ese,", "I will also give thee for a light to the Gentiles,"], ["e fai ma'u faaolataga ia oo i tuluiga o le lalolagi.", "that thou mayest be my salvation unto the end of the earth."]]},
  {num:7,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["o le Faaola o Isaraelu, o lona Alii Paia,", "the Redeemer of Israel,"], ["i le ua faaleaogaina e tagata,", "and his Holy One,"], ["ma inosia e le nuu,", "to him whom man despiseth,"], ["o le auauna a ē pule;", "to him whom the nation abhorreth,"], ["e iloa mai tupu, ma latou tulai;", "to a servant of rulers,"], ["o alii foi,", "Kings shall see and arise,"], ["ma latou ifo;", "princes also shall worship,"], ["auā o Ieova,", "because of the LORD that is faithful,"], ["o le ua faamaoni, o le Paia o Isaraelu,", "and the Holy One of Israel,"], ["le ua filifilia oe.", "and he shall choose thee."]]},
  {num:8,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["O ona po o le alofa ua ou tali atu ai ia te oa;", "In an acceptable time have I heard thee,"], ["o le aso e faaolaina ai ua ou fesoasoani ai ia te oe;", "and in a day of salvation have I helped thee:"], ["ou te leoleo foi ia te oe,", "and I will preserve thee,"], ["ma a'u avatua oe e fai ma feagaiga a le nuu;", "and give thee for a covenant of the people,"], ["ina ia faaeaina le lalolagi,", "to establish the earth,"], ["ia faia nuu ua faatafunaina mo latou tofi;", "to cause to inherit the desolate heritages;"]]},
  {num:9,words:[["e fai atu i e o fusifusia,", "That thou mayest say to the prisoners,"], ["O mai ia i fafo;", "Go forth;"], ["e fai atu foi i e o i le pouliuli, Faaali mai ia outou;", "to them that are in darkness,"], ["latou te aai lava i ala;", "Shew yourselves. They shall feed in the ways,"], ["o mauga tula uma o latou taaga ia.", "and their pastures shall be in all high places."]]},
  {num:10,words:[["Latou te le fia aai, latou te le fia inu foi;", "They shall not hunger nor thirst;"], ["e le ogotia i latou i le vevela po o le la;", "neither shall the heat nor sun smite them:"], ["auā o le ua alofa ia i latou,", "for he that hath mercy on them shall lead them,"], ["na te ave ia te i latou, na te ta'ita'iina foi i latou i vaipuna.", "even by the springs of water shall he guide them."]]},
  {num:11,words:[["Ou te faia foi ma ala o'u mauga uma,", "And I will make all my mountains a way,"], ["e maualuga foi o'u ala tele.", "and my highways shall be exalted."]]},
  {num:12,words:[["Faauta,", "Behold,"], ["e o mai i latou nei mai le mea mamao;", "these shall come from far:"], ["faauta foi,", "and, lo,"], ["o i latou nei mai le itu i matu ma sisifo,", "these from the north and from the west;"], ["ma i latou mai le nuu o Sainima.", "and these from the land of Sinim."]]},
  {num:13,words:[["Ia alaga oe le lagi e,", "Sing,"], ["ia olioli oe le lalolagi e,", "O heavens; and be joyful,"], ["ia leo tetele outou mauga,", "O earth;"], ["ma ia alalaga fiafia;", "and break forth into singing,"], ["auā ua faamafanafanaina e Ieova lona nuu,", "O mountains: for the LORD hath comforted his people,"], ["ua ia alofa foi i ona tagata ua tigaina.", "and will have mercy upon his afflicted."]]},
  {num:14,words:[["A ua fai mai Siona,", "But Zion said,"], ["Ua lafoaiina a'u e Ieova;", "The LORD hath forsaken me,"], ["ua galo mai a'u i le Alii.", "and my Lord hath forgotten me."]]},
  {num:15,words:[["E galo ea i le fafine lana tama ua susu,", "Can a woman forget her sucking child,"], ["na te le alofa i le tama a lona lava manava? ai lava e galo ia te i latou,", "that she should not have compassion on the son of her womb? yea, they may forget,"], ["a e le galo lava oe ia te au.", "yet will I not forget thee."]]},
  {num:16,words:[["Faauta,", "Behold,"], ["ua ou taia lou faatusa i o'u alofilima;", "I have graven thee upon the palms of my hands;"], ["e tumau ou pa i o'u luma.", "thy walls are continually before me."]]},
  {num:17,words:[["E faataalise mai lau fanau; o e na lepetia oe,", "Thy children shall make haste;"], ["ma e na faatafunaina oe, latou te o ese ia te oe.", "thy destroyers and they that made thee waste shall go forth of thee."]]},
  {num:18,words:[["Fetepatepai ia oe i itu uma,", "Lift up thine eyes round about,"], ["ma e vaavaai o loo faapotopoto mai i latou uma,", "and behold: all these gather themselves together,"], ["ua latou o mai ia te oe.", "and come to thee."], ["Ua fetalai mai Ieova,", "As I live, saith the LORD,"], ["O loo ola a'u,", "thou shalt surely clothe thee with them all,"], ["e te ofu oe ia i latou uma e pei o mea e faamatagofie a'i,", "as with an ornament,"], ["ma ē fusi a'i e pei o le a nofo tane.", "and bind them on thee, as a bride doeth."]]},
  {num:19,words:[["Auā o au mea faatafunaina,", "For thy waste and thy desolate places,"], ["ma au mea tuufua,", "and the land of thy destruction,"], ["ma lou fanua ua oloina, e lauitiiti ia i ia ona aso i e nonofo ai;", "shall even now be too narrow by reason of the inhabitants,"], ["e mamao foi e na faaumatia oe.", "and they that swallowed thee up shall be far away."]]},
  {num:20,words:[["O au tama sa aveeseina ia te oe,", "The children which thou shalt have,"], ["latou te toe fai ane i ou taliga,", "after thou hast lost the other,"], ["Ua lauitiiti lenei mea ia te au;", "shall say again in thine ears,"], ["tuutuu atu ia,", "The place is too strait for me:"], ["ou te nofo ai.", "give place to me that I may dwell."]]},
  {num:21,words:[["E te fai ifo foi i lou loto. O ai ea na na fanaua mai i latou nei mo a'u? auā o a'u sa āufanaua ma ua pa,", "Then shalt thou say in thine heart, Who hath begotten me these,"], ["sa tāfea ma tulia a'u;", "seeing I have lost my children, and am desolate,"], ["o ai foi na na tausia i latou nei? Faauta,", "a captive,"], ["o a'u sa tuua e toatasi lava a'u,", "and removing to and fro? and who hath brought up these? Behold, I was left alone;"], ["o i latou nei sa ifea i latou?", "these, where had they been?"]]},
  {num:22,words:[["O loo faapea ona fetalai ma o le Alii o Ieova,", "Thus saith the Lord GOD,"], ["Faauta,", "Behold,"], ["ou te sii atu lo'u lima i nuu ese,", "I will lift up mine hand to the Gentiles,"], ["ma ou faatu i luga lo'u tagavai i nuu;", "and set up my standard to the people:"], ["latou te aumaia au tama tane i o latou fatafata,", "and they shall bring thy sons in their arms,"], ["a e aumaia au tama teine i o latou tau'au.", "and thy daughters shall be carried upon their shoulders."]]},
  {num:23,words:[["E fai foi tupu mau tausi tama,", "And kings shall be thy nursing fathers,"], ["ma o latou masiofo e fai mau failele;", "and their queens thy nursing mothers:"], ["latou te ifo toele ia te oe; latou te etoeto i le eleele o ou vae;", "they shall bow down to thee with their face toward the earth,"], ["e te iloa foi,", "and lick up the dust of thy feet;"], ["o a'u lava o Ieova,", "and thou shalt know that I am the LORD:"], ["e le faamaina i latou o e faatalitali ia te au.", "for they shall not be ashamed that wait for me."]]},
  {num:24,words:[["E faoa ea le vete ai le ua malosi? pe laveaiina ea le tafeaga a le ua amiotonu?", "Shall the prey be taken from the mighty, or the lawful captive delivered?"]]},
  {num:25,words:[["Aua o loo faapea ona fetalai mai o Ieova,", "But thus saith the LORD,"], ["E faoa lava le tafeaga a le ua malosi,", "Even the captives of the mighty shall be taken away,"], ["e laveaiina foi le vete a lē matautia;", "and the prey of the terrible shall be delivered:"], ["ou te finau atu foi a'u i e ua finau atu ia te oe,", "for I will contend with him that contendeth with thee,"], ["ou te faaolaina foi au tama.", "and I will save thy children."]]},
  {num:26,words:[["Ou te fagaina foi e ua saua ia te oe i o latou lava tino;", "And I will feed them that oppress thee with their own flesh;"], ["e onā foi i latou i o latou toto e pei se suavine; e iloa ai tagata uma lava,", "and they shall be drunken with their own blood,"], ["o a'u lava o Ieova,", "as with sweet wine:"], ["o lou Faaola, ma le na faatauina oe,", "and all flesh shall know that I the LORD am thy Saviour and thy Redeemer,"], ["o le Malosi o Iakopo.", "the mighty One of Jacob."]]},
];
renderVerseSet(isa_ch_49_Verses, 'isa-ch49-verses');

var isa_ch_50_Verses = [
  {num:1,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["O fea le tusi alei a lo outou tinā na a'u aleia ai o ia? po o ai le tagata ua ou aitalafu i ai,", "Where is the bill of your mother's divorcement,"], ["na a'u faatauina atu ai outou ia te ia? Faauta mai,", "whom I have put away? or which of my creditors is it to whom I have sold you? Behold,"], ["ona o a outou amio leaga ua faatauina atu ai outou;", "for your iniquities have ye sold yourselves,"], ["ona o a outou solitulafono ua aleia ai lo outou tinā.", "and for your transgressions is your mother put away."]]},
  {num:2,words:[["Na a'u sau,", "Wherefore,"], ["o le a lava le mea na leai ai se tasi? Na a'u valaau,", "when I came,"], ["se a le mea ua leai ai se na tali mai? Ua faapuupuuina ea lo'u lima,", "was there no man? when I called, was there none to answer? Is my hand shortened at all,"], ["ou te le mafaaola ai? pe leai ea se malosi ia te au e laveai ai? Faauta,", "that it cannot redeem? or have I no power to deliver? behold,"], ["o la'u aoai atu e pa'umatuina ai le sami,", "at my rebuke I dry up the sea,"], ["e fai foi e a'u o vaitafe ma nuu naumati;", "I make the rivers a wilderness: their fish stinketh,"], ["e elo i'a ua i ai ona ua leai se suāvai,", "because there is no water,"], ["e mamate foi i le fia inu.", "and dieth for thirst."]]},
  {num:3,words:[["Ou te faaofuina le lagi i le faauliuli;", "I clothe the heavens with blackness,"], ["ou te faia foi le ie talatala ma mea e ufiufi a'i.", "and I make sackcloth their covering."]]},
  {num:4,words:[["Ua foai mai ia te au e le Alii o Ieova le laulaufaiva o e ua a'oa'oina,", "The Lord GOD hath given me the tongue of the learned,"], ["ina ia ou iloa ona faamafanafana i se upu le ua tigaina;", "that I should know how to speak a word in season to him that is weary:"], ["na te fagua a'u i lea taeao ma lea taeao; na te fagua o'u taliga,", "he wakeneth morning by morning,"], ["ina ia ou faalogologo e pei o e ua a'oa'oina.", "he wakeneth mine ear to hear as the learned."]]},
  {num:5,words:[["Ua toina le puipui o o'u taliga e le Alii o Ieova,", "The Lord GOD hath opened mine ear,"], ["a ou te lei finau vale;", "and I was not rebellious,"], ["ou te le foi atu lava.", "neither turned away back."]]},
  {num:6,words:[["Na a'u tuuina atu lo'u tua i e sasa mai,", "I gave my back to the smiters,"], ["ma o'u alafau i e futi le 'ava;", "and my cheeks to them that plucked off the hair:"], ["ou te lei ufiufi foi o'u mata i le mā ma le feanu.", "I hid not my face from shame and spitting."]]},
  {num:7,words:[["A o le Alii o Ieova e fesoasoani mai o ia ia te au;", "For the Lord GOD will help me;"], ["o le mea lea ou te le mā ai;", "therefore shall I not be confounded:"], ["o le mea lea ua ou faia o'u mata ia pei o le papa alā;", "therefore have I set my face like a flint,"], ["ua ou iloa foi e le faamaina a'u.", "and I know that I shall not be ashamed."]]},
  {num:8,words:[["O loo ua latalata mai le na te ta'uamiotonuina a'u,", "He is near that justifieth me;"], ["o ai ea se finau ma a'u? Se'i ma tutū faatasi;", "who will contend with me? let us stand together:"], ["o ai se finau mai? ia faalatalata mai o ia ia te au.", "who is mine adversary? let him come near to me."]]},
  {num:9,words:[["Faauta,", "Behold,"], ["o le Alii o Ieova,", "the Lord GOD will help me;"], ["na te fesoasoani mai ia te au; o ai ea se na te faasalaina mai? Faauta,", "who is he that shall condemn me? lo,"], ["e pala i latou uma e pei o le ofu;", "they all shall wax old as a garment;"], ["e 'aina e le mogamoga.", "the moth shall eat them up."]]},
  {num:10,words:[["O ai ea so outou ua mata'u ia Ieova,", "Who is among you that feareth the LORD,"], ["o loo faalogo i le upu a lana auauna,", "that obeyeth the voice of his servant,"], ["e lē savali i le pouliuli,", "that walketh in darkness,"], ["a e leai sona malamalama? ia faatuatua o ia i le suafa o Ieova,", "and hath no light? let him trust in the name of the LORD,"], ["ma faalagolago i lona Atua.", "and stay upon his God."]]},
  {num:11,words:[["Faauta mai outou uma o e si'a se afi;", "Behold,"], ["ua siomia outou e outou i aloiafi;", "all ye that kindle a fire,"], ["savavali ia i le malamalama o lo outou afi,", "that compass yourselves about with sparks:"], ["ma aloiafi o lo outou afi;", "walk in the light of your fire,"], ["e oo ia te outou lenei mea ai lo'u lima,", "and in the sparks that ye have kindled. This shall ye have of mine hand;"], ["tou te taooto i le tiga.", "ye shall lie down in sorrow."]]},
];
renderVerseSet(isa_ch_50_Verses, 'isa-ch50-verses');

var isa_ch_51_Verses = [
  {num:1,words:[["Faalogo mai ia ia te au,", "Hearken to me,"], ["outou o e tausisi atu i le amiotonu,", "ye that follow after righteousness,"], ["e ua saili ia Ieova;", "ye that seek the LORD:"], ["ina vaavaai ia i le papa na tofitofia mai ai outou,", "look unto the rock whence ye are hewn,"], ["ma le gutu o le lua na elia mai ai outou.", "and to the hole of the pit whence ye are digged."]]},
  {num:2,words:[["Ia outou vaavaai ia Aperaamo lo outou tamā,", "Look unto Abraham your father,"], ["ma Sara o le na fanaua outou;", "and unto Sarah that bare you:"], ["auā na a'u valaauina o ia a o toatasi,", "for I called him alone,"], ["ma ou faamanuia ia te ia,", "and blessed him,"], ["ma faatoateleina o ia.", "and increased him."]]},
  {num:3,words:[["Auā e faamafanafanaina Siona e Ieova,", "For the LORD shall comfort Zion:"], ["e faamafanafanaina ana mea faatafunaina uma lava;", "he will comfort all her waste places;"], ["na te faia lona fanua lafulafua e pei o Etena,", "and he will make her wilderness like Eden, and her desert like the garden of the LORD;"], ["ma lona toafa e pei o le faatoaga a Ieova;", "joy and gladness shall be found therein,"], ["e maua ai le fiafia ma le olioli,", "thanksgiving,"], ["o le faafetai ma le leo o le pese.", "and the voice of melody."]]},
  {num:4,words:[["Faalogo mai ia ia te au lo'u nuu e;", "Hearken unto me, my people;"], ["o'u tagata e uai mai ia o outou taliga ia te au;", "and give ear unto me,"], ["auā e alu atu le tulafono ia te au,", "O my nation:"], ["ou te faatumauina foi la'u faamasinoga e fai ma malamalama o nuu.", "for a law shall proceed from me, and I will make my judgment to rest for a light of the people."]]},
  {num:5,words:[["Ua lata mai le amiotonu mai ia te au,", "My righteousness is near;"], ["ua alu atu la'u faaolataga;", "my salvation is gone forth,"], ["o'u lima foi e faamasinoina ai nuu;", "and mine arms shall judge the people;"], ["e faatalitali mai ia te au o nuu tu matafaga,", "the isles shall wait upon me,"], ["latou te faamoemoe foi i lo'u lima.", "and on mine arm shall they trust."]]},
  {num:6,words:[["Ina tepa ae ia outou i le lagi,", "Lift up your eyes to the heavens,"], ["ma vaai i le lalolagi i lalo;", "and look upon the earth beneath:"], ["auā e mavae atu le lagi e pei o le asu,", "for the heavens shall vanish away like smoke,"], ["e pala le lalolagi e pei o le ofu;", "and the earth shall wax old like a garment,"], ["e faapena lava ona oti o e nonofo ai;", "and they that dwell therein shall die in like manner:"], ["a o la'u faaolataga e faavavau lava lea,", "but my salvation shall be for ever,"], ["ma le amiotonu mai ia te au o le gausia lava lea.", "and my righteousness shall not be abolished."]]},
  {num:7,words:[["Faalogo mai ia ia te au,", "Hearken unto me,"], ["outou o e ua iloa le amiotonu,", "ye that know righteousness,"], ["o le nuu ua i o latou loto la'u tulafono;", "the people in whose heart is my law;"], ["aua le fefefe i le faalumaina mai e tagata;", "fear ye not the reproach of men,"], ["aua foi le faavaivai i lo latou faifai mai.", "neither be ye afraid of their revilings."]]},
  {num:8,words:[["Auā e 'aina i latou e le mogamoga e pei o le ofu,", "For the moth shall eat them up like a garment,"], ["e 'aina foi i latou e le pepe e pei o fulufulu mamoe;", "and the worm shall eat them like wool:"], ["a o le amiotonu mai ia te au e faavavau lava lea,", "but my righteousness shall be for ever,"], ["ma la'u faaolataga e āutupulaga lea.", "and my salvation from generation to generation."]]},
  {num:9,words:[["Ala mai ia,", "Awake,"], ["ina ala mai,", "awake,"], ["ia ofu i le malosi,", "put on strength,"], ["o oe na le aao o Ieova;", "O arm of the LORD;"], ["ala mai ia e pei o aso anamua,", "awake,"], ["o tupulaga o le vavau;", "as in the ancient days,"], ["e le o oe ea le na fasiotia Raava,", "in the generations of old. Art thou not it that hath cut Rahab,"], ["o le na manua ai le tanimo?", "and wounded the dragon?"]]},
  {num:10,words:[["E le o oe ea na pa'umatu ai le sami,", "Art thou not it which hath dried the sea, the waters of the great deep;"], ["o le suāsami o le moana sāusau? o le na faia mea loloto i le sami ma ala e ui ai e ua faatauina?", "that hath made the depths of the sea a way for the ransomed to pass over?"]]},
  {num:11,words:[["E foi mai e ua togiolaina e Ieova,", "Therefore the redeemed of the LORD shall return,"], ["latou te o mai foi i Siona ma le alaga ma le olioli e faavavau i luga i o latou ulu;", "and come with singing unto Zion;"], ["latou te maua le olioli ma le fiafia;", "and everlasting joy shall be upon their head: they shall obtain gladness and joy;"], ["a e sosola ese le faanoanoa ma le mapuitiga.", "and sorrow and mourning shall flee away."]]},
  {num:12,words:[["O a'u,", "I, even I,"], ["o a'u lava lē faamafanafana ia te outou;", "am he that comforteth you:"], ["o ai ea oe e te fefe i le tagata e oti,", "who art thou,"], ["ma le atalii o le tagata e avea o ia e pei o le mutia.", "that thou shouldest be afraid of a man that shall die, and of the son of man which shall be made as grass;"]]},
  {num:13,words:[["Ua galo foi ia te oe o Ieova o le na faia oe,", "And forgettest the LORD thy maker,"], ["le na fofola le lagi,", "that hath stretched forth the heavens,"], ["ma faavaeina le lalolagi; ua e fefe pea i aso uma ona o le ita o lē faasaua,", "and laid the foundations of the earth;"], ["ina ua sauni o ia e fasioti;", "and hast feared continually every day because of the fury of the oppressor,"], ["a o ifea le ita o lē faasaua?", "as if he were ready to destroy? and where is the fury of the oppressor?"]]},
  {num:14,words:[["O le ua faano'uno'u ina ua fusifusia e faavave o ia ina ia tatalaina,", "The captive exile hasteneth that he may be loosed,"], ["ia le oti foi o ia i le lua,", "and that he should not die in the pit,"], ["ia le oge foi i ni mea e 'ai.", "nor that his bread should fail."]]},
  {num:15,words:[["O a'u foi o Ieova lou Atua,", "But I am the LORD thy God,"], ["o le e laolao ai le sami pe a ū mai ona peau;", "that divided the sea, whose waves roared:"], ["o Ieova o 'au o lona igoa lea.", "The LORD of hosts is his name."]]},
  {num:16,words:[["Ua ou tuuina atu a'u upu i lou gutu,", "And I have put my words in thy mouth,"], ["ua ou ufiufi foi ia te oe i le paolo o lo'u lima,", "and I have covered thee in the shadow of mine hand,"], ["e faatumau ai le lagi,", "that I may plant the heavens,"], ["ma faavaeina le lalolagi,", "and lay the foundations of the earth,"], ["e fai atu foi ia Siona,", "and say unto Zion,"], ["O lo'u nuu lava oe.", "Thou art my people."]]},
  {num:17,words:[["Ala mai ia,", "Awake,"], ["ina ala mai;", "awake,"], ["ina tulai mai oe Ierusalema,", "stand up, O Jerusalem,"], ["ua e inu nai le lima o Ieova le ipu o lona ita;", "which hast drunk at the hand of the LORD the cup of his fury;"], ["ua e inu i le ipu o le ipu e tautevateva ai,", "thou hast drunken the dregs of the cup of trembling,"], ["ua e inu uma ai lava.", "and wrung them out."]]},
  {num:18,words:[["Ua leai se tasi o ana tama uma na ia fanaua na te ta'ita'iina o ia; ua leai foi se tasi o ana tama uma na ia tausia,", "There is none to guide her among all the sons whom she hath brought forth;"], ["na te tago atu i lona lima.", "neither is there any that taketh her by the hand of all the sons that she hath brought up."]]},
  {num:19,words:[["Ua oo mai ia te oe o nei mea e lua;", "These two things are come unto thee; who shall be sorry for thee? desolation,"], ["o ai ea se na te faamafanafana ia te oe? o le faatafunaina ma le lepetia,", "and destruction,"], ["o le oge ma le pelu;", "and the famine,"], ["o ai ea? Ou te faamatalaloto ia te oe.", "and the sword: by whom shall I comfort thee?"]]},
  {num:20,words:[["Ua matapogia au tama,", "Thy sons have fainted,"], ["o loo taatitia i latou i mea e amata mai ai ala uma,", "they lie at the head of all the streets,"], ["e pei o le teō i le upega;", "as a wild bull in a net:"], ["ua tutumu i latou i le toasa o Ieova,", "they are full of the fury of the LORD,"], ["o le aoaiga mai lou Atua.", "the rebuke of thy God."]]},
  {num:21,words:[["O le mea lea,", "Therefore hear now this,"], ["se'i e faalogo mai ai i lenei mea,", "thou afflicted,"], ["o oe le ua tiga ma onā,", "and drunken,"], ["a e le o le uaina.", "but not with wine:"]]},
  {num:22,words:[["O loo faapea ona fetalai mai o lou Alii, o Ieova,", "Thus saith thy Lord the LORD,"], ["o lou Atua foi,", "and thy God that pleadeth the cause of his people,"], ["o le na te faia finauga a lona nuu;", "Behold,"], ["faauta, ou te ave ese i lou lima le ipu e tautevateva ai,", "I have taken out of thine hand the cup of trembling,"], ["o le ipu, o le ipu lava o lo'u ita;", "even the dregs of the cup of my fury;"], ["e te le toe inu ai lava.", "thou shalt no more drink it again:"]]},
  {num:23,words:[["A ou te tuu atu ai i lima o e faatiga ia te oe,", "But I will put it into the hand of them that afflict thee;"], ["o e na fai mai ia te oe,", "which have said to thy soul,"], ["Ifo ia,", "Bow down, that we may go over:"], ["ina ia matou ui atu ai;", "and thou hast laid thy body as the ground,"], ["ona fai lea o lou tua e pei o le eleele,", "and as the street,"], ["e pei o le ala foi i e sāvali i ai.", "to them that went over."]]},
];
renderVerseSet(isa_ch_51_Verses, 'isa-ch51-verses');

var isa_ch_52_Verses = [
  {num:1,words:[["Ala mai ia,", "Awake,"], ["ina ala mai;", "awake;"], ["ia e ofu i lou malosi,", "put on thy strength,"], ["o oe Siona e! ia e ofu i ou ofu matagofie,", "O Zion;"], ["o oe Ierusalema e,", "put on thy beautiful garments,"], ["le aai ua faasaina;", "O Jerusalem,"], ["auā e le toe alu atu ia te oe le ua le peritomeina,", "the holy city:"], ["ma le ua leaga.", "for henceforth there shall no more come into thee the uncircumcised and the unclean."]]},
  {num:2,words:[["Ia e lulu oe ia te oe ai le efuefu;", "Shake thyself from the dust;"], ["tulai ia,", "arise,"], ["ina e tietie i lou nofoa o oe Ierusalema;", "and sit down,"], ["tatala mai ia noanoaga o lou ua,", "O Jerusalem:"], ["o oe sa tāfea,", "loose thyself from the bands of thy neck,"], ["le tama fafine a Siona.", "O captive daughter of Zion."]]},
  {num:3,words:[["Auā o loo faapea ona fetalai mai o Ieova, Na faatauina atu outou,", "For thus saith the LORD,"], ["ua le tauia mai;", "Ye have sold yourselves for nought;"], ["e faatauina mai foi outou, a e le avatu ai ni ario.", "and ye shall be redeemed without money."]]},
  {num:4,words:[["Auā o loo faapea ona fetalai mai o le Alii o Ieova,", "For thus saith the Lord GOD,"], ["Na alu ifo lo'u nuu anamua i Aikupito e āumau ai;", "My people went down aforetime into Egypt to sojourn there;"], ["ua faasaua fua foi Asuria ia i latou.", "and the Assyrian oppressed them without cause."]]},
  {num:5,words:[["A o lenei,", "Now therefore,"], ["se a ea sa'u mea iinei? ua fetalai mai ai Ieova;", "what have I here,"], ["auā ua avea fua lo'u nuu; o e pule ia i latou,", "saith the LORD,"], ["ua latou uio,", "that my people is taken away for nought? they that rule over them make them to howl,"], ["ua fetalai mai ai Ieova;", "saith the LORD;"], ["ma ua inosia pea lava lo'u igoa i aso uma.", "and my name continually every day is blasphemed."]]},
  {num:6,words:[["O le mea lea e iloa ai lo'u igoa e lo'u nuu;", "Therefore my people shall know my name:"], ["o le mea lea e iloa ai i lea lava aso,", "therefore they shall know in that day that I am he that doth speak:"], ["o a'u lava le na fai atu,", "behold,"], ["Faauta mai ia te au!", "it is I."]]},
  {num:7,words:[["E matuā matagofie i luga o mauga o vae o le ua fai mai le tala lelei,", "How beautiful upon the mountains are the feet of him that bringeth good tidings,"], ["o lē logologo mai le manuia,", "that publisheth peace;"], ["ua tala mai le tala lelei;", "that bringeth good tidings of good,"], ["ua faailoa mai le olataga;", "that publisheth salvation;"], ["ua fai mai ia Siona,", "that saith unto Zion,"], ["O loo pule lou Atua.", "Thy God reigneth!"]]},
  {num:8,words:[["O le leo o ou tagata vaai,", "Thy watchmen shall lift up the voice;"], ["ua latou leo tetele,", "with the voice together shall they sing:"], ["ua latou alalaga faatasi; auā latou te iloa e faafesagai lava,", "for they shall see eye to eye,"], ["pe a faafoisia Siona e Ieova.", "when the LORD shall bring again Zion."]]},
  {num:9,words:[["Ia alalaga fiafia faatasi outou o mea faatafunaina i Ierusalema;", "Break forth into joy, sing together,"], ["auā ua faamafanafanaina lona nuu e Ieova,", "ye waste places of Jerusalem:"], ["ua na faatauina Ierusalema.", "for the LORD hath comforted his people, he hath redeemed Jerusalem."]]},
  {num:10,words:[["Ua to ese e Ieova le ofu i lona aao paia i luma o nuu uma;", "The LORD hath made bare his holy arm in the eyes of all the nations;"], ["ua iloa foi e tuluiga uma o le lalolagi le olataga mai lo tatou Atua.", "and all the ends of the earth shall see the salvation of our God."]]},
  {num:11,words:[["O ese ia,", "Depart ye,"], ["ina o ese outou,", "depart ye,"], ["ia outou o atu nai lea mea;", "go ye out from thence, touch no unclean thing;"], ["aua ne'i pa'i atu i se mea leaga;", "go ye out of the midst of her;"], ["o atu ia outou nai totonu ia te ia;", "be ye clean,"], ["ia mamā outou o e tauave ipu a Ieova.", "that bear the vessels of the LORD."]]},
  {num:12,words:[["Auā tou te le o atu ma le faataalise,", "For ye shall not go out with haste,"], ["tou te le o atu foi faasosola;", "nor go by flight:"], ["auā e afio Ieova i o outou luma;", "for the LORD will go before you;"], ["e muli'au foi ia te outou le Atua o Isaraelu.", "and the God of Israel will be your rereward."]]},
  {num:13,words:[["Faauta,", "Behold,"], ["e manuia la'u Auauna,", "my servant shall deal prudently,"], ["e faasilisiliina o ia, ma viia,", "he shall be exalted and extolled,"], ["ma matuā faaneeneeina.", "and be very high."]]},
  {num:14,words:[["E pei ona ofo o tagata e toatele ia te oe,", "As many were astonied at thee;"], ["ua faaleaga faapea ona fofoga e sili i mata o tagata,", "his visage was so marred more than any man,"], ["ma lona tino e sili i tino o tagata;", "and his form more than the sons of men:"]]},
  {num:15,words:[["e faapea ona sausauina e ia o nuu e tele;", "So shall he sprinkle many nations;"], ["ona o ia e punitia ai e tupu o latou lava fofoga;", "the kings shall shut their mouths at him:"], ["auā latou te vaaia le mea na le talatalaina ia i latou,", "for that which had not been told them shall they see;"], ["latou te iloa foi le mea na latou le faalogo i ai.", "and that which they had not heard shall they consider."]]},
];
renderVerseSet(isa_ch_52_Verses, 'isa-ch52-verses');

var isa_ch_53_Verses = [
  {num:1,words:[["O ai ea ua talitonu i la matou upu e taulogologo atu; ua faaalia ia te ai le aao o Ieova?", "Who hath believed our report? and to whom is the arm of the LORD revealed?"]]},
  {num:2,words:[["Na tupu ae o ia e pei o se tātupu i ona luma,", "For he shall grow up before him as a tender plant,"], ["e pei o le pogai i le nuu naumati;", "and as a root out of a dry ground:"], ["e le aulelei pe lalelei o ia;", "he hath no form nor comeliness;"], ["a tatou vaavaai ia te ia e leai sona matagofie,", "and when we shall see him,"], ["ina ia tatou mananao ai ia te ia.", "there is no beauty that we should desire him."]]},
  {num:3,words:[["Ua inosia ma tuulafoaiina o ia e tagata;", "He is despised and rejected of men;"], ["o le tagata faanoanoa,", "a man of sorrows,"], ["ua masani foi ma le tiga;", "and acquainted with grief:"], ["e peiseai ua 'alo ese mata ia te ia;", "and we hid as it were our faces from him;"], ["ua inosia o ia,", "he was despised,"], ["ma ua tatou le manatua lava o ia.", "and we esteemed him not."]]},
  {num:4,words:[["E moni,", "Surely he hath borne our griefs,"], ["ua na tauave o tatou tiga,", "and carried our sorrows:"], ["ma na tauave o tatou faanoanoa; a ua tatou manatu o ia ua taia,", "yet we did esteem him stricken,"], ["ua fasia e le Atua,", "smitten of God,"], ["ma ua faatigaina.", "and afflicted."]]},
  {num:5,words:[["A ua manu'a o ia ona o a tatou solitulafono,", "But he was wounded for our transgressions,"], ["ua momomo o ia ona o a tatou amio leaga;", "he was bruised for our iniquities:"], ["o le aoaiga e filemu ai tatou sa i ona luga lea,", "the chastisement of our peace was upon him;"], ["o ona faalavalava foi ua malolo ai tatou.", "and with his stripes we are healed."]]},
  {num:6,words:[["O i tatou uma ua sē i tatou e pei o mamoe,", "All we like sheep have gone astray;"], ["ua taitasi ma faasaga i lona lava ala;", "we have turned every one to his own way;"], ["a ua faaoo ia te ia e Ieova le amio leaga o i tatou uma.", "and the LORD hath laid on him the iniquity of us all."]]},
  {num:7,words:[["Na faasauaina o ia,", "He was oppressed,"], ["sa tigaina foi o ia,", "and he was afflicted,"], ["a e le tautala mai o ia; e pei o le tamai mamoe ua ta'ita'iina ia fasia,", "yet he opened not his mouth:"], ["e pei o le mamoe foi i luma o e sele lona fulufulu,", "he is brought as a lamb to the slaughter,"], ["ua faalologo ia,", "and as a sheep before her shearers is dumb,"], ["o ia foi ua le tautala mai.", "so he openeth not his mouth."]]},
  {num:8,words:[["O le faasaua ma le faamasinoga na aveeseina ai o ia;", "He was taken from prison and from judgment:"], ["o ai foi na te talatalaina lana tupulaga? auā ua vavaeeseina o ia i le nuu o tagata ola;", "and who shall declare his generation? for he was cut off out of the land of the living:"], ["na taia o ia ona o le solitulafono a lo'u nuu.", "for the transgression of my people was he stricken."]]},
  {num:9,words:[["Na tofia o ia ia fai lona tuugamau faatasi ma ē pagotata,", "And he made his grave with the wicked,"], ["a e peitai sa i le mauoa ina ua maliu;", "and with the rich in his death;"], ["auā na le faia e ia se faasauaga,", "because he had done no violence,"], ["ua leai foi se pepelo i lona fofoga.", "neither was any deceit in his mouth."]]},
  {num:10,words:[["A ua finagalo Ieova e tu'imomomo ia te ia,", "Yet it pleased the LORD to bruise him;"], ["ua ia faatigaina o ia;", "he hath put him to grief:"], ["pe afai na te faia se taulaga mo agasala,", "when thou shalt make his soul an offering for sin,"], ["ona iloa lea e ia o lana fanau,", "he shall see his seed,"], ["e faalevalevaina ona aso,", "he shall prolong his days,"], ["o le finagalo foi o Ieova e manuia lea ia te ia.", "and the pleasure of the LORD shall prosper in his hand."]]},
  {num:11,words:[["Ona o le tiga o lona agaga na te iloa ai lana fanau ,", "He shall see of the travail of his soul,"], ["e malie ai o ia;", "and shall be satisfied:"], ["o le malamalama mai ia te ia e ta'uamiotonuina ai tagata e toatele e la'u auauna ua amiotonu;", "by his knowledge shall my righteous servant justify many;"], ["auā e tauave e ia a latou amio leaga.", "for he shall bear their iniquities."]]},
  {num:12,words:[["O le mea lea ou te vaevaea ai se vaega mo ia faatasi ma e ua sili,", "Therefore will I divide him a portion with the great,"], ["e vaea foi le vete faatasi ma e fitafita,", "and he shall divide the spoil with the strong;"], ["ona ua ia sasaa atu o lona ola ia oti;", "because he hath poured out his soul unto death:"], ["na faitauina foi o ia faatasi ma e pagotata;", "and he was numbered with the transgressors;"], ["na ia aveina foi le agasala a tagata e toatele,", "and he bare the sin of many,"], ["ua fautua foi o ia mo e solitulafono.", "and made intercession for the transgressors."]]},
  {num:13,words:[["E a'oa'oina lau fanau uma lava", "to taught your born all indeed"], ["e le ALII;", "by the Lord"], ["e tele foi le manuia o lau fanau.", "to great also the peace your born"]]},
  {num:14,words:[["E faatumauina oe", "by faatumauina you"], ["i le amiotonu;", "in the righteous"], ["e mamao", "to to be far ofl\""], ["ma oe", "and you"], ["le sauaga,", "the sauaga"], ["aua e te le fefe;", "for by the get scared"], ["e mamao foi ma le mata'u,", "to to be far ofl\" also and the ax"], ["aua e le faalatalata mai lea", "for by the faalatalata from"], ["ia te oe.", "unto thee"]]},
  {num:15,words:[["Faauta,", "behold"], ["latou te faapotopoto lava", "them gather together indeed"], ["i latou,", "them"], ["a e le", "but by the"], ["ona o a'u;", "because of I"], ["o i latou uma O e faapotopoto", "them all to gather together"], ["e tau", "to season"], ["ma oe,", "and you"], ["e 1048", "by 1048"]]},
];
renderVerseSet(isa_ch_53_Verses, 'isa-ch53-verses');

var isa_ch_54_Verses = [
  {num:1,words:[["Ia pese oe na le fafine pa sa le fanau;", "Sing,"], ["ia leo tele,", "O barren, thou that didst not bear;"], ["ma ia alaga fiafia oe sa le faatiga,", "break forth into singing,"], ["auā ua sili ona toatele o le fanau a le nofo fua,", "and cry aloud,"], ["i le fanau a le nofo tane,", "thou that didst not travail with child: for more are the children of the desolate than the children of the married wife,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:2,words:[["Ia faalautele le mea e tu ai lou fale ie;", "Enlarge the place of thy tent,"], ["ia fālōina ie puipui o mea e te nofo ai;", "and let them stretch forth the curtains of thine habitations:"], ["aua e te faaitiitia;", "spare not,"], ["ia faaumiumiina au maea,", "lengthen thy cords,"], ["ma ia malolosi au fao;", "and strengthen thy stakes;"]]},
  {num:3,words:[["auā e te osofia le tuapa i le itu taumatau ma le itu tauagavale;", "For thou shalt break forth on the right hand and on the left;"], ["o lau fanau foi e fai mo latou tofi nuu ese,", "and thy seed shall inherit the Gentiles,"], ["e āina foi e i latou o aai tuufua.", "and make the desolate cities to be inhabited."]]},
  {num:4,words:[["Aua e te fefe,", "Fear not;"], ["auā e te le mā;", "for thou shalt not be ashamed:"], ["aua foi e te masiasi,", "neither be thou confounded;"], ["auā e le faamaina oe;", "for thou shalt not be put to shame:"], ["auā e galo ia te oe lou mā ina o ē teine muli;", "for thou shalt forget the shame of thy youth,"], ["e te le toe manatua foi lou luma ina o ē nofo fua.", "and shalt not remember the reproach of thy widowhood any more."]]},
  {num:5,words:[["Auā o le na faia oe o lau tane lea, o Ieova o 'au o lona igoa lea;", "For thy Maker is thine husband;"], ["o le na faatauina oe,", "the LORD of hosts is his name;"], ["o le Paia o Isaraelu lea;", "and thy Redeemer the Holy One of Israel;"], ["e ta'ua o ia, O le Atua o le lalolagi uma.", "The God of the whole earth shall he be called."]]},
  {num:6,words:[["Auā ua valaau Ieova ia te oe,", "For the LORD hath called thee as a woman forsaken and grieved in spirit,"], ["e pei o le avā ua lafoaiina,", "and a wife of youth,"], ["ma ua faanoanoa lona loto, o le avā foi sa nofo a o teine muli ina ua lafoaiina oe,", "when thou wast refused,"], ["ua fetalai mai ai lou Atua.", "saith thy God."]]},
  {num:7,words:[["Ua se emo lava o le mata na ou lafoaiina ai oe,", "For a small moment have I forsaken thee;"], ["a o le alofa tele lava ou te faapotopotoina mai ai oe.", "but with great mercies will I gather thee."]]},
  {num:8,words:[["O le sasaaina atu o lo'u ita na 'alo ai o'u mata ia te oe, ua se emo o le mata;", "In a little wrath I hid my face from thee for a moment;"], ["a o le alofa e faavavau ou te alofa atu ai ia te oe,", "but with everlasting kindness will I have mercy on thee,"], ["ua fetalai mai ai Ieova, o le na faatauina oe.", "saith the LORD thy Redeemer."]]},
  {num:9,words:[["Auā e pei o le lolo ia Noa lenei mea ia te au;", "For this is as the waters of Noah unto me:"], ["na ou tauto ai a'u e le toe lofia le lalolagi i le lolo ia Noa;", "for as I have sworn that the waters of Noah should no more go over the earth;"], ["e faapea ona ou tauto, ou te le ita ia te oe,", "so have I sworn that I would not be wroth with thee,"], ["ou te le aoai atu foi ia te oe.", "nor rebuke thee."]]},
  {num:10,words:[["Auā e mavae atu o atu mauga,", "For the mountains shall depart,"], ["e luluina foi mauga;", "and the hills be removed;"], ["a o lo'u alofa e le mavae atu lea nai ia te oe,", "but my kindness shall not depart from thee,"], ["ma la'u feagaiga e manuia ai e le luluina lea,", "neither shall the covenant of my peace be removed,"], ["ua fetalai mai ai Ieova o lē alofa ia te oe.", "saith the LORD that hath mercy on thee."]]},
  {num:11,words:[["O oe na le ua tiga,", "O thou afflicted,"], ["ua afatia,", "tossed with tempest,"], ["ua le faamafanafanaina;", "and not comforted,"], ["faauta,", "behold,"], ["ou te atiina ae au maa i mea e vali a'i mata,", "I will lay thy stones with fair colours,"], ["ma ou faavaeina oe i safaira.", "and lay thy foundations with sapphires."]]},
  {num:12,words:[["Ou te faia ou matagi'olo i maa mūmū,", "And I will make thy windows of agates,"], ["ma ou faitotoa i maa tioata,", "and thy gates of carbuncles,"], ["ma ou tuaoi uma i maa matagofie.", "and all thy borders of pleasant stones."]]},
  {num:13,words:[["E a'oa'oina lau fanau uma lava e Ieova;", "And all thy children shall be taught of the LORD;"], ["e tele foi le manuia o lau fanau.", "and great shall be the peace of thy children."]]},
  {num:14,words:[["E faatumauina oe i le amiotonu;", "In righteousness shalt thou be established:"], ["e mamao ma oe le sauaga,", "thou shalt be far from oppression;"], ["auā e te le fefe;", "for thou shalt not fear:"], ["e mamao foi ma le mata'u,", "and from terror;"], ["auā e le faalatalata mai lea ia te oe.", "for it shall not come near thee."]]},
  {num:15,words:[["Faauta,", "Behold,"], ["latou te faapotopoto lava i latou,", "they shall surely gather together,"], ["a e le ona o a'u; o i latou uma o e faapotopoto e tau ma oe,", "but not by me:"], ["e vavae mai i latou ia te oe.", "whosoever shall gather together against thee shall fall for thy sake."]]},
  {num:16,words:[["Faauta, o a'u ua ou faia lē fai mea uamea,", "Behold,"], ["o loo tapili i malala ola,", "I have created the smith that bloweth the coals in the fire,"], ["ma gaosi ai auupega i lana galuega;", "and that bringeth forth an instrument for his work;"], ["o a'u foi ua ou faia le na te faatafunaina, na te faaumatia.", "and I have created the waster to destroy."]]},
  {num:17,words:[["O auupega uma e faia e tau ma oe e le manuia ia;", "No weapon that is formed against thee shall prosper;"], ["o laulaufaiva uma e finau atu ia te oe i le faamasinoga e te faasalaina ia;", "and every tongue that shall rise against thee in judgment thou shalt condemn. This is the heritage of the servants of the LORD,"], ["o le tofi lena o auauna a Ieova, o a latou amiotonu foi mai ia te au lea,", "and their righteousness is of me,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
];
renderVerseSet(isa_ch_54_Verses, 'isa-ch54-verses');

var isa_ch_55_Verses = [
  {num:1,words:[["E! outou uma o e fia inu,", "Ho,"], ["o mai ia i le vai,", "every one that thirsteth,"], ["atoa ma outou ua leai ni tupe,", "come ye to the waters,"], ["o mai ia,", "and he that hath no money;"], ["ina faatau ma aai;", "come ye, buy,"], ["ia outou o mai lava,", "and eat;"], ["ma faatau le auina ma le suāsusu,", "yea,"], ["a e leai se tupe,", "come,"], ["e leai foi se tau e faatau a'i .", "buy wine and milk without money and without price."]]},
  {num:2,words:[["Se a le mea tou te avatu ai a outou tupe i mea e le ni mea e 'ai,", "Wherefore do ye spend money for that which is not bread? and your labour for that which satisfieth not? hearken diligently unto me,"], ["ma avatu mea na tiga ai outou i mea e le maoona ai? Se'i matuā faalogologo mai ia ia te au, ma outou aai i mea lelei,", "and eat ye that which is good,"], ["e fiafia foi o outou loto i mea lololo.", "and let your soul delight itself in fatness."]]},
  {num:3,words:[["Uai mai ia o outou taliga,", "Incline your ear,"], ["ma outou o mai ia te au;", "and come unto me:"], ["faalogologo mai ia,", "hear,"], ["e ola ai o outou agaga;", "and your soul shall live;"], ["ou te osia foi le feagaiga e faavavau ma outou,", "and I will make an everlasting covenant with you,"], ["o mea alofa ia na folafolaina ia Tavita e faamaoni lava.", "even the sure mercies of David."]]},
  {num:4,words:[["Faauta,", "Behold,"], ["ua ou avatua o ia e fai ma molimau i le nuu,", "I have given him for a witness to the people,"], ["o le ta'imua ma le pule i le nuu.", "a leader and commander to the people."]]},
  {num:5,words:[["Faauta,", "Behold,"], ["e te valaau i nuu ese sa e le iloa; o nuu ese foi sa latou le iloa oe,", "thou shalt call a nation that thou knowest not,"], ["latou te taufetuli mai ia te oe,", "and nations that knew not thee shall run unto thee because of the LORD thy God,"], ["ona o Ieova lou Atua, ma le Paia o Isaraelu;", "and for the Holy One of Israel;"], ["auā ua ia ta'uleleia oe.", "for he hath glorified thee."]]},
  {num:6,words:[["Ia outou saili ia Ieova manū o mafai ona maua o ia;", "Seek ye the LORD while he may be found,"], ["ia outou valaau ia te ia manū o latalata mai o ia;", "call ye upon him while he is near:"]]},
  {num:7,words:[["ia lafoai e le ua amio leaga lona ala,", "Let the wicked forsake his way,"], ["ma le tagata agasala ia lafoai e ia ona manatu;", "and the unrighteous man his thoughts:"], ["a ia foi mai ia Ieova,", "and let him return unto the LORD,"], ["ona alofa mai lea o ia ia te ia;", "and he will have mercy upon him;"], ["ia foi mai i lo tatou Atua,", "and to our God,"], ["auā na te matuā faamagaloina.", "for he will abundantly pardon."]]},
  {num:8,words:[["Auā o o'u manatu e le o outou manatu,", "For my thoughts are not your thoughts,"], ["o o'u ala e le o outou ala,", "neither are your ways my ways,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:9,words:[["Auā e pei ona sili ona maualuga o le lagi i le lalolagi,", "For as the heavens are higher than the earth,"], ["ua faapea ona sili ona maualuga o o'u ala i o outou ala,", "so are my ways higher than your ways,"], ["ma o'u manatu e sili i o outou manatu.", "and my thoughts than your thoughts."]]},
  {num:10,words:[["Auā e pei ona totō ifo o le ua ma le kiona mai le lagi,", "For as the rain cometh down,"], ["a e le toe foi atu i ai,", "and the snow from heaven, and returneth not thither,"], ["a e peitai e faasūsūina ai le laueleele,", "but watereth the earth,"], ["ma fua mai ai ma totogo mai ai,", "and maketh it bring forth and bud, that it may give seed to the sower,"], ["e tupu mai ai saito i lē lulu saito ma mea e 'ai i le ua 'ai;", "and bread to the eater:"]]},
  {num:11,words:[["e faapea foi la'u upu e alu atu ai lo'u gutu,", "So shall my word be that goeth forth out of my mouth:"], ["e le foi mai fua ia te au;", "it shall not return unto me void,"], ["a e peitai e faia le mea ou te loto i ai,", "but it shall accomplish that which I please,"], ["e manuia foi i le mea ou te auina atu ai.", "and it shall prosper in the thing whereto I sent it."]]},
  {num:12,words:[["Auā tou te o atu ma le fiafia,", "For ye shall go out with joy,"], ["e ta'ita'iina foi outou ma le manuia;", "and be led forth with peace:"], ["o atu mauga ma mauga e leo tetele ma le alaga fiafia i o outou luma,", "the mountains and the hills shall break forth before you into singing,"], ["e pāti lima foi laau uma o le vao.", "and all the trees of the field shall clap their hands."]]},
  {num:13,words:[["E tupu ae le perosi e sui a'i le laau tuitui;", "Instead of the thorn shall come up the fir tree,"], ["e tupu ae le atasi e sui a'i le ogogo;", "and instead of the brier shall come up the myrtle tree:"], ["e fai foi ma igoa e viia ai Ieova,", "and it shall be to the LORD for a name,"], ["e fai foi ma faailoga e faavavau e le mavae atu lava.", "for an everlasting sign that shall not be cut off."]]},
];
renderVerseSet(isa_ch_55_Verses, 'isa-ch55-verses');

var isa_ch_56_Verses = [
  {num:1,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["Ia outou tausia le faamasinoga,", "Keep ye judgment,"], ["ma outou faia le amiotonu;", "and do justice:"], ["auā ua latalata ona oo mai o la'u faaolataga,", "for my salvation is near to come,"], ["ma le faaaliga o le amiotonu mai ia te au.", "and my righteousness to be revealed."]]},
  {num:2,words:[["Amuia le tagata na te faia lenei mea,", "Blessed is the man that doeth this,"], ["ma le atalii o le tagata na te taofimauina ai;", "and the son of man that layeth hold on it;"], ["o loo tausi i le sapati ia le solia,", "that keepeth the sabbath from polluting it,"], ["ma taofi i lona lima ia le faia se mea leaga e tasi.", "and keepeth his hand from doing any evil."]]},
  {num:3,words:[["Aua foi ne'i fai ane le tagata ese,", "Neither let the son of the stranger,"], ["le ua faatasi mai ia Ieova,", "that hath joined himself to the LORD,"], ["e faapea mai,", "speak,"], ["Ua matuā faate'aeseina a'u e Ieova i lona nuu;", "saying, The LORD hath utterly separated me from his people:"], ["aua le fai ane foi le eunuka,", "neither let the eunuch say,"], ["Faauta,", "Behold,"], ["o a'u o le laau popo.", "I am a dry tree."]]},
  {num:4,words:[["Auā o loo faapea ona fetalai mai o Ieova i eunuka o e tausi i o'u sapati,", "For thus saith the LORD unto the eunuchs that keep my sabbaths,"], ["ma latou mananao i mea ou te loto i ai,", "and choose the things that please me,"], ["ma latou taofi mau i la'u feagaiga;", "and take hold of my covenant;"]]},
  {num:5,words:[["ou te avatu ia te i latou lava i lo'u fale ma totonu o o'u pa,", "Even unto them will I give in mine house and within my walls a place and a name better than of sons and of daughters:"], ["o le faailoga ma le igoa e sili ona lelei i atalii ma afafine;", "I will give them an everlasting name,"], ["ou te avatu ia te ia le igoa e faavavau e le aveeseina lava.", "that shall not be cut off."]]},
  {num:6,words:[["O tagata ese foi o e faatasi mai ia Ieova,", "Also the sons of the stranger,"], ["ē o auauna ia te ia,", "that join themselves to the LORD,"], ["ma alolofa i le suafa o Ieova,", "to serve him, and to love the name of the LORD,"], ["e fai mana auauna,", "to be his servants,"], ["o i latou uma o e tausi i le sapati a e le soli i ai,", "every one that keepeth the sabbath from polluting it,"], ["ma latou taofi mau i la'u feagaiga;", "and taketh hold of my covenant;"]]},
  {num:7,words:[["ou te aumaia i latou lava i lo'u mauga paia,", "Even them will I bring to my holy mountain,"], ["ma a'u faafiafia ia te i latou i lo'u fale tatalo;", "and make them joyful in my house of prayer:"], ["o a latou taulaga mu ma a latou taulaga e talia ia i lo'u fata faitaulaga;", "their burnt offerings and their sacrifices shall be accepted upon mine altar;"], ["auā e ta'ua lo'u fale o le fale tatalo mo nuu uma.", "for mine house shall be called an house of prayer for all people."]]},
  {num:8,words:[["Ua fetalai mai le Alii o Ieova,", "The Lord GOD which gathereth the outcasts of Israel saith,"], ["o le na te faapotopotoina e ua tulia o Isaraelu, Ou te toe faapotopotoina mai nisi ia te ia,", "Yet will I gather others to him,"], ["e faaopoopo i e ua uma ona faapotopotoina ia te ia.", "beside those that are gathered unto him."]]},
  {num:9,words:[["O outou manu uma o le vao e,", "All ye beasts of the field,"], ["o mai,", "come to devour,"], ["ina aai,", "yea,"], ["o outou manu uma o le vao matua.", "all ye beasts in the forest."]]},
  {num:10,words:[["O ona tagata vaai,", "His watchmen are blind:"], ["ua tauaso i latou;", "they are all ignorant,"], ["o i latou uma latou te le iloa se mea;", "they are all dumb dogs,"], ["o ulī gūgū i latou uma, latou te le lavā ou,", "they cannot bark;"], ["o e fai miti,", "sleeping,"], ["o e taooto,", "lying down,"], ["o fia momoe i latou.", "loving to slumber."]]},
  {num:11,words:[["O ulī 'ai tetele i latou,", "Yea,"], ["latou te le iloa se ma'ona;", "they are greedy dogs which can never have enough,"], ["o i latou foi o leoleo mamoe, latou te le iloa faautauta,", "and they are shepherds that cannot understand:"], ["ua faasaga i latou uma i o latou lava ala,", "they all look to their own way,"], ["ua taitasi ma faasaga i lana lava oloa,", "every one for his gain,"], ["e le faapito lava.", "from his quarter."]]},
  {num:12,words:[["O mai ia,", "Come ye,"], ["ou te aumaia le uaina,", "say they,"], ["tatou te inu ia onā i le 'ava;", "I will fetch wine, and we will fill ourselves with strong drink;"], ["e pei o le aso nei foi a taeao;", "and to morrow shall be as this day,"], ["e silisili ese ona lelei.", "and much more abundant."]]},
];
renderVerseSet(isa_ch_56_Verses, 'isa-ch56-verses');

var isa_ch_57_Verses = [
  {num:1,words:[["Ua fano le ua amiotonu,", "The righteous perisheth,"], ["a e leai sē mafafau i ai;", "and no man layeth it to heart:"], ["ua aveeseina foi tagata alolofa,", "and merciful men are taken away,"], ["a ua leai sē manatunatu ua aveeseina le ua amiotonu ai le leaga.", "none considering that the righteous is taken away from the evil to come."]]},
  {num:2,words:[["E ulu atu o ia i le manuia,", "He shall enter into peace:"], ["latou te malolo i o latou moega,", "they shall rest in their beds,"], ["o i latou ia o e savavali ma le tonu.", "each one walking in his uprightness."]]},
  {num:3,words:[["A o outou,", "But draw near hither,"], ["ina faalatalata mai ia iinei, o outou tama a le fafine iite i ao,", "ye sons of the sorceress,"], ["o le fanau a le mulilua ma le fafine talitane.", "the seed of the adulterer and the whore."]]},
  {num:4,words:[["Tou te faatauemu ea ia te ai? E faamaga o outou gutu ia te ai? tou te faaeto mai o outou laulaufaiva ia te ai? E le o le fanau fouvale ea outou? o le fanau e pepelo?", "Against whom do ye sport yourselves? against whom make ye a wide mouth, and draw out the tongue? are ye not children of transgression, a seed of falsehood,"]]},
  {num:5,words:[["O loo faatupu le manao i atua i lalo o laau uma e tauluulu ola;", "Enflaming yourselves with idols under every green tree,"], ["o loo fasioti le fanau i alia i lalo o maluapapa.", "slaying the children in the valleys under the clifts of the rocks?"]]},
  {num:6,words:[["O maa lamolemole o le alia o lou vaega lea,", "Among the smooth stones of the stream is thy portion;"], ["o ia lava e fai mou tofi;", "they,"], ["ua e liligi atu ai lava le taulaga i mea e inu,", "they are thy lot: even to them hast thou poured a drink offering,"], ["ua e avatu foi le taulaga i mea e 'ai.", "thou hast offered a meat offering."], ["Ou te loto mălie ea ona o ia mea?", "Should I receive comfort in these?"]]},
  {num:7,words:[["Ua e tuuina lou moega i le mauga maualuga ma le tele;", "Upon a lofty and high mountain hast thou set thy bed:"], ["ua e alu ae foi i ai e fai taulaga.", "even thither wentest thou up to offer sacrifice."]]},
  {num:8,words:[["Ua e tuuina lau faamanatuga i tua o le puipui ma le pou o le faitotoa;", "Behind the doors also and the posts hast thou set up thy remembrance:"], ["auā ua e faaali oe i le tasi a e le o a'u;", "for thou hast discovered thyself to another than me,"], ["ua e alu ae; ua e faalauteleina lou moega;", "and art gone up;"], ["ua e faia se feagaiga ma i latou;", "thou hast enlarged thy bed,"], ["ua e manao i lo latou moega,", "and made thee a covenant with them;"], ["ua e filifilia le mea e tuu ai .", "thou lovedst their bed where thou sawest it."]]},
  {num:9,words:[["Ua e alu atu i le tupu ma le uu,", "And thou wentest to the king with ointment,"], ["ua e faateleina ou uu manogi,", "and didst increase thy perfumes,"], ["ua e tuuina atu ou sāvali i mea mamao,", "and didst send thy messengers far off,"], ["ma ua e faaleaga oe ia te oe e oo ifo i seoli.", "and didst debase thyself even unto hell."]]},
  {num:10,words:[["Ua lailoa oe i le mamao o lou ala;", "Thou art wearied in the greatness of thy way;"], ["ua e le fai ane,", "yet saidst thou not,"], ["E le aoga;", "There is no hope:"], ["ua e maua le malosi o lou lima,", "thou hast found the life of thine hand;"], ["o le mea lea ua e le faavaivai ai.", "therefore thou wast not grieved."]]},
  {num:11,words:[["Na e atuatuvale ia te ai,", "And of whom hast thou been afraid or feared,"], ["ma e mata'u,", "that thou hast lied,"], ["ina ua e pepelo,", "and hast not remembered me,"], ["ma ē le manatua a'u,", "nor laid it to thy heart? have not I held my peace even of old,"], ["ma ē le mafaufau? na a'u le faalologo ea mai anamuā lava? a ua e le mata'u ia te au.", "and thou fearest me not?"]]},
  {num:12,words:[["Ou te faaali atu lau amiotonu ma au galuega;", "I will declare thy righteousness, and thy works;"], ["e le aoga foi ia mea ia te oe.", "for they shall not profit thee."]]},
  {num:13,words:[["A ē alaga,", "When thou criest,"], ["ia laveai āu aofaga ia te oe;", "let thy companies deliver thee;"], ["e siitia i latou uma e le matagi,", "but the wind shall carry them all away; vanity shall take them:"], ["e avea i le mānava;", "but he that putteth his trust in me shall possess the land,"], ["a o le ua faatuatua ia te au e maua e ia le nuu e fai mona tofi lo'u mauga paia.", "and shall inherit my holy mountain;"]]},
  {num:14,words:[["E fai ane foi se tasi ,", "And shall say,"], ["Faalaulelei,", "Cast ye up,"], ["ina faalaulelei ia,", "cast ye up,"], ["teu ia le ala,", "prepare the way,"], ["ia outou aveeseina mea e tausuai ai i le ala o lo'u nuu.", "take up the stumblingblock out of the way of my people."]]},
  {num:15,words:[["Auā o loo faapea ona fetalai mai o le ua Maualuga ma ua Silisili,", "For thus saith the high and lofty One that inhabiteth eternity,"], ["o lē afio e faavavau,", "whose name is Holy;"], ["e paia lona suafa, Ou te nofo i le mea maualuga ma le paia,", "I dwell in the high and holy place,"], ["ma te nonofo foi ma le ua momomo ma ua maulalo lona loto,", "with him also that is of a contrite and humble spirit,"], ["e faamafanafana i e ua loto maulalo,", "to revive the spirit of the humble,"], ["ma faamafanafanaina loto o e ua loto momomo.", "and to revive the heart of the contrite ones."]]},
  {num:16,words:[["Auā ou te le finau e faavavau,", "For I will not contend for ever,"], ["ou te le ita pea lava pea;", "neither will I be always wroth:"], ["auā e faavaivai le loto i o'u luma,", "for the spirit should fail before me,"], ["o agaga foi na a'u faia.", "and the souls which I have made."]]},
  {num:17,words:[["O le agasala o lona matapeapea na ou ita ai,", "For the iniquity of his covetousness was I wroth,"], ["na ou taia foi o ia;", "and smote him:"], ["na ou lafi,", "I hid me,"], ["ma ou ita;", "and was wroth,"], ["auā na savali o ia ma le finau vale i le ala o lona lava loto.", "and he went on frowardly in the way of his heart."]]},
  {num:18,words:[["Ua ou iloa ona ala,", "I have seen his ways,"], ["ou te faamalolo foi ia te ia;", "and will heal him:"], ["ou te ta'ita'iina o ia, ou te toe avatu foi faamafanafanaga ia te ia,", "I will lead him also,"], ["ma e ua faanoanoa faatasi ma ia.", "and restore comforts unto him and to his mourners."]]},
  {num:19,words:[["O loo ou te faia le fua o laugutu,", "I create the fruit of the lips;"], ["O le filemu,", "Peace,"], ["o le filemu i le ua mamao,", "peace to him that is far off,"], ["atoa ma le ua lata mai,", "and to him that is near,"], ["ua fetalai mai ai Ieova;", "saith the LORD;"], ["ou te faamaloloina foi o ia.", "and I will heal him."]]},
  {num:20,words:[["A o e amio leaga e tusa i latou ma le sami ua sousou,", "But the wicked are like the troubled sea,"], ["e le mafai ona to'a filemu;", "when it cannot rest,"], ["a e lafoia ae e le suāsami le eleele ma le palapala.", "whose waters cast up mire and dirt."]]},
  {num:21,words:[["Ua fetalai mai lo'u Atua,", "There is no peace, saith my God,"], ["E leai se filemu i e amio leaga.", "to the wicked."]]},
];
renderVerseSet(isa_ch_57_Verses, 'isa-ch57-verses');

var isa_ch_58_Verses = [
  {num:1,words:[["Ia alaga tele,", "Cry aloud,"], ["aua le leo itiiti,", "spare not,"], ["ia e leo tele e pei o se pu;", "lift up thy voice like a trumpet,"], ["ma e faaali atu i lo'u nuu o latou solitulafono,", "and shew my people their transgression,"], ["ma ē faaali atu i le aiga o Iakopo a latou agasala.", "and the house of Jacob their sins."]]},
  {num:2,words:[["A ua latou saili mai ia te au i lea aso ma lea aso,", "Yet they seek me daily,"], ["ua latou fia iloa o'u ala;", "and delight to know my ways,"], ["e pei o se nuu ua faia le amiotonu,", "as a nation that did righteousness,"], ["ma latou le lafoai le faatonuga a lo latou Atua;", "and forsook not the ordinance of their God:"], ["ua latou fesili mai ia te au i faamasinoga tonu,", "they ask of me the ordinances of justice;"], ["ua latou faalatalata atu i le Atua ma le fiafia.", "they take delight in approaching to God."]]},
  {num:3,words:[["Se a le mea ua matou anapopogi ai,", "Wherefore have we fasted,"], ["a e te le silasila mai? se a le mea ua faatigaina ai i matou e i matou,", "say they,"], ["a e te le silafia? Faauta,", "and thou seest not? wherefore have we afflicted our soul,"], ["o le aso e anapopogi ai outou,", "and thou takest no knowledge? Behold,"], ["ua outou maua ai le fiafia,", "in the day of your fast ye find pleasure,"], ["ma outou faatauanauina a outou auauna ia faia a outou galuega uma.", "and exact all your labours."]]},
  {num:4,words:[["Faauta,", "Behold,"], ["ua outou anapopogi ia finau ai,", "ye fast for strife and debate,"], ["ma misa ai, ma ia tu'i ai i le lima e fai ai le amio leaga;", "and to smite with the fist of wickedness:"], ["aua tou te anapopogi e pei o le asō,", "ye shall not fast as ye do this day,"], ["e lagona ai o outou leo i le mea maualuga.", "to make your voice to be heard on high."]]},
  {num:5,words:[["E faapena ea le anapogi ou te loto i ai;", "Is it such a fast that I have chosen? a day for a man to afflict his soul? is it to bow down his head as a bulrush, and to spread sackcloth and ashes under him? wilt thou call this a fast,"], ["o le aso e faatiga ai le tagata ia te ia lava? e punou ai ea lona ulu e pei o le fiso? e fola lona moega i le ie talatala ma le lefulefu? E te faaigoa ea lena mea o le anapogi ma le aso e fiafia i ai Ieova?", "and an acceptable day to the LORD?"]]},
  {num:6,words:[["E le o lenei ea le anapogi ou te loto i ai? ma ia tatalaina fusi na faia i le amio leaga,", "Is not this the fast that I have chosen? to loose the bands of wickedness,"], ["e tatala fusi o le amo,", "to undo the heavy burdens,"], ["e tuuina atu ia sa'oloto e ua faasauaina,", "and to let the oppressed go free,"], ["ma ia outou gausia amo uma lava.", "and that ye break every yoke?"]]},
  {num:7,words:[["E le o lenei ea? ona ia tofitofi au mea e 'ai i le ua fia 'ai,", "Is it not to deal thy bread to the hungry,"], ["ia au mai i lou fale e ua matitiva ma faasauaina;", "and that thou bring the poor that are cast out to thy house? when thou seest the naked,"], ["a ē iloa le ua le lavalavā e te faaofuina o ia,", "that thou cover him;"], ["aua foi e te lafi ia i latou o lou lava aiga.", "and that thou hide not thyself from thine own flesh?"]]},
  {num:8,words:[["Ona gafoa mai ai lea o lou malamalama e pei o le tafa o ata,", "Then shall thy light break forth as the morning,"], ["e taalise ona tupu mai foi o lou malolo;", "and thine health shall spring forth speedily:"], ["e alu atu foi lau amiotonu i ou luma,", "and thy righteousness shall go before thee;"], ["e muli'au mai le pupula o Ieova ia te oe.", "the glory of the LORD shall be thy rereward."]]},
  {num:9,words:[["Ona e valaau lea,", "Then shalt thou call,"], ["a e tali mai ai Ieova;", "and the LORD shall answer;"], ["e te alaga atu,", "thou shalt cry,"], ["a e fetalai mai o ia, O a'u lenei;", "and he shall say,"], ["pe afai e te faate'aeseina le amo ia te outou,", "Here I am. If thou take away from the midst of thee the yoke,"], ["o le tusi o le lima,", "the putting forth of the finger,"], ["ma le upu vale.", "and speaking vanity;"]]},
  {num:10,words:[["Afai foi e te alofa atu i le ua fia'ai,", "And if thou draw out thy soul to the hungry,"], ["ma e fafaga ia ma'ona o le ua tiga;", "and satisfy the afflicted soul;"], ["ona alu ae lea o lou malamalama i le pouliuli,", "then shall thy light rise in obscurity,"], ["ma lou pogisa e pei o le aoauli ia.", "and thy darkness be as the noonday:"]]},
  {num:11,words:[["E ta'ita'iina foi oe e le aunoa e Ieova;", "And the LORD shall guide thee continually,"], ["e faamălie foi o ia ia te oe pe a oge vai,", "and satisfy thy soul in drought,"], ["ma faamalosia ou ivi;", "and make fat thy bones: and thou shalt be like a watered garden,"], ["e avea foi oe e pei se fanua ua faasūsūina,", "and like a spring of water,"], ["e pei o le punavai foi e le mate ona suāvai.", "whose waters fail not."]]},
  {num:12,words:[["O e tutupu mai ia te oe latou te ati ae mea na faatafunaina mai anamua;", "And they that shall be of thee shall build the old waste places:"], ["e te faatuina faavae o lea tupulaga ma lea tupulaga;", "thou shalt raise up the foundations of many generations;"], ["e igoa ai oe,", "and thou shalt be called,"], ["O lē ati ae i solo,", "The repairer of the breach,"], ["O le faaola i magāala i mea e nonofo ai.", "The restorer of paths to dwell in."]]},
  {num:13,words:[["Afai e te liliu ese lou vae i le sapati,", "If thou turn away thy foot from the sabbath,"], ["a ē le faia lou lava loto i lo'u aso sa;", "from doing thy pleasure on my holy day;"], ["ma ē ta'ua le sapati,", "and call the sabbath a delight,"], ["o le aso fiafia,", "the holy of the LORD,"], ["le aso ua sa ia Ieova, ua mamalu;", "honourable;"], ["ma e faamamalu i ai,", "and shalt honour him,"], ["o loo e le faia au lava amio,", "not doing thine own ways,"], ["o loo le maua ai lou lava fiafia,", "nor finding thine own pleasure,"], ["ma ē le tautala ai i au lava upu;", "nor speaking thine own words:"]]},
  {num:14,words:[["ona e fiafia lava lea ia Ieova;", "Then shalt thou delight thyself in the LORD;"], ["ou te faatietie ane foi ia te oe i luga o mea maualuluga o le lalolagi,", "and I will cause thee to ride upon the high places of the earth,"], ["ou te fafaga foi ia te oe i le tofi o Iakopo lou tamā;", "and feed thee with the heritage of Jacob thy father:"], ["auā ua fetalai mai ai le fofoga o Ieova.", "for the mouth of the LORD hath spoken it."]]},
  {num:15,words:[["Ua le iloa lava", "the known indeed"], ["le faamaoni;", "the faithful"], ["o le ua “alo", "the Son"], ["i le leaga", "in the evil"], ["ua vetea ana mea.", "vetea his thing"], ["Ona silafia lea e le ALII,", "and seen by the Lord"], ["ua leaga foi ia te ia", "evil also unto to"], ["ina", "let"], ["ua 1053", "1053"]]},
];
renderVerseSet(isa_ch_58_Verses, 'isa-ch58-verses');

var isa_ch_59_Verses = [
  {num:1,words:[["Faauta,", "Behold,"], ["e lei faapuupuuina le aao o Ieova,", "the LORD'S hand is not shortened,"], ["ia le mafaaola;", "that it cannot save;"], ["e le tutuli foi ona taliga,", "neither his ear heavy,"], ["ia le mafaafofoga.", "that it cannot hear:"]]},
  {num:2,words:[["A e peitai o a outou amio leaga ua fai ia ma pupuni i le va o outou ma lo outou Atua,", "But your iniquities have separated between you and your God, and your sins have hid his face from you,"], ["o a outou agasala foi ua 'alo ai ona fofoga ia te outou ua ia le faafofoga mai ai.", "that he will not hear."]]},
  {num:3,words:[["Auā ua leaga o outou lima i le toto,", "For your hands are defiled with blood,"], ["ma outou tamatamai lima ua leaga ia i le amio leaga;", "and your fingers with iniquity;"], ["ua tala pepelo o outou laugutu,", "your lips have spoken lies,"], ["ua tautala o outou laulaufaiva i le mea faapiopio.", "your tongue hath muttered perverseness."]]},
  {num:4,words:[["Ua leai se valaau i le amiotonu,", "None calleth for justice,"], ["ua leai se finau ma le faamaoni;", "nor any pleadeth for truth:"], ["ua latou faatuatua i le mea faatauvaa;", "they trust in vanity,"], ["ua tala pepelo,", "and speak lies;"], ["ua to i latou i le agasala,", "they conceive mischief,"], ["ma ua fanau mai le amio leaga.", "and bring forth iniquity."]]},
  {num:5,words:[["Ua latou togitogi i fua o le gata uogo,", "They hatch cockatrice' eggs,"], ["ua outou lalaga le apogaleveleve;", "and weave the spider's web:"], ["o le na te 'aina ni o latou fua e oti o ia;", "he that eateth of their eggs dieth,"], ["o le fua ua solia e oso mai ai le gata.", "and that which is crushed breaketh out into a viper."]]},
  {num:6,words:[["E le avea o latou apogaleveleve ma ofu;", "Their webs shall not become garments,"], ["latou te le oofu foi i mea ua latou faia;", "neither shall they cover themselves with their works:"], ["o a latou galuega, o galuega ia a le amio leaga;", "their works are works of iniquity,"], ["o le amio faasaua ua i o latou lima.", "and the act of violence is in their hands."]]},
  {num:7,words:[["Ua taufetuli o latou vae i le mea leaga;", "Their feet run to evil,"], ["ua latou faataalise e sasaa ai le toto o e ua le sala o latou manatu o manatu leaga ia;", "and they make haste to shed innocent blood: their thoughts are thoughts of iniquity;"], ["o le faatafunaina ma le lepetia o mea ua i o latou ala ia.", "wasting and destruction are in their paths."]]},
  {num:8,words:[["Ua latou le iloa le ala e manuia ai,", "The way of peace they know not;"], ["ua leai se tonu i mea latou te faia;", "and there is no judgment in their goings:"], ["ua latou faapiopioina o latou lava magāala; o i latou uma o e savavali ai,", "they have made them crooked paths:"], ["latou te le iloa se manuia.", "whosoever goeth therein shall not know peace."]]},
  {num:9,words:[["O le mea lea ua mamao ai ma i matou le faamasinoga,", "Therefore is judgment far from us,"], ["ua le maua mai foi i matou e le amiotonu;", "neither doth justice overtake us:"], ["ua matou faatalitali i le malamalama, faauta foi,", "we wait for light,"], ["o le pouliuli;", "but behold obscurity;"], ["ua faatalitali i le pupula mai,", "for brightness,"], ["a ua matou savavali i le pogisa.", "but we walk in darkness."]]},
  {num:10,words:[["Ua matou tautāgotago atu i le pa e pei o e tauaso;", "We grope for the wall like the blind,"], ["ua matou tautāgotago atu lava e pei o e ua leai ni mata;", "and we grope as if we had no eyes:"], ["ua matou tausuai i le oauli e pei o le segisegi; ua matou i mea o i ai le manuia,", "we stumble at noonday as in the night;"], ["e pei o e ua oti.", "we are in desolate places as dead men."]]},
  {num:11,words:[["Ua gu i matou uma lava e pei o urosa;", "We roar all like bears,"], ["ua matuā tagi foi i matou e pei o lupe;", "and mourn sore like doves:"], ["ua matou faatalitali i le faamasinoga,", "we look for judgment,"], ["a e leai;", "but there is none;"], ["ua faamoemoe i le faaolataga,", "for salvation,"], ["a e mamao ma i matou.", "but it is far off from us."]]},
  {num:12,words:[["Auā ua faateleina a matou solitulafono i ou luma;", "For our transgressions are multiplied before thee,"], ["ua molia foi i matou e a matou agasala;", "and our sins testify against us:"], ["auā o loo ia te i matou a matou solitulafono;", "for our transgressions are with us; and as for our iniquities,"], ["ua matou iloa foi a matou amio leaga;", "we know them;"]]},
  {num:13,words:[["o le solitulafono ma le pepelo ia Ieova;", "In transgressing and lying against the LORD,"], ["o le ō ese i lo matou Atua;", "and departing away from our God,"], ["o le tautala faasaua ma le upu faafouvale;", "speaking oppression and revolt,"], ["o le manatunatu ma le tautala mai i upu pepelo mai le loto.", "conceiving and uttering from the heart words of falsehood."]]},
  {num:14,words:[["Ua faafoisia i tua le faamasinoga,", "And judgment is turned away backward,"], ["ua tu mamao atu le amiotonu;", "and justice standeth afar off:"], ["auā ua paū le faamaoni i le malae,", "for truth is fallen in the street,"], ["e le mafai ona ulu mai le amio sa'o.", "and equity cannot enter."]]},
  {num:15,words:[["Ua le iloa lava le faamaoni;", "Yea, truth faileth;"], ["o le ua 'alo i le leaga ua vetea ana mea . Ona silafia lea e Ieova,", "and he that departeth from evil maketh himself a prey:"], ["ua leaga foi ia te ia ina ua leai se faamasinoga.", "and the LORD saw it, and it displeased him that there was no judgment."]]},
  {num:16,words:[["Na ia silafia ua leai se tagata;", "And he saw that there was no man,"], ["ua ofo lava ina ua leai se fautua;", "and wondered that there was no intercessor:"], ["o le mea lea na fai ai le olataga e lona lava aao;", "therefore his arm brought salvation unto him; and his righteousness,"], ["o lana amiotonu foi na lāgomia ai o ia.", "it sustained him."]]},
  {num:17,words:[["Na ia ofu i le amiotonu e pei se ufifatafata,", "For he put on righteousness as a breastplate,"], ["sa i lona ao le puloutau o le olataga;", "and an helmet of salvation upon his head;"], ["na ia ofu i ofu o le taui ma sui e fai ma ofu;", "and he put on the garments of vengeance for clothing,"], ["na ia ofu foi i le maelega e pei se ofu talaloa.", "and was clad with zeal as a cloke."]]},
  {num:18,words:[["E pei o a latou amio e faapea ona taui mai e ia,", "According to their deeds,"], ["o le toasa i e ua fai o ia mo latou fili,", "accordingly he will repay,"], ["o le taui i e ita ia te ia;", "fury to his adversaries, recompence to his enemies;"], ["na te taui atu lava i nuu tu matafaga.", "to the islands he will repay recompence."]]},
  {num:19,words:[["E pau mai i sisifo, latou te matatau i le suafa o Ieova;", "So shall they fear the name of the LORD from the west,"], ["e pau mai foi i le mea e alu ae ai le la, e matatau i latou i lona mamalu;", "and his glory from the rising of the sun. When the enemy shall come in like a flood,"], ["a oo mai e pei se vaitafe le ua ita mai, ona faatuina lea o se tagavai e tetee atu ia te ia e le Agaga o Ieova.", "the Spirit of the LORD shall lift up a standard against him."]]},
  {num:20,words:[["E afio mai foi le Faaola i Siona,", "And the Redeemer shall come to Zion,"], ["e afio mai foi i e liliu mai nai le solitulafono o loo ia Iakopo,", "and unto them that turn from transgression in Jacob,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:21,words:[["A o a'u,", "As for me,"], ["o la'u feagaiga lenei e faia ma i latou,", "this is my covenant with them,"], ["ua fetalai mai ai Ieova,", "saith the LORD;"], ["O lo'u Agaga o loo i luga ia te oe,", "My spirit that is upon thee,"], ["ma a'u upu ua ou tuuina atu ai i lou gutu,", "and my words which I have put in thy mouth,"], ["e le te'a ese ia i lou gutu ma gutu o lau fanau,", "shall not depart out of thy mouth,"], ["ma gutu o le fanau a lau fanau,", "nor out of the mouth of thy seed,"], ["e afua mai i na ona aso,", "nor out of the mouth of thy seed's seed,"], ["a e oo i le faavavau,", "saith the LORD,"], ["ua fetalai mai ai Ieova.", "from henceforth and for ever."]]},
];
renderVerseSet(isa_ch_59_Verses, 'isa-ch59-verses');

var isa_ch_60_Verses = [
  {num:1,words:[["Tulai ia,", "Arise,"], ["ina malamalama ia,", "shine;"], ["auā ua oo mai lou malamalama;", "for thy light is come,"], ["ua alu ae foi le pupula o Ieova i ou luga.", "and the glory of the LORD is risen upon thee."]]},
  {num:2,words:[["Auā faauta mai,", "For,"], ["e ufitia le lalolagi i le pouliuli,", "behold,"], ["e ufitia foi nuu i le pogisa;", "the darkness shall cover the earth, and gross darkness the people:"], ["a e afio ae Ieova i ou luga,", "but the LORD shall arise upon thee,"], ["ma le pupula o Ieova e aliali mai lea i ou luga.", "and his glory shall be seen upon thee."]]},
  {num:3,words:[["E o mai nuu ese i lou malamalama,", "And the Gentiles shall come to thy light,"], ["o tupu foi e o mai i latou i le pupula o lou alu ae.", "and kings to the brightness of thy rising."]]},
  {num:4,words:[["Ia e fetepai i itu uma,", "Lift up thine eyes round about,"], ["ma e vaai,", "and see:"], ["o loo faapotopoto mai i latou uma;", "all they gather themselves together,"], ["ua latou o mai ia te oe,", "they come to thee:"], ["o au tama tane e o mai i latou i mea mamao,", "thy sons shall come from far,"], ["e afisi foi au tama fafine i lou itu.", "and thy daughters shall be nursed at thy side."]]},
  {num:5,words:[["Ona e vaai ai lea,", "Then thou shalt see,"], ["ma e olioli;", "and flow together,"], ["e polepole oe,", "and thine heart shall fear,"], ["ma fiafia tele lou loto;", "and be enlarged;"], ["auā e liua mai ia te oe le oa o le sami;", "because the abundance of the sea shall be converted unto thee,"], ["e oo mai ia te oe le oloa o nuu ese.", "the forces of the Gentiles shall come unto thee."]]},
  {num:6,words:[["E ufitia oe i le vao kamela e tele,", "The multitude of camels shall cover thee,"], ["o kamela taanoa o Mitiana ma Efa;", "the dromedaries of Midian and Ephah;"], ["o i latou uma mai Seepa e o mai;", "all they from Sheba shall come:"], ["latou te aumaia auro ma pulu lipano,", "they shall bring gold and incense;"], ["latou te tala fiafia i viiga o Ieova.", "and they shall shew forth the praises of the LORD."]]},
  {num:7,words:[["E faapotopotoina ia te oe lafu mamoe uma o Kitara;", "All the flocks of Kedar shall be gathered together unto thee,"], ["e auauna ia te oe mamoe poa o Nepaiota,", "the rams of Nebaioth shall minister unto thee:"], ["latou te o ae, e talileleia i lo'u fata faitaulaga;", "they shall come up with acceptance on mine altar,"], ["ou te faamatagofie foi le fale o i ai lo'u matagofie.", "and I will glorify the house of my glory."]]},
  {num:8,words:[["O ai ea i latou na o loo felelei e pei se ao,", "Who are these that fly as a cloud,"], ["e pei o lupe foi i o latou faitotoa?", "and as the doves to their windows?"]]},
  {num:9,words:[["Auā e faatalitali nuu tu matafaga ia te au,", "Surely the isles shall wait for me,"], ["e muamua foi vaa o Tasesa,", "and the ships of Tarshish first,"], ["e aumaia lau fanau i mea mamao,", "to bring thy sons from far,"], ["o a latou ario ma a latou auro e faatasi ma i latou;", "their silver and their gold with them,"], ["ona o le suafa o Ieova lou Atua,", "unto the name of the LORD thy God,"], ["ma le Paia o Isaraelu,", "and to the Holy One of Israel,"], ["auā ua ia faamatagofie ia te oe.", "because he hath glorified thee."]]},
  {num:10,words:[["E atiina ae ou pa e tagata ese;", "And the sons of strangers shall build up thy walls,"], ["e auauna mai o latou tupu ia te oe;", "and their kings shall minister unto thee:"], ["auā o lo'u ita na a'u taia ai oe;", "for in my wrath I smote thee,"], ["a o lo'u alofa ou te alofa ai lava ia te oe.", "but in my favour have I had mercy on thee."]]},
  {num:11,words:[["E avanoa pea lava ou faitotoa,", "Therefore thy gates shall be open continually;"], ["e le punitia i le ao ma le po;", "they shall not be shut day nor night;"], ["ina ia aumaia ia te oe le oloa o nuu ese,", "that men may bring unto thee the forces of the Gentiles,"], ["ma ia ta'ita'iina ai o latou tupu.", "and that their kings may be brought."]]},
  {num:12,words:[["Auā e fano le nuu ma le malo ua le mafai ona auauna ia te oe;", "For the nation and kingdom that will not serve thee shall perish; yea,"], ["e matuā faatafunaina ia nuu.", "those nations shall be utterly wasted."]]},
  {num:13,words:[["E o mai ia te oe mea e ta'ua ai Lepanona o le perosi,", "The glory of Lebanon shall come unto thee,"], ["ma le titara,", "the fir tree,"], ["ma le tasura e faatasi,", "the pine tree, and the box together,"], ["e faamatagofie a'i le mea e i ai lo'u malumalu;", "to beautify the place of my sanctuary;"], ["ou te faalaleleia foi le mea e tu ai o'u vae.", "and I will make the place of my feet glorious."]]},
  {num:14,words:[["O le fanau o e na faasaua ia te oe latou te o mai,", "The sons also of them that afflicted thee shall come bending unto thee;"], ["ma latou ifo ia te oe; o i latou uma e na 'ino'ino ia te oe,", "and all they that despised thee shall bow themselves down at the soles of thy feet;"], ["latou te ifo atu i ou alofivae;", "and they shall call thee,"], ["latou te faaigoa ia te oe, O le aai a Ieova,", "The city of the LORD,"], ["O Siona o le aai a le Paia o Isaraelu.", "The Zion of the Holy One of Israel."]]},
  {num:15,words:[["Na fai oe ma nuu lafoaiina ma le inosia,", "Whereas thou hast been forsaken and hated,"], ["ua leai foi se ui ai,", "so that no man went through thee,"], ["a o lenei e faia oe e a'u ma nuu matagofie e faavavau,", "I will make thee an eternal excellency,"], ["ma nuu e olioli ai i lea tupulaga ma lea tupulaga.", "a joy of many generations."]]},
  {num:16,words:[["E te susu i le suāsusu o nuu ese,", "Thou shalt also suck the milk of the Gentiles,"], ["e te susu foi i susu o tupu;", "and shalt suck the breast of kings:"], ["e te iloa foi o a'u o Ieova o lou Faaola, ma le na faatauina oe,", "and thou shalt know that I the LORD am thy Saviour and thy Redeemer,"], ["o le Malosi o Iakopo.", "the mighty One of Jacob."]]},
  {num:17,words:[["Ou te aumaia le auro e sui a'i le 'apa memea;", "For brass I will bring gold,"], ["ou te aumaia foi le ario e sui a'i le uamea,", "and for iron I will bring silver,"], ["ma le 'apa memea e sui a'i laau,", "and for wood brass,"], ["ma uamea e sui a'i maa;", "and for stones iron:"], ["e avea foi e a'u ou alii ia filemu,", "I will also make thy officers peace,"], ["ma ou faipule ia amiotonu.", "and thine exactors righteousness."]]},
  {num:18,words:[["E le toe lagona le sauaga i lou laueleele; o le faatafunaina ma le lepetia o mea e le lagona ia i lou nuu;", "Violence shall no more be heard in thy land,"], ["a e faaigoaina e oe ou pa,", "wasting nor destruction within thy borders;"], ["O le olataga,", "but thou shalt call thy walls Salvation,"], ["ma ou puipui, O le viiga.", "and thy gates Praise."]]},
  {num:19,words:[["E le toe faia le la mou malamalama i le ao;", "The sun shall be no more thy light by day;"], ["e le faamalamalama foi ia te oe le masina i lona susulu mai;", "neither for brightness shall the moon give light unto thee:"], ["a e faia Ieova mou malamalama e faavavau,", "but the LORD shall be unto thee an everlasting light,"], ["e fai foi lou Atua mou matagofie.", "and thy God thy glory."]]},
  {num:20,words:[["E le toe goto lou la,", "Thy sun shall no more go down;"], ["e le toe mavae atu foi lou masina;", "neither shall thy moon withdraw itself:"], ["auā e faia Ieova mou malamalama e faavavau;", "for the LORD shall be thine everlasting light,"], ["e uma foi aso o lou faanoanoa.", "and the days of thy mourning shall be ended."]]},
  {num:21,words:[["O lou nuu foi e amiotonu i latou uma lava;", "Thy people also shall be all righteous:"], ["e fai mo latou le nuu e faavavau;", "they shall inherit the land for ever,"], ["o le tātupu o la'u faatoaga,", "the branch of my planting,"], ["o le galuega a o'u lima,", "the work of my hands,"], ["e fai mo'u viiga.", "that I may be glorified."]]},
  {num:22,words:[["O le toaitiiti e fai ma toaafe,", "A little one shall become a thousand,"], ["ma le ua faatauvaa e fai ma nuu malosi; o a'u o Ieova,", "and a small one a strong nation:"], ["ou te faavave ona fai i ona lava aso.", "I the LORD will hasten it in his time."]]},
];
renderVerseSet(isa_ch_60_Verses, 'isa-ch60-verses');

var isa_ch_61_Verses = [
  {num:1,words:[["Ua i o'u luga le Agaga o le Alii o Ieova;", "The Spirit of the Lord GOD is upon me;"], ["auā ua faauuina a'u e Ieova e tala'i le tala lelei i e ua tigaina,", "because the LORD hath anointed me to preach good tidings unto the meek;"], ["ua ia auina mai a'u e fufusi i e loto momomo,", "he hath sent me to bind up the brokenhearted,"], ["e tala'i le saolotoga i le tafeaga,", "to proclaim liberty to the captives,"], ["ma le matuā tatalaina o e ua fusifusia.", "and the opening of the prison to them that are bound;"]]},
  {num:2,words:[["E tala'i le tausaga e talileleia mai ai e Ieova,", "To proclaim the acceptable year of the LORD,"], ["ma le aso e taui ai ma sui e lo tatou Atua;", "and the day of vengeance of our God;"], ["e faamatalaloto i e faanoanoa uma lava;", "to comfort all that mourn;"]]},
  {num:3,words:[["e avatu le fiafia i e faanoanoa i Siona,", "To appoint unto them that mourn in Zion,"], ["e foaiina atu ia i latou le matagofie e sui a'i le lefulefu,", "to give unto them beauty for ashes,"], ["o le uu o le olioli e sui a'i le faanoanoa,", "the oil of joy for mourning,"], ["o le ofu e fai a'i viiga e sui a'i le loto faavaivai; e igoa i latou,", "the garment of praise for the spirit of heaviness;"], ["O laau o le amiotonu,", "that they might be called trees of righteousness,"], ["o le faatoaga a Ieova,", "the planting of the LORD,"], ["e fai mona viiga.", "that he might be glorified."]]},
  {num:4,words:[["Latou te atiina ae foi mea na faatafunaina mai le vavau;", "And they shall build the old wastes,"], ["latou te faatuina mea na faatuufuaina anamua;", "they shall raise up the former desolations, and they shall repair the waste cities,"], ["latou te toe faia aai sa faatafunaina o mea sa tuufua i lea tupulaga ma lea tupulaga.", "the desolations of many generations."]]},
  {num:5,words:[["E tutū tagata ese ma latou leoleo i a outou lafu mamoe,", "And strangers shall stand and feed your flocks,"], ["o tagata o nuu ese e fai i latou ma a outou galuefanua ma a outou galuevine.", "and the sons of the alien shall be your plowmen and your vinedressers."]]},
  {num:6,words:[["A o outou, e igoa outou,", "But ye shall be named the Priests of the LORD:"], ["O faitaulaga a Ieova; e ta'ua outou,", "men shall call you the Ministers of our God:"], ["O auauna a lo tatou Atua;", "ye shall eat the riches of the Gentiles,"], ["tou te aai mea lelei a nuu ese, e fai foi ma outou o a latou oa.", "and in their glory shall ye boast yourselves."]]},
  {num:7,words:[["E tailua ni mea e sui a'i lo outou masiasi;", "For your shame ye shall have double;"], ["latou te olioli foi i lo latou vaega e sui a'i le mā;", "and for confusion they shall rejoice in their portion:"], ["auā e fai mo latou tofi le tailua i lo latou nuu;", "therefore in their land they shall possess the double:"], ["e ia te i latou le olioli e faavavau.", "everlasting joy shall be unto them."]]},
  {num:8,words:[["Auā o a'u o Ieova,", "For I the LORD love judgment,"], ["ou te fiafia i le faamasinoga,", "I hate robbery for burnt offering;"], ["ou te 'ino'ino i mea ua faoa faaletaupulea; ou te avatua lo latou taui ma le faamaoni;", "and I will direct their work in truth,"], ["ou te osia le feagaiga e faavavau ma i latou.", "and I will make an everlasting covenant with them."]]},
  {num:9,words:[["E iloga la latou fanau i nuu ese,", "And their seed shall be known among the Gentiles,"], ["e iloga foi ē tutupu ia te i latou i totonu o nuu;", "and their offspring among the people:"], ["e iloa i latou e i latou uma o e vaai i ai,", "all that see them shall acknowledge them,"], ["o i latou lava o le fanau ua faamanuia e Ieova.", "that they are the seed which the LORD hath blessed."]]},
  {num:10,words:[["Ou te matuā fiafia ia Ieova,", "I will greatly rejoice in the LORD,"], ["e olioli lo'u loto i lo'u Atua;", "my soul shall be joyful in my God;"], ["auā ua na faaofuina a'u i ofu o le olataga,", "for he hath clothed me with the garments of salvation,"], ["ua na faapulupuluina a'u i le ofu o le amiotonu;", "he hath covered me with the robe of righteousness,"], ["e pei o le faatoafaiavā ua pulou o ia pei se faitaulaga;", "as a bridegroom decketh himself with ornaments,"], ["e pei o le faatoanofotane foi ua teuteu o ia i ana teuga.", "and as a bride adorneth herself with her jewels."]]},
  {num:11,words:[["Auā e pei ona faatupuina e le laueleele lona fua,", "For as the earth bringeth forth her bud,"], ["e pei ona faatupuina foi e le faatoaga mea ua totō ai,", "and as the garden causeth the things that are sown in it to spring forth;"], ["e faapea lava ona faatupuina e le Alii o Ieova o le amiotonu ma le viiga i luma o nuu uma.", "so the Lord GOD will cause righteousness and praise to spring forth before all the nations."]]},
];
renderVerseSet(isa_ch_61_Verses, 'isa-ch61-verses');

var isa_ch_62_Verses = [
  {num:1,words:[["Ou te le faalologo auā o Siona,", "For Zion's sake will I not hold my peace,"], ["ou te le mapu foi auā o Ierusalema,", "and for Jerusalem's sake I will not rest,"], ["seia alu atu lana amiotonu e pei o se mea pupula,", "until the righteousness thereof go forth as brightness,"], ["ma lona olataga e pei o le sulu ua mumū.", "and the salvation thereof as a lamp that burneth."]]},
  {num:2,words:[["E vāai nuu ese i lau amiotonu,", "And the Gentiles shall see thy righteousness,"], ["ma tupu uma latou te vāai i lou mamalu;", "and all kings thy glory:"], ["e igoa foi oe i le igoa fou,", "and thou shalt be called by a new name,"], ["e ta'ua mai e le fofoga o Ieova.", "which the mouth of the LORD shall name."]]},
  {num:3,words:[["E fai oe ma pale matagofie i le aao o Ieova, ma pulou o le tupu i le alofilima o lou Atua,", "Thou shalt also be a crown of glory in the hand of the LORD,"], ["E le toe ta'ua oe, Ua lafoaiina;", "and a royal diadem in the hand of thy God."]]},
  {num:4,words:[["e le toe ta'ua foi lou laueleele,", "Thou shalt no more be termed Forsaken;"], ["Ua tuufua; a e peitai e igoa oe,", "neither shall thy land any more be termed Desolate:"], ["Ua ia te ia lo'u fiafia;", "but thou shalt be called Hephzi-bah,"], ["e igoa foi lou laueleele,", "and thy land Beulah:"], ["O le nofo tane; auā e fiafia Ieova ia te oe,", "for the LORD delighteth in thee,"], ["e nofo tane foi lou laueleele.", "and thy land shall be married."]]},
  {num:5,words:[["Auā e pei o le taulealea ua fai avā i le taupou,", "For as a young man marrieth a virgin,"], ["e faapea au tama tane ona fai avā ia te oe;", "so shall thy sons marry thee:"], ["e pei ona fiafia foi o le faatoafaiavā i lana avā,", "and as the bridegroom rejoiceth over the bride,"], ["e faapea ona fiafia o lou Atua ia te oe.", "so shall thy God rejoice over thee."]]},
  {num:6,words:[["Ierusalema e,", "I have set watchmen upon thy walls,"], ["ua ou tofia ē leoleo i luga o ou pa,", "O Jerusalem,"], ["latou te le faalologo e atoa le ao e atoa foi le po, a e faapea lava pea;", "which shall never hold their peace day nor night:"], ["o outou o e ta'uta'uina Ieova,", "ye that make mention of the LORD,"], ["aua ne'i filemu outou;", "keep not silence,"]]},
  {num:7,words:[["aua foi ne'i tuu atu ia te ia ia filemu,", "And give him no rest,"], ["seia faamauina e ia,", "till he establish,"], ["ma seia faia Ierusalema ma viiga i le lalolagi.", "and till he make Jerusalem a praise in the earth."]]},
  {num:8,words:[["Ua tauto Ieova i lona aao taumatau ma lona aao malosi,", "The LORD hath sworn by his right hand, and by the arm of his strength,"], ["Ou te le toe avatu lava lau saito e 'ai mā e ita ia te oe;", "Surely I will no more give thy corn to be meat for thine enemies;"], ["e le inumia foi e le fanau a le tagata ese lau uaina sa tigaina ai oe.", "and the sons of the stranger shall not drink thy wine, for the which thou hast laboured:"]]},
  {num:9,words:[["A e peitai o e faaputuina latou te aai ai,", "But they that have gathered it shall eat it,"], ["ma latou vivii ia Ieova;", "and praise the LORD;"], ["o e taulia mai latou te feinu ai i o'u lotoā paia.", "and they that have brought it together shall drink it in the courts of my holiness."]]},
  {num:10,words:[["Ui atu,", "Go through,"], ["ina ui atu ia i faitotoa,", "go through the gates;"], ["teu le ala o le nuu;", "prepare ye the way of the people;"], ["faalaulelei,", "cast up,"], ["ina faalaulelei ia le ala tele,", "cast up the highway;"], ["ia au ese ai maa;", "gather out the stones;"], ["ia faatu i luga se tagavai mo le nuu.", "lift up a standard for the people."]]},
  {num:11,words:[["Faauta,", "Behold,"], ["ua faailoa e Ieova e oo i le tuluiga o le lalolagi,", "the LORD hath proclaimed unto the end of the world,"], ["Fai atu i le tama fafine a Siona,", "Say ye to the daughter of Zion,"], ["Faauta,", "Behold,"], ["ua oo mai lou Faaola;", "thy salvation cometh;"], ["faauta,", "behold,"], ["o loo ia te ia lana taui,", "his reward is with him,"], ["ua i ona luma foi le totogi o lana galuega.", "and his work before him."]]},
  {num:12,words:[["E igoa foi i latou,", "And they shall call them,"], ["O le nuu paia;", "The holy people,"], ["O e ua faatauina e Ieova;", "The redeemed of the LORD:"], ["e igoa foi oe,", "and thou shalt be called,"], ["O le aai e uia,", "Sought out,"], ["O le aai e le lafoaiina.", "A city not forsaken."]]},
];
renderVerseSet(isa_ch_62_Verses, 'isa-ch62-verses');

var isa_ch_63_Verses = [
  {num:1,words:[["O ai ea lenei lē afio mai mai Etoma, ua afio mai mai Posara ma ofu mūmū;", "Who is this that cometh from Edom,"], ["o le ua matagofie lona ofu;", "with dyed garments from Bozrah? this that is glorious in his apparel,"], ["o lē afio mai i le tele o lona malosi? O a'u lea,", "travelling in the greatness of his strength? I that speak in righteousness,"], ["o lē tautala i le amiotonu, o le ua malosi e faaola.", "mighty to save."]]},
  {num:2,words:[["Se a le mea ua mūmū ai lou ofu ma ou ofu e pei o le ua soli i le soligāvine?", "Wherefore art thou red in thine apparel, and thy garments like him that treadeth in the winefat?"]]},
  {num:3,words:[["Ua ou solia toatasi le tuugāuaina,", "I have trodden the winepress alone;"], ["a o le nuu sa leai so latou e toatasi ia te au;", "and of the people there was none with me:"], ["na ou solia i latou i lo'u ita,", "for I will tread them in mine anger,"], ["ma a'u solia lava i latou i lo'u tiga;", "and trample them in my fury;"], ["na pisia o'u ofu i o latou toto,", "and their blood shall be sprinkled upon my garments,"], ["ua leaga ai o'u ofu uma.", "and I will stain all my raiment."]]},
  {num:4,words:[["Auā sa i lo'u loto le aso e taui ai ma sui;", "For the day of vengeance is in mine heart,"], ["ua oo foi i le tausaga o e ua faatauina e a'u.", "and the year of my redeemed is come."]]},
  {num:5,words:[["Na a'u vaai,", "And I looked,"], ["a ua leai se fesoasoani;", "and there was none to help;"], ["na ou ofo lava ina ua leai se lagolago mai ia te au;", "and I wondered that there was none to uphold: therefore mine own arm brought salvation unto me;"], ["ona faia lea e lo'u lava lima le faaolataga ma a'u;", "and my fury,"], ["na lāgomia foi a'u e lo'u lava ita.", "it upheld me."]]},
  {num:6,words:[["Na ou solia le nuu i lo'u ita,", "And I will tread down the people in mine anger,"], ["na ou faaona ia te i latou i lo'u tiga;", "and make them drunk in my fury,"], ["na ou sasaaina foi o latou toto i le eleele.", "and I will bring down their strength to the earth."]]},
  {num:7,words:[["Ou te vivii i le alofa o Ieova,", "I will mention the lovingkindnesses of the LORD,"], ["o viiga o Ieova,", "and the praises of the LORD,"], ["e tusa ma mea uma ua foai mai e Ieova ia te i tatou,", "according to all that the LORD hath bestowed on us,"], ["ma lona agalelei tele lava i le aiga o Isaraelu,", "and the great goodness toward the house of Israel,"], ["ua na foai mai ia te i latou e tusa ma lona alofa mutimutivale,", "which he hath bestowed on them according to his mercies,"], ["e tusa foi ma le tele o lona alofa.", "and according to the multitude of his lovingkindnesses."]]},
  {num:8,words:[["Auā na fetalai o ia,", "For he said,"], ["O lo'u lava nuu i latou;", "Surely they are my people,"], ["o le fanau e le pepelo;", "children that will not lie:"], ["na fai foi o ia mo latou Faaola.", "so he was their Saviour."]]},
  {num:9,words:[["O latou puapuaga uma na le fai ai o ia mo latou fili;", "In all their affliction he was afflicted,"], ["na faaolaina i latou e le agelu mai ona luma;", "and the angel of his presence saved them:"], ["na ia faatauina i latou i lona alofa ma lona agalelei;", "in his love and in his pity he redeemed them; and he bare them,"], ["na ia siitia i latou ma ave ia i latou i aso uma anamua.", "and carried them all the days of old."]]},
  {num:10,words:[["A o i latou,", "But they rebelled,"], ["na latou fouvale,", "and vexed his holy Spirit:"], ["ma latou faatigaina lona Agaga Paia; ona liliu ai lea o ia ua toasa ia i latou,", "therefore he was turned to be their enemy,"], ["o ia lava na tau ma i latou.", "and he fought against them."]]},
  {num:11,words:[["Na ia manatua aso anamua,", "Then he remembered the days of old, Moses,"], ["o Mose ma lona nuu. O ifea le na faaae mai ia te i latou mai le sami,", "and his people,"], ["faatasi ma le leoleo a lona lafu mamoe? O ifea le na tuu lona Agaga Paia i totonu ia te ia?", "saying, Where is he that brought them up out of the sea with the shepherd of his flock? where is he that put his holy Spirit within him?"]]},
  {num:12,words:[["o le na ta'ita'i ia te i latou i le lima taumatau o Mose,", "That led them by the right hand of Moses with his glorious arm,"], ["ma lona aao mamalu, na vaea e ia le sami i o latou luma,", "dividing the water before them,"], ["ina ia faia mo ia le suafa e faavavau?", "to make himself an everlasting name?"]]},
  {num:13,words:[["o le na ta'ita'i ia te i latou i mea loloto,", "That led them through the deep,"], ["e pei o le solofanua i le vao,", "as an horse in the wilderness,"], ["na latou le tausuai.", "that they should not stumble?"]]},
  {num:14,words:[["E pei o le lafu manu ua alu ifo i le vanu,", "As a beast goeth down into the valley,"], ["ua avane le malologa ia te i latou e le Agaga o Ieova;", "the Spirit of the LORD caused him to rest: so didst thou lead thy people,"], ["sa faapea ona e ta'ita'iina o lou nuu e fai mo oe le suafa mamalu.", "to make thyself a glorious name."]]},
  {num:15,words:[["Silasila mai ia mai le lagi,", "Look down from heaven, and behold from the habitation of thy holiness and of thy glory:"], ["ma e silafia mai lou afioaga paia ma le matagofie. O ifea lou maelega ma lou malosi? o le tagi o lou alo ma lou alofa ia te au ua taofia ea ia?", "where is thy zeal and thy strength, the sounding of thy bowels and of thy mercies toward me? are they restrained?"]]},
  {num:16,words:[["Auā o oe lava lo matou Tamā;", "Doubtless thou art our father,"], ["e ui lava ina le iloa o i matou e Aperaamo,", "though Abraham be ignorant of us, and Israel acknowledge us not:"], ["ua le vaai mai foi Isaraelu ia te i matou,", "thou,"], ["o oe Ieova o lo matou Tamā oe,", "O LORD,"], ["o le na faatauina i matou;", "art our father, our redeemer;"], ["mai anamuā lava lou suafa.", "thy name is from everlasting."]]},
  {num:17,words:[["Ieova e,", "O LORD,"], ["se a le mea ua e faaseseina ai i matou i ou ala? ma e faamaaaina o matou loto ina ia le matatau ia te oe? Foi mai ia ona o au auauna,", "why hast thou made us to err from thy ways, and hardened our heart from thy fear? Return for thy servants' sake,"], ["o itu aiga o lou tofi.", "the tribes of thine inheritance."]]},
  {num:18,words:[["E itiiti ona aso na faia ai e lou nuu paia mo i latou;", "The people of thy holiness have possessed it but a little while:"], ["o e ita mai ia te i matou ua latou solia lou malumalu.", "our adversaries have trodden down thy sanctuary."]]},
  {num:19,words:[["Ua fai i matou e pei o i latou na e le pule i ai talu anamua;", "We are thine: thou never barest rule over them;"], ["e lei ta'ua lou suafa i luga o i latou.", "they were not called by thy name."]]},
];
renderVerseSet(isa_ch_63_Verses, 'isa-ch63-verses');

var isa_ch_64_Verses = [
  {num:1,words:[["E! le fia masae o le lagi ia te oe,", "Oh that thou wouldest rend the heavens,"], ["ma ia e afio ifo,", "that thou wouldest come down,"], ["ina ia tafe ifo mauga i ou luma.", "that the mountains might flow down at thy presence,"]]},
  {num:2,words:[["E pei o le afi e faamu a'i laau iti,", "As when the melting fire burneth,"], ["o le afi e pupuna a'i le vai,", "the fire causeth the waters to boil,"], ["e faailoa atu lou suafa i e ita ia te oe;", "to make thy name known to thine adversaries,"], ["e gatete nuu ese i ou luma.", "that the nations may tremble at thy presence!"]]},
  {num:3,words:[["Na e faia mea matautia sa le manatua e i matou;", "When thou didst terrible things which we looked not for,"], ["na e afio ifo,", "thou camest down,"], ["sa tafe ifo mauga i ou luma.", "the mountains flowed down at thy presence."]]},
  {num:4,words:[["Talu mai le vavau e lei faalogo,", "For since the beginning of the world men have not heard, nor perceived by the ear,"], ["e lei lagona e taliga ,", "neither hath the eye seen,"], ["e lei vaaia e mata se tasi atua ua na o oe,", "O God,"], ["na te faia mea lelei mo le ua faamoemoe ia te ia.", "beside thee, what he hath prepared for him that waiteth for him."]]},
  {num:5,words:[["Lua te fetaiai ma le ua olioli ma le ua faia le amiotonu;", "Thou meetest him that rejoiceth and worketh righteousness,"], ["o e manatua oe i ou ala;", "those that remember thee in thy ways:"], ["faauta,", "behold,"], ["ua e toasa,", "thou art wroth;"], ["auā ua agasala i matou;", "for we have sinned:"], ["o i ai le faavavau,", "in those is continuance,"], ["e faaolaina foi i matou.", "and we shall be saved."]]},
  {num:6,words:[["O i matou nei e tusa ma le mea leaga i matou uma;", "But we are all as an unclean thing, and all our righteousnesses are as filthy rags;"], ["o a matou amiotonu uma e tusa ia ma le ie o le ma'i;", "and we all do fade as a leaf;"], ["ua mamae i matou uma e pei o le lau laau,", "and our iniquities,"], ["o a matou amioletonu e pei se matagi ua lelea ai i matou.", "like the wind, have taken us away."]]},
  {num:7,words:[["Ua leai foi sē valaau i lou suafa,", "And there is none that calleth upon thy name,"], ["ua leai sē ala mai e taofi atu ia te oe;", "that stirreth up himself to take hold of thee:"], ["auā ua 'alo ou fofoga ia te i matou,", "for thou hast hid thy face from us, and hast consumed us,"], ["ua e liua faasuavai i matou ona o a matou amio leaga.", "because of our iniquities."]]},
  {num:8,words:[["A o lenei,", "But now,"], ["Ieova e,", "O LORD,"], ["o oe lava lo matou Tamā;", "thou art our father;"], ["o i matou nei o le omea,", "we are the clay,"], ["a o oe le Tufuga;", "and thou our potter;"], ["o le galuega a ou aao i matou uma.", "and we all are the work of thy hand."]]},
  {num:9,words:[["Ieova e,", "Be not wroth very sore,"], ["aua ne'i faasilisili lou toasa,", "O LORD,"], ["aua foi ne'i manatua a matou amio leaga e oo i le faavavau;", "neither remember iniquity for ever: behold,"], ["faauta,", "see,"], ["se'i e sisila mai,", "we beseech thee,"], ["o lou nuu i matou uma.", "we are all thy people."]]},
  {num:10,words:[["O ou aai paia o le vao tuufua lea;", "Thy holy cities are a wilderness,"], ["o Siona o le vao tuufua lea;", "Zion is a wilderness,"], ["o Ierusalema o le mea faatafunaina lea.", "Jerusalem a desolation."]]},
  {num:11,words:[["O lo matou fale paia ma le matagofie sa vivii ai o matou tamā ia te oe,", "Our holy and our beautiful house,"], ["ua mu lea i le afi;", "where our fathers praised thee, is burned up with fire:"], ["o a matou mea faafiafia uma ua faatafunaina ia.", "and all our pleasant things are laid waste."]]},
  {num:12,words:[["Ieova e,", "Wilt thou refrain thyself for these things, O LORD? wilt thou hold thy peace,"], ["e te taofi ea lou toasa i ia mea? e te le fetalai ea? e te matuā faatiga tele mai ea ia te i matou.", "and afflict us very sore?"]]},
];
renderVerseSet(isa_ch_64_Verses, 'isa-ch64-verses');

var isa_ch_65_Verses = [
  {num:1,words:[["U a ou faalogo atu i e na le fesili mai;", "I am sought of them that asked not for me;"], ["ua maua a'u e i latou na le saili mai ia te au;", "I am found of them that sought me not:"], ["na ou fai atu i le nuu na le igoa i latou i lo'u igoa,", "I said, Behold me,"], ["Faauta,", "behold me,"], ["o a'u lenei!", "unto a nation that was not called by my name."]]},
  {num:2,words:[["Ua ou faaloaloa atu o'u lima i aso uma i le nuu finau vale,", "I have spread out my hands all the day unto a rebellious people,"], ["o e savavali i le ala e le lelei,", "which walketh in a way that was not good,"], ["e tusa ma o latou lava manatu;", "after their own thoughts;"]]},
  {num:3,words:[["o le nuu e faaonoono mai pea lava ia te au i o'u luma,", "A people that provoketh me to anger continually to my face;"], ["o loo latou fai taulaga i faatoaga,", "that sacrificeth in gardens,"], ["ma latou faamu mea manogi i luga o maaomea;", "and burneth incense upon altars of brick;"]]},
  {num:4,words:[["ua latou nonofo i tuugamau,", "Which remain among the graves,"], ["ua atoa le po o i ai i latou i mea lilo;", "and lodge in the monuments,"], ["ua latou aai i tufaaga o puaa;", "which eat swine's flesh,"], ["o le sua foi o mea leaga ua i a latou ipu ia;", "and broth of abominable things is in their vessels;"]]},
  {num:5,words:[["o e fai ane,", "Which say,"], ["Alu ese oe;", "Stand by thyself,"], ["aua e te faalatalata mai ia te au,", "come not near to me;"], ["auā e sili ona paia o a'u ia te oe. O i latou ia o le asu i lo'u isu;", "for I am holier than thou. These are a smoke in my nose,"], ["o le afi e mu i aso uma.", "a fire that burneth all the day."]]},
  {num:6,words:[["Faauta,", "Behold,"], ["ua tusia le upu i o'u luma;", "it is written before me:"], ["ou te le faalologo,", "I will not keep silence,"], ["a e peitai ou te taui atu,", "but will recompense,"], ["ou te taui atu lava i o latou fatafata,", "even recompense into their bosom,"]]},
  {num:7,words:[["o a outou amio leaga,", "Your iniquities,"], ["faatasi ma le amio leaga a o outou tamā,", "and the iniquities of your fathers together,"], ["ua fetalai mai ai Ieova,", "saith the LORD,"], ["o i latou e na faamuina mea manogi i luga o mauga,", "which have burned incense upon the mountains,"], ["ma latou faifaia a'u i luga o mea maualuluga;", "and blasphemed me upon the hills:"], ["ou te fuatia atu foi a latou amioga anamua i o latou fatafata.", "therefore will I measure their former work into their bosom."]]},
  {num:8,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["E pei ona maua o le suāvine i le fuifui vine,", "As the new wine is found in the cluster,"], ["ona latou fai ane lea,", "and one saith,"], ["Aua le faamaumauina,", "Destroy it not;"], ["auā o loo i ai le manuia;", "for a blessing is in it:"], ["e faapea ona ou faia ona o a'u auauna,", "so will I do for my servants' sakes,"], ["e le faamaumauina i latou uma.", "that I may not destroy them all."]]},
  {num:9,words:[["Ou te faatupuina foi le fanau ia Iakopo,", "And I will bring forth a seed out of Jacob,"], ["mai ia Iuta foi le na te fai mona o'u mauga;", "and out of Judah an inheritor of my mountains:"], ["o e na filifilia e a'u latou te fai ia mo latou;", "and mine elect shall inherit it,"], ["o a'u auauna foi latou te nonofo ai.", "and my servants shall dwell there."]]},
  {num:10,words:[["E faia Sarona ma lotoā o lafu mamoe,", "And Sharon shall be a fold of flocks,"], ["ma le vanu o Akori e faia lea ma mea e taooto ai lafu manu,", "and the valley of Achor a place for the herds to lie down in,"], ["mo lo'u nuu e na saili mai ia te au.", "for my people that have sought me."]]},
  {num:11,words:[["A o outou o e lafoai ia Ieova,", "But ye are they that forsake the LORD,"], ["ma faagalogalo i lo'u mauga paia;", "that forget my holy mountain,"], ["o e laulau le 'ai mo Kato,", "that prepare a table for that troop,"], ["ma faatumu le taulaga i mea e inu mo Meni,", "and that furnish the drink offering unto that number."]]},
  {num:12,words:[["ou te faitauina atu outou mo le pelu,", "Therefore will I number you to the sword,"], ["tou te punonou uma lava ia fasia;", "and ye shall all bow down to the slaughter:"], ["auā na ou valaau,", "because when I called,"], ["a ua outou le tali mai;", "ye did not answer;"], ["na ou fai atu,", "when I spake,"], ["a ua outou le faalogo mai;", "ye did not hear;"], ["ua outou faia foi le mea ua leaga ia te au,", "but did evil before mine eyes,"], ["ma outou filifilia le mea ou te le fiafia i ai;", "and did choose that wherein I delighted not."]]},
  {num:13,words:[["o le mea lea,", "Therefore thus saith the Lord GOD,"], ["o loo faapea ona fetalai mai ai o le Alii o Ieova,", "Behold,"], ["Faauta mai,", "my servants shall eat,"], ["e aai a'u auauna,", "but ye shall be hungry:"], ["a o outou tou te fia aai; faauta,", "behold,"], ["e feinu a'u auauna,", "my servants shall drink,"], ["a o outou tou te fia inu;", "but ye shall be thirsty:"], ["faauta,", "behold,"], ["e olioli a'u auauna,", "my servants shall rejoice,"], ["a o outou tou te mamā;", "but ye shall be ashamed:"]]},
  {num:14,words:[["faauta,", "Behold,"], ["e alalaga a'u auauna ona o le loto fiafia,", "my servants shall sing for joy of heart,"], ["a o outou tou te faataio ona o le loto tiga,", "but ye shall cry for sorrow of heart,"], ["ma outou uio ona o le loto momomo.", "and shall howl for vexation of spirit."]]},
  {num:15,words:[["E tuu foi o outou igoa e fai a'i fetuu a e ua filifilia e a'u;", "And ye shall leave your name for a curse unto my chosen:"], ["e fasiotia foi outou e le Alii o Ieova;", "for the Lord GOD shall slay thee,"], ["a e faaigoa e ia o ana auauna i se tasi igoa.", "and call his servants by another name:"]]},
  {num:16,words:[["O lē faamanuia o ia e ia i le nuu na te faamanuia o ia ia te ia i le Atua e faamaoni;", "That he who blesseth himself in the earth shall bless himself in the God of truth;"], ["ma le na te tauto i le nuu e tauto o ia i le Atua e faamaoni;", "and he that sweareth in the earth shall swear by the God of truth;"], ["auā ua galo muai puapuaga,", "because the former troubles are forgotten,"], ["auā foi ua lilo ia mea ia te au.", "and because they are hid from mine eyes."]]},
  {num:17,words:[["Auā faauta mai,", "For,"], ["ou te faia le lagi fou ma le lalolagi fou;", "behold,"], ["e le toe manatua mea na muamua,", "I create new heavens and a new earth: and the former shall not be remembered,"], ["e le alu ae foi i le loto.", "nor come into mind."]]},
  {num:18,words:[["A e peitai ia outou olioli ma fiafia e faavavau i le mea ou te faia;", "But be ye glad and rejoice for ever in that which I create:"], ["auā faauta,", "for,"], ["ou te faia Ierusalema ma faafiafia,", "behold, I create Jerusalem a rejoicing,"], ["ou te faia foi lona nuu ma faaolioli.", "and her people a joy."]]},
  {num:19,words:[["Ou te fiafia foi i Ierusalema,", "And I will rejoice in Jerusalem,"], ["ma a'u olioli i lo'u nuu;", "and joy in my people:"], ["e le toe lagona ai le leo o sē tagi,", "and the voice of weeping shall be no more heard in her,"], ["ma le leo o sē alaga.", "nor the voice of crying."]]},
  {num:20,words:[["E le toe i ai i lea mea le tama meamea,", "There shall be no more thence an infant of days,"], ["po o le toeaina ua le atoatoa ona aso;", "nor an old man that hath not filled his days:"], ["auā e oti le taulealea ua selau ona tausaga; a o le ua agasala ua selau ona tausaga,", "for the child shall die an hundred years old;"], ["e fetuuina o ia.", "but the sinner being an hundred years old shall be accursed."]]},
  {num:21,words:[["Latou te faia fale,", "And they shall build houses,"], ["ma latou mau ai;", "and inhabit them;"], ["latou te totō tovine,", "and they shall plant vineyards,"], ["ma latou aai i o latou fua.", "and eat the fruit of them."]]},
  {num:22,words:[["Latou te le fai fale ina ia mau ai nisi;", "They shall not build, and another inhabit;"], ["latou te le totō ina ia 'ai ai nisi;", "they shall not plant,"], ["auā e pei o aso o le laau aso o lo'u nuu;", "and another eat:"], ["e uma lava i e ua filifilia e a'u o mea na faia e o latou lima.", "for as the days of a tree are the days of my people, and mine elect shall long enjoy the work of their hands."]]},
  {num:23,words:[["Latou te le galulue fua,", "They shall not labour in vain,"], ["latou te fananau,", "nor bring forth for trouble;"], ["a e le tupu ai le atuatuvale; auā o le fanau ua faamanuia e Ieova i latou,", "for they are the seed of the blessed of the LORD,"], ["atoa ma i latou e tutupu mai ia te i latou.", "and their offspring with them."]]},
  {num:24,words:[["A o lei valaau lava i latou,", "And it shall come to pass,"], ["ou te tali atu;", "that before they call,"], ["a o tautala mai i latou,", "I will answer; and while they are yet speaking,"], ["ou te faalogo atu lava.", "I will hear."]]},
  {num:25,words:[["E aai faatasi le luko ma le tamai mamoe, e 'aina 'au o saito e le leona e pei o le povi;", "The wolf and the lamb shall feed together,"], ["a o le gata e fai mana mea e 'ai le efuefu;", "and the lion shall eat straw like the bullock:"], ["latou te le faia se mea leaga,", "and dust shall be the serpent's meat. They shall not hurt nor destroy in all my holy mountain,"], ["latou te le faaumatia foi se mea i lo'u mauga paia uma lava, ua fetalai mai ai Ieova.", "saith the LORD."]]},
];
renderVerseSet(isa_ch_65_Verses, 'isa-ch65-verses');

var isa_ch_66_Verses = [
  {num:1,words:[["O loo faapea ona fetalai mai o Ieova,", "Thus saith the LORD,"], ["O le lagi o lo'u nofoa lea,", "The heaven is my throne,"], ["o le lalolagi o le mea e tu ai ou vae lea;", "and the earth is my footstool:"], ["o ifea le fale tou te faia mo a'u? o ifea foi le mea ou te malolo ai?", "where is the house that ye build unto me? and where is the place of my rest?"]]},
  {num:2,words:[["Na faia ia mea uma e o'u lima;", "For all those things hath mine hand made,"], ["sa i ai lava ia mea uma,", "and all those things have been,"], ["ua fetalai mai ai Ieova;", "saith the LORD:"], ["a o lenei le tagata ou te vaai i ai,", "but to this man will I look,"], ["o e ua faamaulalo ma le loto tiga,", "even to him that is poor and of a contrite spirit,"], ["o le ua gatete foi i la'u upu.", "and trembleth at my word."]]},
  {num:3,words:[["O le ua fasi le povi,", "He that killeth an ox is as if he slew a man;"], ["o le fasi tagata lea;", "he that sacrificeth a lamb,"], ["o le ua fai taulaga i le tamai mamoe, o lē vaea le ua o le ulī lea;", "as if he cut off a dog's neck;"], ["o le ua faia le taulaga i mea e 'ai,", "he that offereth an oblation,"], ["ua faaitaulaga lea i le toto o le puaa;", "as if he offered swine's blood;"], ["o le ua fai le faamanatuga i le pulu lipano,", "he that burneth incense,"], ["o le faamanū lea i le tupua; o i latou nei foi,", "as if he blessed an idol. Yea,"], ["ua latou filifilia o latou lava ala;", "they have chosen their own ways,"], ["ua fiafia foi o latou loto i a latou mea inosia.", "and their soul delighteth in their abominations."]]},
  {num:4,words:[["O a'u foi,", "I also will choose their delusions,"], ["ou te filifili i mea latou te tiga ai,", "and will bring their fears upon them;"], ["ou te faaoo foi ia te i latou o mea latou te fefefe ai;", "because when I called,"], ["auā na ou valaau,", "none did answer;"], ["a ua leai se na tali mai; na ou fai atu,", "when I spake,"], ["a ua latou le faalogo mai;", "they did not hear:"], ["ua latou faia le mea leaga i o'u luma,", "but they did evil before mine eyes,"], ["ua latou filifilia foi le mea ou te le fiafia i ai.", "and chose that in which I delighted not."]]},
  {num:5,words:[["Faalogo mai ia i le upu a Ieova,", "Hear the word of the LORD,"], ["outou o e gatete i lana upu,", "ye that tremble at his word;"], ["O outou uso,", "Your brethren that hated you,"], ["o e 'ino'ino ia te outou,", "that cast you out for my name's sake,"], ["ma tutuli ia te outou ona o lo'u igoa, ua latou fai ane,", "said,"], ["Ia viia Ieova;", "Let the LORD be glorified:"], ["matou te vaaia foi lo outou olioli,", "but he shall appear to your joy,"], ["a e mamā lava i latou.", "and they shall be ashamed."]]},
  {num:6,words:[["O le leo o le vāvāō mai le aai! o le leo mai le malumalu! o le siufofoga o Ieova,", "A voice of noise from the city, a voice from the temple,"], ["o loo taui atu le taui i e ita ia te ia.", "a voice of the LORD that rendereth recompence to his enemies."]]},
  {num:7,words:[["Ua ia fanau mai a o lei faamāsuisui;", "Before she travailed, she brought forth;"], ["na ia fanau mai le tama tane a o lei oo ina faatiga.", "before her pain came, she was delivered of a man child."]]},
  {num:8,words:[["O ai ea ua faalogo i se mea faapena? O ai ea ua vaai i ni mea faapena? E faatiga ea se nuu i le aso e tasi? E fanaua mai loa ea se nuu? auā na faatiga,", "Who hath heard such a thing? who hath seen such things? Shall the earth be made to bring forth in one day? or shall a nation be born at once? for as soon as Zion travailed,"], ["ua fanaua mai foi Siona ana tama tane.", "she brought forth her children."]]},
  {num:9,words:[["Ou te faafaatiga,", "Shall I bring to the birth,"], ["a ou te le faafanau ea? ua fetalai mai ai Ieova;", "and not cause to bring forth? saith the LORD:"], ["ou te faafanau,", "shall I cause to bring forth,"], ["ma a'u punitia? ua fetalai mai ai lou Atua.", "and shut the womb? saith thy God."]]},
  {num:10,words:[["Ia fiafia faatasi ma Ierusalema,", "Rejoice ye with Jerusalem,"], ["ma ia oliloli ia te ia outou uma o e alolofa ia te ia;", "and be glad with her,"], ["ia matuā olioli faatasi ma ia,", "all ye that love her: rejoice for joy with her,"], ["outou uma sa faanoanoa ona o ia;", "all ye that mourn for her:"]]},
  {num:11,words:[["ina ia outou fesusui,", "That ye may suck,"], ["ma ia malilie i le susu o lona faamafanafana mai;", "and be satisfied with the breasts of her consolations;"], ["ina ia matuā fesusui lava,", "that ye may milk out,"], ["ma ia outou fiafia i le tele o lona mamalu.", "and be delighted with the abundance of her glory."]]},
  {num:12,words:[["Auā o loo faapea ona fetalai mai o Ieova,", "For thus saith the LORD,"], ["Faauta,", "Behold,"], ["ou te faatupuina le manuia ia te ia e pei o se vaitafe,", "I will extend peace to her like a river,"], ["ma le mamalu o nuu ese e pei o le alia ua oso i tua;", "and the glory of the Gentiles like a flowing stream:"], ["tou te fesusui foi;", "then shall ye suck,"], ["e afisi outou i lona itu,", "ye shall be borne upon her sides,"], ["e faaolioliina foi i ona vae.", "and be dandled upon her knees."]]},
  {num:13,words:[["E pei o le tagata ua faamaiseina e lona tinā,", "As one whom his mother comforteth,"], ["e faapea ona ou faamaise ia te outou;", "so will I comfort you;"], ["e faamaiseina lava outou i Ierusalema.", "and ye shall be comforted in Jerusalem."]]},
  {num:14,words:[["Tou te vaaia foi,", "And when ye see this,"], ["e olioli ai o outou loto,", "your heart shall rejoice,"], ["e tupu olaola foi o outou ivi e pei o le vao mu'a;", "and your bones shall flourish like an herb:"], ["e iloa le aao o Ieova e ana auauna;", "and the hand of the LORD shall be known toward his servants,"], ["a e matuā toasa o ia i e ita ia te ia.", "and his indignation toward his enemies."]]},
  {num:15,words:[["Auā faauta,", "For,"], ["e afio mai Ieova i le afi,", "behold,"], ["e pei o le asiosio foi ona nofoa faataavalevale,", "the LORD will come with fire, and with his chariots like a whirlwind,"], ["ina ia faafoi atu lona tiga i le toasa,", "to render his anger with fury,"], ["ma lana aoaiga i le mumū o le afi.", "and his rebuke with flames of fire."]]},
  {num:16,words:[["Auā e faasala Ieova i tagata uma i le afi atoa ma lana pelu;", "For by fire and by his sword will the LORD plead with all flesh:"], ["e tele foi le fasi a Ieova.", "and the slain of the LORD shall be many."]]},
  {num:17,words:[["O e latou te faasaina i latou lava,", "They that sanctify themselves,"], ["ma latou faamamāina i latou lava i faatoaga,", "and purify themselves in the gardens behind one tree in the midst,"], ["o loo mulimuli i le tasi i totonu,", "eating swine's flesh,"], ["o e aai i tufaaga o puaa, ma le mea e inosia,", "and the abomination,"], ["ma le imoa,", "and the mouse,"], ["e fano faatasi i latou,", "shall be consumed together,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:18,words:[["A o a'u,", "For I know their works and their thoughts:"], ["ua oo mai i o'u luma a latou galuega ma o latou manatu,", "it shall come,"], ["e faapotopotoina ai o nuu ese uma ma gagana;", "that I will gather all nations and tongues; and they shall come,"], ["latou te o mai ma latou iloa lo'u mamalu.", "and see my glory."]]},
  {num:19,words:[["Ou te tuuina atu foi ia te i latou le faailoga;", "And I will set a sign among them,"], ["a o i latou ua sao,", "and I will send those that escape of them unto the nations,"], ["ou te auina atu ni o latou i nuu ese,", "to Tarshish,"], ["o Tasesa,", "Pul,"], ["ma Pula,", "and Lud,"], ["ma Luti,", "that draw the bow, to Tubal,"], ["o e lolo'u le aufana,", "and Javan,"], ["o Tupalu ma Iavana,", "to the isles afar off,"], ["o nuu tu matafaga e mamao,", "that have not heard my fame,"], ["o e ua le lagona le tala ia te au,", "neither have seen my glory;"], ["ma latou le iloa lo'u mamalu i nuu ese.", "and they shall declare my glory among the Gentiles."]]},
  {num:20,words:[["Latou te aumaia foi o outou uso uma mai nuu uma,", "And they shall bring all your brethren for an offering unto the LORD out of all nations upon horses,"], ["o le taulaga ia Ieova,", "and in chariots,"], ["i luga o solofanua,", "and in litters,"], ["ma nofoa faataavalevale,", "and upon mules,"], ["ma fata, ma falata,", "and upon swift beasts,"], ["ma kamela i lo'u mauga paia o Ierusalema,", "to my holy mountain Jerusalem,"], ["ua fetalai mai ai Ieova;", "saith the LORD,"], ["e pei ona aumaia e le fanauga a Isaraelu o le taulaga i le ipu mamā i le fale o Ieova.", "as the children of Israel bring an offering in a clean vessel into the house of the LORD."]]},
  {num:21,words:[["Ou te aumaia foi ni o latou e fai ma faitaulaga e fai foi ma sa Levī,", "And I will also take of them for priests and for Levites,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:22,words:[["Auā e pei ona tumau i o'u luma o le lagi fou ma le lalolagi fou ou te faia,", "For as the new heavens and the new earth, which I will make,"], ["ua fetalai mai ai Ieova,", "shall remain before me,"], ["e faapea ona tumau o a outou fanau ma lo outou igoa.", "saith the LORD, so shall your seed and your name remain."]]},
  {num:23,words:[["O lea masina faatoa vaaia,", "And it shall come to pass,"], ["ma lea masina faatoa vaaia,", "that from one new moon to another,"], ["o lea sapati ma lea sapati e o mai ai tagata uma lava e ifo mai i o'u luma,", "and from one sabbath to another, shall all flesh come to worship before me,"], ["ua fetalai mai ai Ieova.", "saith the LORD."]]},
  {num:24,words:[["Latou te o atu foi,", "And they shall go forth,"], ["ma latou matamata i tino o tagata oti ē sa fouvale ia te au;", "and look upon the carcases of the men that have transgressed against me:"], ["auā e le mamate o latou ilo,", "for their worm shall not die,"], ["e le tineia foi lo latou afi;", "neither shall their fire be quenched;"], ["e inosia foi i latou e tagata uma lava.", "and they shall be an abhorring unto all flesh."]]},
];
renderVerseSet(isa_ch_66_Verses, 'isa-ch66-verses');

